INSERT INTO public.body_map_areas VALUES (6, 'neck', 'Neck', 'upper_body', 1, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Neck discomfort often comes from tension, poor desk posture, or holding stress in the shoulders and upper back. It can also result from sleeping in an awkward position or looking down at screens for extended periods.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (7, 'shoulder', 'Shoulder', 'upper_body', 2, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Shoulder discomfort is commonly related to repetitive overhead movements, desk work posture, or tension carrying from the neck. It can also come from sleeping on one side or carrying heavy bags.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (8, 'elbow', 'Elbow', 'upper_body', 3, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Elbow discomfort often develops from repetitive gripping or twisting motions, typing, or overuse during exercise. It typically builds gradually over time.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (9, 'wrist_hand', 'Wrist and hand', 'upper_body', 4, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Wrist and hand discomfort commonly comes from keyboard and mouse use, gripping activities, or repetitive motions. It may feel worse after long work sessions.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (10, 'upper_back', 'Upper back', 'upper_body', 5, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Upper back discomfort often relates to rounded shoulders, poor desk ergonomics, or weak postural muscles. Prolonged sitting and screen work are common contributors.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (11, 'lower_back', 'Lower back', 'core', 6, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Lower back discomfort is frequently linked to prolonged sitting, weak core muscles, or poor lifting habits. Stress and lack of movement throughout the day can make it worse.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (12, 'hip', 'Hip', 'lower_body', 7, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Hip discomfort often comes from extended sitting, tight hip flexors, or imbalances from exercise. It can also relate to how you sit or stand throughout the day.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (13, 'quadriceps', 'Quadriceps (front of thigh)', 'lower_body', 8, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Front thigh discomfort typically relates to exercise load, sitting posture, or tightness from lack of stretching. It may feel more noticeable after workouts or long sitting periods.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (14, 'hamstrings', 'Hamstrings (back of thigh)', 'lower_body', 9, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Back of thigh discomfort often comes from sitting for long periods, exercise strain, or inadequate warm-up before activity. Tight hamstrings are common in desk workers.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (15, 'knee', 'Knee', 'lower_body', 10, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Knee discomfort can relate to exercise load, muscle imbalances around the knee, or extended sitting. Stairs and squatting movements often highlight the issue.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (16, 'calf', 'Calf', 'lower_body', 11, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Calf discomfort typically relates to standing or walking demands, footwear, or exercise load. Tight calves are common and often respond well to simple stretching.', NULL, NULL);
INSERT INTO public.body_map_areas VALUES (17, 'ankle_foot', 'Ankle and foot', 'lower_body', 12, true, '2025-12-16 16:48:16.514258', '2025-12-16 16:48:16.514258', 'Ankle and foot discomfort often relates to footwear, standing time, or exercise load. It may also come from changes in activity level or walking surfaces.', NULL, NULL);
INSERT INTO public.body_map_guidance_rules VALUES (1, 'training', 'severity', 'range', '1', '3', 'You can continue training as normal. Just stay aware of how this area feels during and after exercise.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (2, 'training', 'severity', 'range', '4', '6', 'Consider reducing load or volume for exercises that use this area. Listen to your body and back off if discomfort increases.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (3, 'training', 'severity', 'range', '7', '10', 'Avoid loading this area for now. Focus on other body parts in your training and prioritize recovery.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (4, 'training', 'trainingImpact', 'equals', 'modify_avoid', NULL, 'Avoid loading this area temporarily. Substitute with exercises that don''t stress this region.', 20, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (5, 'training', 'trainingImpact', 'equals', 'careful', NULL, 'Use lighter loads and reduced volume. Pay attention to any increase in discomfort.', 20, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (6, 'daily', 'severity', 'range', '1', '3', 'Normal movement is encouraged. Gentle stretching and regular position changes will help.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (7, 'daily', 'severity', 'range', '4', '6', 'Move within comfortable ranges. Take regular breaks and avoid staying in one position too long.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (8, 'daily', 'severity', 'range', '7', '10', 'Take it easy on this area. Prioritize rest and gentle movement only within comfortable limits.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (9, 'daily', 'movementImpact', 'equals', 'significant', NULL, 'Movement is significantly limited. Stay within pain-free ranges and avoid movements that provoke discomfort.', 20, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (10, 'daily', 'movementImpact', 'equals', 'slight', NULL, 'Move within comfortable ranges. Gentle stretching may help, but don''t push into discomfort.', 20, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (11, 'desk', 'trigger', 'equals', 'after_sitting', NULL, 'Since this shows up after long sitting, focus on regular breaks. Stand and move every 30-45 minutes. Check your desk setup - screen height, chair position, and keyboard placement can all contribute.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (12, 'desk', 'trigger', 'equals', 'during_day', NULL, 'Pay attention to your posture throughout the day. Regular micro-breaks and position changes can help prevent buildup.', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (13, 'caution', 'severity', 'range', '7', '10', 'Avoid exercises that load this area until discomfort reduces', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (14, 'caution', 'movementImpact', 'equals', 'significant', NULL, 'Stay within pain-free movement ranges', 10, true, '2025-12-16 16:48:44.755175');
INSERT INTO public.body_map_guidance_rules VALUES (15, 'caution', 'duration', 'equals', 'more_than_two_weeks', NULL, 'Monitor closely - persistent discomfort lasting over two weeks deserves attention', 10, true, '2025-12-16 16:48:44.755175');
