INSERT INTO public.breath_routine_phases VALUES (1, 1, 'Breathing Phase', 4, 5, 4, 5, 10, 0, 0, '2026-01-27 14:58:09.786969');
INSERT INTO public.breath_techniques VALUES (1, 'box-breathing', 'Box Breathing', 'A powerful stress-relief technique used by Navy SEALs. Equal parts inhale, hold, exhale, and hold create a ''box'' pattern that calms the nervous system.', '{"Reduces stress and anxiety","Improves focus and concentration","Lowers blood pressure","Promotes mental clarity"}', 'relaxation', 'beginner', 5, 4, 4, 4, 4, 4, '{"Find a comfortable seated position","Breathe in through your nose for 4 seconds","Hold your breath for 4 seconds","Exhale slowly for 4 seconds","Hold empty for 4 seconds","Repeat the cycle"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:51.911495', NULL);
INSERT INTO public.breath_techniques VALUES (2, '4-7-8-breathing', '4-7-8 Breathing', 'Dr. Andrew Weil''s relaxing breath technique, excellent for falling asleep quickly and reducing anxiety.', '{"Promotes deep relaxation","Helps with falling asleep","Reduces anxiety","Manages cravings"}', 'relaxation', 'beginner', 5, 4, 7, 8, 0, 4, '{"Place tongue behind upper front teeth","Exhale completely through mouth","Inhale quietly through nose for 4 seconds","Hold breath for 7 seconds","Exhale completely through mouth for 8 seconds"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:51.960916', NULL);
INSERT INTO public.breath_techniques VALUES (3, 'wim-hof', 'Wim Hof Method', 'An intense breathing technique developed by ''The Iceman''. Increases oxygen levels and energy while building mental resilience.', '{"Boosts immune system","Increases energy","Reduces inflammation","Builds mental resilience"}', 'energy', 'advanced', 10, 2, 0, 2, 0, 30, '{"Take 30-40 deep breaths","On the last exhale, hold as long as comfortable","Take a recovery breath and hold for 15 seconds","Repeat the cycle 3-4 times"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.000414', NULL);
INSERT INTO public.breath_techniques VALUES (4, 'physiological-sigh', 'Physiological Sigh', 'The fastest way to calm down in real-time. A double inhale followed by a long exhale activates the parasympathetic system.', '{"Instant stress relief","Calms nervous system","Improves emotional regulation","Enhances focus"}', 'relaxation', 'beginner', 2, 2, 1, 6, 0, 3, '{"Take a deep breath in through nose","Add a second shorter inhale on top","Exhale slowly through mouth","Repeat as needed"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.044035', NULL);
INSERT INTO public.breath_techniques VALUES (5, 'energizing-breath', 'Energizing Breath', 'Also known as Bellows Breath or Bhastrika. A powerful technique to increase alertness and energy levels quickly.', '{"Increases energy","Improves alertness","Warms the body","Clears mental fog"}', 'energy', 'intermediate', 3, 1, 0, 1, 0, 20, '{"Sit with spine straight","Breathe rapidly through nose","Keep inhale and exhale equal","Pump your belly with each breath"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.082975', NULL);
INSERT INTO public.breath_techniques VALUES (6, 'coherent-breathing', 'Coherent Breathing', 'Breathing at 5 breaths per minute creates heart rate variability coherence, optimizing cardiovascular and nervous system function.', '{"Improves HRV","Balances nervous system","Reduces blood pressure","Enhances emotional stability"}', 'recovery', 'beginner', 10, 6, 0, 6, 0, 5, '{"Breathe in slowly for 6 seconds","Breathe out slowly for 6 seconds","Maintain smooth, continuous flow","Keep breathing relaxed and natural"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.136645', NULL);
INSERT INTO public.breath_techniques VALUES (7, 'alternate-nostril', 'Alternate Nostril', 'An ancient yogic technique (Nadi Shodhana) that balances the left and right hemispheres of the brain.', '{"Balances brain hemispheres","Reduces anxiety","Improves focus","Calms the mind"}', 'focus', 'beginner', 5, 4, 0, 4, 0, 10, '{"Close right nostril with thumb","Inhale through left nostril","Close left nostril with ring finger","Exhale through right nostril","Inhale through right","Switch and exhale through left"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.175254', NULL);
INSERT INTO public.breath_techniques VALUES (8, 'deep-belly-breathing', 'Deep Belly Breathing', 'Diaphragmatic breathing engages the full lung capacity and activates the parasympathetic nervous system for deep relaxation.', '{"Activates relaxation response","Improves digestion","Reduces cortisol","Lowers heart rate"}', 'relaxation', 'beginner', 5, 5, 0, 5, 0, 6, '{"Place one hand on chest, one on belly","Breathe in through nose, expanding belly","Keep chest relatively still","Exhale slowly, contracting belly"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.212446', NULL);
INSERT INTO public.breath_techniques VALUES (9, 'power-breathing', 'Power Breathing', 'A pre-workout or pre-performance breathing technique to maximize oxygen intake and prime the body for action.', '{"Increases oxygen levels","Primes for performance","Boosts energy","Enhances focus"}', 'performance', 'intermediate', 5, 3, 2, 3, 0, 10, '{"Take a powerful breath in through nose","Hold briefly at the top","Exhale forcefully","Build rhythm and intensity"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.252435', NULL);
INSERT INTO public.breath_techniques VALUES (10, 'recovery-breathing', 'Recovery Breathing', 'A post-workout recovery technique that helps clear lactate, reduce heart rate, and initiate the recovery process.', '{"Speeds recovery","Lowers heart rate","Clears lactate","Activates rest mode"}', 'recovery', 'beginner', 6, 4, 0, 8, 0, 8, '{"Lie down or sit comfortably","Breathe in through nose for 4 seconds","Exhale slowly for 8 seconds","Focus on complete relaxation"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.323724', NULL);
INSERT INTO public.breath_techniques VALUES (11, 'focus-breathing', 'Focus Breathing', 'A technique designed to sharpen mental clarity and enhance concentration before important tasks or decisions.', '{"Sharpens mental clarity","Improves concentration","Reduces mental chatter","Enhances decision-making"}', 'focus', 'beginner', 4, 4, 2, 4, 2, 6, '{"Sit in an alert but relaxed posture","Breathe in steadily for 4 seconds","Hold briefly while focusing attention","Exhale smoothly","Hold empty, maintaining focus"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.362408', NULL);
INSERT INTO public.breath_techniques VALUES (12, 'sleep-preparation', 'Sleep Preparation', 'A calming sequence designed to lower arousal levels and prepare the body and mind for restful sleep.', '{"Promotes sleepiness","Lowers arousal levels","Calms racing thoughts","Prepares body for rest"}', 'relaxation', 'beginner', 8, 4, 0, 7, 1, 8, '{"Lie down comfortably","Breathe in slowly through nose","Exhale even more slowly","Allow body to become heavy with each exhale"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:06:52.407508', NULL);
INSERT INTO public.breath_techniques VALUES (13, 'nsdr', 'NSDR (Non-Sleep Deep Rest)', 'A protocol popularized by Dr. Andrew Huberman that induces deep relaxation without sleep. Combines slow breathing with body scanning to restore mental and physical energy.', '{"Restores dopamine levels","Enhances learning and memory","Reduces fatigue without sleep","Promotes deep relaxation","Improves focus after session"}', 'recovery', 'beginner', 20, 4, 0, 6, 2, 10, '{"Lie down in a comfortable position","Close your eyes and relax your body","Breathe slowly and deeply","Scan your body from head to toe, releasing tension","Allow yourself to drift into deep relaxation","Remain aware but deeply relaxed for 10-20 minutes"}', NULL, NULL, NULL, NULL, true, 0, '2025-12-11 16:43:54.041808', NULL);
