INSERT INTO public.habit_templates VALUES (1, 'Custom Habit', 'Create your own custom habit', 'CUSTOM', '✏️', false, NULL, false, 0, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (7, 'Eat protein', 'This habit focuses on having clients consume protein with each of their meals.', 'NUTRITION PORTION GUIDES', '🥩', false, NULL, true, 40, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (8, 'Eat good fats', 'This habit focuses on incorporating healthy fats into meals using portion control.', 'NUTRITION PORTION GUIDES', '🥑', false, NULL, true, 41, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (9, 'Eat complex carbs', 'This habit focuses on consuming complex carbohydrates for sustained energy.', 'NUTRITION PORTION GUIDES', '🍠', false, NULL, true, 42, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (10, 'Eat vegetables', 'This habit focuses on increasing vegetable intake at each meal.', 'NUTRITION PORTION GUIDES', '🥦', false, NULL, true, 43, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (11, 'Follow portion guides', 'This habit focuses on using hand/fist portion guides for balanced meals.', 'NUTRITION PORTION GUIDES', '✋', false, NULL, true, 44, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', NULL);
INSERT INTO public.habit_templates VALUES (14, 'Prepare Your Own Meals', 'Restaurant meals and ready-made food are typically higher in sodium, refined oils, and hidden calories than equivalent home-cooked meals, and they remove your visibility and control over what goes into your body.
INSERT INTO public.habit_templates VALUES (16, 'Hydrate Before You Caffeinate', 'After 7 to 8 hours without fluids, your body wakes up in a mild state of dehydration. Even slight dehydration can be enough to impair cognitive function, reduce focus, and lower physical performance.
INSERT INTO public.habit_templates VALUES (15, 'Limit Alcohol', 'Alcohol''s impact on performance extends well beyond the next morning. Even modest intake measurably disrupts REM sleep, reducing the overnight recovery that repairs muscle, consolidates memory, and regulates stress hormones.
INSERT INTO public.habit_templates VALUES (6, 'Perform Daily Maintenance', 'This habit focuses on daily mobility and maintenance routines to support recovery and performance.', 'DAILY MAINTENANCE', '🧘', true, NULL, false, 30, true, '2025-10-16 11:35:12.650395', '2025-10-16 11:35:12.650395', 'Helps you maintain physical and mental wellbeing through a consistent daily routine of self-care and recovery practices.');
INSERT INTO public.habit_templates VALUES (2, 'Hit Your Step Count', 'Your daily step count plays a major role in long term health and body composition. A large part of this comes from Non-Exercise Activity Thermogenesis (NEAT) which quietly drives daily energy use outside the gym. When this drops, progress often stalls regardless of how well you train or eat.
INSERT INTO public.habit_templates VALUES (5, 'Track Your Meals', 'Nutritional tracking is one of the most evidence-backed tools for changing body composition and eating habits. Research consistently shows that people who log their food make better nutritional decisions, not because tracking itself burns calories, but because it creates conscious awareness of choices that are otherwise made automatically.
INSERT INTO public.habit_templates VALUES (19, 'Perform Corrective Exercises', 'Corrective exercises are not supplementary. They are the prescription for your specific movement dysfunction or injury. Unlike general exercise, they are targeted to address the precise imbalances, weaknesses, or restrictions contributing to your pain.
INSERT INTO public.habit_templates VALUES (20, 'Avoid Painful Movements', 'There is a critical difference between discomfort that signals adaptation and pain that signals tissue damage. Pushing through the wrong kind of pain does not demonstrate toughness. It prolongs recovery and risks turning a short-term setback into a chronic issue.
INSERT INTO public.habit_templates VALUES (21, 'Take the Active Route', 'The gap between active and sedentary people often has little to do with the gym. It comes down to the dozens of micro-decisions made throughout the day.
INSERT INTO public.habit_templates VALUES (22, 'Stretch Before Bed', 'Evening stretching serves a dual purpose. It physically releases the tension that accumulates in your muscles throughout the day, and it acts as a signal that the workday is over and recovery has begun.
INSERT INTO public.habit_templates VALUES (24, 'Wear Blue Light Glasses', 'The human brain evolved to associate blue wavelength light, the kind dominant in sunlight, with daytime and wakefulness. When you expose yourself to screens in the evening, you send your brain a signal to suppress melatonin, the hormone responsible for initiating sleep.
INSERT INTO public.habit_templates VALUES (23, 'Hit Your Fibre Target', 'Dietary fibre is one of the most under-consumed nutrients in modern diets, particularly among high-performing professionals eating on the go. Adequate fibre intake feeds the beneficial bacteria in your gut microbiome, which plays a role in digestion, immune function, and general wellbeing.
INSERT INTO public.habit_templates VALUES (18, 'Use Your Standing Desk', 'Research consistently links prolonged sitting to increased risk of cardiovascular disease, metabolic dysfunction, and musculoskeletal pain, even in people who exercise regularly. A standing desk is only effective if you actually use it.
INSERT INTO public.habit_templates VALUES (28, 'Push Your Comfort Zone', 'Comfort is the enemy of development. The human brain and body share a fundamental adaptation principle: they only grow in response to stress that exceeds their current capacity. In the gym, this is called progressive overload.
INSERT INTO public.habit_templates VALUES (29, 'Take Radical Ownership', 'Radical ownership is the recognition that your results, in health, performance, relationships, and leadership, are a direct product of your decisions, not your circumstances. This is not a comfortable idea.
INSERT INTO public.habit_templates VALUES (30, 'Practise Mindfulness', 'Mindfulness is not a wellness trend. It is a cognitive training practice with a substantial evidence base. Regular meditation and deliberate stillness increase grey matter density in regions of the brain associated with attention, emotional regulation, and decision-making.
INSERT INTO public.habit_templates VALUES (31, 'Complete Your Check-In', 'Your daily check-in is the data engine that powers everything else on this platform. Without consistent input, the system cannot identify meaningful patterns in your health, flag early signs of overtraining or burnout, or generate the reporting that gives you a clear picture of your progress.
INSERT INTO public.habit_templates VALUES (26, 'Practise a Bedtime Ritual', 'Sleep quality is not just determined by what happens when you are in bed. It is shaped by the 60 to 90 minutes before it. A consistent bedtime ritual works by training your circadian rhythm through repeated behavioural cues.
INSERT INTO public.habit_templates VALUES (27, 'Set a Consistent Wake Time', 'Your circadian rhythm is a biological clock that governs hormone release, body temperature, alertness, and other physiological processes. It functions best when anchored to a consistent schedule.
INSERT INTO public.habit_templates VALUES (17, 'Perform Office Stretches', 'Prolonged sitting is one of the most underestimated threats to executive health. Hours at a desk tighten hip flexors, compress the spine, round the shoulders, and reduce blood flow to the brain, all of which quietly erode both physical health and cognitive output.
INSERT INTO public.habit_templates VALUES (3, 'Hit Your Protein Target', 'Protein is the single most important macronutrient for body composition, recovery, and long-term physical performance. It preserves muscle mass during periods of caloric deficit, supports tissue repair after training, regulates appetite, and provides a stable energy source.
INSERT INTO public.habit_templates VALUES (25, 'Digital Detox Before Bed', 'The problem with screens before bed is not only the blue light. It is the cognitive and emotional activation they produce. Checking email, reading news, or scrolling social media keeps the brain in a state of alertness that directly conflicts with the physiological wind-down required for quality sleep.
INSERT INTO public.habit_templates VALUES (32, 'Review Your Goals', 'Research in behavioural psychology consistently shows that people who regularly review their goals are more likely to achieve them, not because reviewing creates motivation, but because it keeps priorities in working memory where they can influence moment-to-moment decisions.
INSERT INTO public.habit_templates VALUES (33, 'Manage Your Energy', 'Time management is a widely understood concept. Energy management is not, and it is often more important. Every person has predictable windows of peak cognitive performance during the day, periods where focus is sharpest, decision quality is highest, and output is at its best.
INSERT INTO public.habit_templates VALUES (34, 'Take a Recovery Break', 'Sustained cognitive performance follows the same principle as physical performance: output requires recovery. The brain cannot maintain high-quality focus indefinitely. Research suggests meaningful cognitive decline begins after 90 to 120 minutes of uninterrupted demanding work, though this varies between individuals.
INSERT INTO public.habit_templates VALUES (35, 'Avoided Alcohol', 'Choosing to go alcohol-free today is one of the most direct investments you can make in your sleep quality, recovery, and cognitive performance. Alcohol disrupts REM sleep architecture even in small amounts, elevates cortisol, suppresses protein synthesis, and impairs the overnight repair processes your body relies on to perform the next day.
INSERT INTO public.habit_templates VALUES (36, 'Stay Hydrated', 'Dehydration is one of the most common and overlooked performance limiters. Even a 1 to 2 percent drop in hydration can measurably impair concentration, reaction time, and decision-making. For executives managing high cognitive loads across long days, these marginal losses compound fast.
INSERT INTO public.learn_topics VALUES (1, 'Sleep', 'sleep', 'Master sleep quality and recovery for peak performance', '😴', 1, true, '2025-11-21 07:27:28.874184', '/7_1763710544106.png');
INSERT INTO public.learn_topics VALUES (2, 'Stress & Burnout', 'stress-burnout', 'Manage stress and prevent burnout with practical techniques', '🧠', 2, true, '2025-11-21 07:27:28.874184', '/8_1763710544106.png');
INSERT INTO public.learn_topics VALUES (3, 'Movement', 'movement', 'Strengthen, mobilize, and optimize your physical performance', '💪', 3, true, '2025-11-21 07:27:28.874184', '/9_1763710544107.png');
INSERT INTO public.learn_topics VALUES (4, 'Mindset', 'mindset', 'Develop mental resilience and peak performance mindsets', '🎯', 4, true, '2025-11-21 07:27:28.874184', '/10_1763710544107.png');
INSERT INTO public.learn_topics VALUES (5, 'Nutrition', 'nutrition', 'Fuel your body with science-backed nutrition strategies', '🥗', 5, true, '2025-11-21 07:27:28.874184', '/11_1763710544107.png');
INSERT INTO public.learn_topics VALUES (6, 'Travel & Routine', 'travel-routine', 'Stay consistent and healthy while traveling', '✈️', 6, true, '2025-11-21 07:27:28.874184', '/12_1763710544108.png');
INSERT INTO public.learn_topics VALUES (7, 'Productivity', 'productivity', 'Optimize your focus and output for maximum impact', '⚡', 7, true, '2025-11-21 07:27:28.874184', '/13_1763710544108.png');
