INSERT INTO public.recipes VALUES (225, 'Nandos Sweet Potato Chips', 'Crispy, seasoned sweet potato chips coated in coconut flour and Nandos seasoning. A healthier take on a classic side.', 259, 5, 33, 10, NULL, '{"400g sweet potato, cut into 1cm thick chips","2 tbsp olive oil","80g coconut flour","2 tbsp Nandos seasoning","2 tbsp arrowroot flour"}', '{"Preheat oven to 180°C/350°F gas 5. Line 1–2 baking trays with baking paper.","Toss the sweet potato chips in the olive oil.","In a separate bowl mix together the coconut flour, Nandos seasoning and arrowroot flour.","Cover the chips in the flour mix and place on the baking tray.","Cook for 18–20 minutes, remove from the oven and flip, return to the oven and cook for another 18–20 minutes.","Season with salt & pepper and serve hot."}', '{side,chips,"sweet potato",nandos}', 'side', '2026-02-06 07:37:45.026654', NULL, 4, '{gluten-free}', '{vegan,dairy-free,gluten-free}', '{"sweet potato","coconut flour","nandos seasoning"}', 60);
INSERT INTO public.recipes VALUES (199, 'Vegan Chocolate Avocado Mousse', 'Rich chocolate mousse made with avocado', 250, 4, 18, 18, '/uploads/recipes/vegan-chocolate-avocado-mousse.png', '{"1 ripe avocado","2 tbsp cocoa powder","2 tbsp maple syrup","Splash soy milk"}', '{"Blend until smooth","Chill before serving"}', '{Vegan,Gluten-free,Dairy-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 10);
INSERT INTO public.recipes VALUES (200, 'Oat and Date Energy Bites', 'No-bake energy balls with oats, dates and cocoa', 87, 3, 12, 3, '/uploads/recipes/oat-date-energy-bites.png', '{"100g oats","8 dates","1 tbsp peanut butter","Cocoa powder"}', '{"Blend ingredients","Roll into balls","Chill before eating"}', '{Vegan}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 10, NULL, '{vegan,dairy-free}', '{Fruit,Grains}', 10);
INSERT INTO public.recipes VALUES (66, 'Creamy Fruit Salad', 'Fresh seasonal fruits tossed in honey-sweetened Greek yogurt - light and refreshing.', 282, 6, 54, 6, '/uploads/recipes/creamy-fruit-salad.png', '{"1 large banana, chopped","1 red apple, chopped","1 orange, chopped","200g strawberries, chopped","140g Greek yoghurt","1 tbsp honey"}', '{"Mix Greek yoghurt and honey.","Add fruit and toss to combine.","Divide between 2 bowls."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 10);
INSERT INTO public.recipes VALUES (165, 'Smoky Lentil and Walnut Ragu', 'A hearty vegan ragu with smoky lentils and crunchy walnuts', 317, 17, 42, 9, '/uploads/recipes/smoky-lentil-walnut-ragu.png', '{"200g dried green lentils","1 tbsp olive oil","1 onion diced","2 garlic cloves minced","2 carrots finely chopped","2 celery sticks finely chopped","400g chopped tomatoes","2 tbsp tomato puree","1 tsp smoked paprika","40g walnuts chopped","Sea salt and black pepper"}', '{"Cook lentils according to packet instructions","Gently sauté onion, garlic, carrot and celery in olive oil for 8 to 10 minutes","Stir in tomato puree, tomatoes, paprika and seasoning","Add cooked lentils and simmer for 10 minutes","Stir through walnuts before serving"}', '{Vegan}', 'main', '2026-01-27 21:03:49.919603', 'Medium', 4, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 45);
INSERT INTO public.recipes VALUES (118, 'Chilli Con Carne', 'Classic beef chilli with mushrooms, kidney beans and warming spices.', 1908, 180, 162, 60, '/uploads/recipes/chilli-con-carne.jpg', '{"1 tbsp olive oil","1 brown onion, diced","2 cloves garlic, minced","2 tsp smoked paprika","2 tsp ground cumin","1 tsp chilli powder","1 tsp dried oregano","1/2 tsp cayenne pepper","500g lean beef mince","400g mushrooms, chopped","1 red bell pepper, chopped","1 x (400g) tin chopped tomatoes","1 x (400g) tin red kidney beans, rinsed","150ml passata","150ml water","10g coriander, leaves picked"}', '{"Heat oil and cook onion 5 minutes.","Add garlic and spices, cook 2 minutes.","Add mince and brown.","Add mushrooms, pepper and cook 3 minutes.","Add tomatoes, beans, passata and water.","Simmer 35 to 40 minutes until thickened.","Serve with fresh coriander."}', '{"High protein"}', 'main', '2026-01-27 07:12:52.433764', NULL, 6, NULL, '{high-protein}', '{Beef}', 60);
INSERT INTO public.recipes VALUES (166, 'Chickpea and Spinach Lemon Stew', 'A quick and zesty chickpea stew with fresh spinach and lemon', 280, 14, 38, 8, '/uploads/recipes/chickpea-spinach-lemon-stew.png', '{"2 tins chickpeas drained","1 tbsp olive oil","1 onion sliced","2 garlic cloves minced","1 tsp cumin","1 tsp turmeric","200g spinach","Zest and juice of 1 lemon","Sea salt and black pepper"}', '{"Sauté onion and garlic in olive oil until soft","Add spices and cook for 1 minute","Stir in chickpeas and warm through","Add spinach, lemon zest and juice","Season and serve"}', '{Vegan,"High protein"}', 'main', '2026-01-27 21:03:49.919603', 'Easy', 3, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 30);
INSERT INTO public.recipes VALUES (167, 'Miso Tofu and Sesame Greens', 'Crispy tofu glazed with miso served with sesame broccoli', 258, 21, 12, 14, '/uploads/recipes/miso-tofu-sesame-greens.png', '{"200g firm tofu cubed","1 tbsp white miso","1 tsp sesame oil","1 tbsp soy sauce","200g tenderstem broccoli","1 tsp sesame seeds","1 clove garlic grated"}', '{"Pan fry tofu until golden","Mix miso, soy and garlic then coat tofu","Steam broccoli until tender","Drizzle with sesame oil and top with seeds","Serve tofu alongside greens"}', '{Vegan,"High protein",Low-carb}', 'main', '2026-01-27 21:03:49.919603', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 25);
INSERT INTO public.recipes VALUES (74, 'Berry Bowl', 'A protein-packed smoothie bowl with mixed berries, banana, and topped with chia seeds and almonds.', 506, 37, 49, 18, '/uploads/recipes/berry-bowl.png', '{"300g frozen mixed berries","2 frozen banana","250ml almond milk","2 scoops vanilla protein powder (vegan if required)","2 tbsp ground flax","1 tbsp black chia seeds","2 tbsp almonds, chopped"}', '{"Reserve a handful of berries for serving.","Add the remaining berries, banana, almond milk, protein powder and ground flax to the blender and blitz until smooth.","Transfer to two serving bowls, top with reserved berries, chia seeds and almonds."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 10);
INSERT INTO public.recipes VALUES (168, 'Harissa Roasted Aubergine with Tahini Beans', 'Spiced roasted aubergine topped with creamy tahini white beans', 313, 15, 34, 13, '/uploads/recipes/harissa-aubergine-tahini-beans.png', '{"2 aubergines halved","1 tbsp harissa paste","1 tin cannellini beans drained","1 tbsp tahini","1 tbsp lemon juice","Handful parsley chopped","Sea salt"}', '{"Roast aubergines brushed with harissa at 200C for 30 minutes","Warm beans in pan","Stir tahini and lemon into beans","Top aubergine with beans and parsley"}', '{Vegan}', 'main', '2026-01-27 21:03:49.919603', 'Medium', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 40);
INSERT INTO public.recipes VALUES (169, 'Tempeh Stir Fry with Ginger and Lime', 'A quick Asian-style tempeh stir fry with fresh ginger and lime', 308, 23, 18, 16, '/uploads/recipes/tempeh-stir-fry-ginger-lime.png', '{"180g tempeh sliced","1 tbsp olive oil","1 red pepper sliced","1 courgette sliced","1 tbsp soy sauce","Grated ginger","Juice of 1 lime"}', '{"Pan fry tempeh until golden","Add vegetables and cook until tender","Stir in soy, ginger and lime","Serve immediately"}', '{Vegan,"High protein"}', 'main', '2026-01-27 21:03:49.919603', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 25);
INSERT INTO public.recipes VALUES (170, 'Red Lentil Coconut Dal', 'Creamy coconut dal with warming spices and fresh coriander', 323, 16, 40, 11, '/uploads/recipes/red-lentil-coconut-dal.png', '{"200g red lentils","1 onion diced","2 garlic cloves","1 tbsp curry powder","200ml light coconut milk","400ml vegetable stock","Fresh coriander"}', '{"Sauté onion and garlic","Stir in curry powder","Add lentils, coconut milk and stock","Simmer for 20 minutes","Garnish with coriander"}', '{Vegan,Dairy-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 4, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 35);
INSERT INTO public.recipes VALUES (84, 'Beans', 'Slow-cooked homemade baked beans with haricot beans in a rich tomato and mustard sauce.', 223, 10, 30, 7, '/uploads/recipes/beans.png', '{"2 tsp olive oil","1 onion, finely diced","1 x 400g tin chopped tomatoes","1 tbsp cider vinegar","2 tsp English mustard","2 tsp coconut sugar","1/2 tsp paprika","1/2 tsp cracked pepper","1 x 400g tin haricot beans, drained"}', '{"Heat the olive oil and onion in a medium sized saucepan. Cook for 5 minutes.","Add the tomatoes, vinegar, mustard, coconut sugar, paprika, salt and cracked pepper. Bring to the boil, then reduce to a simmer and cook for 10 minutes.","Add the beans and turn down to a low heat. Simmer for 45 minutes.","Serve immediately with crusty bread, optional."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 2, NULL, '{vegetarian}', NULL, 65);
INSERT INTO public.recipes VALUES (85, 'Poppy Seed Pancakes', 'Light and fluffy lemon poppy seed pancakes - a zesty twist on a breakfast classic.', 568, 14, 83, 20, '/uploads/recipes/poppy-seed-pancakes.png', '{"1 medium egg","200g plain flour","75g caster sugar","1 tsp baking powder","150ml milk","2 lemons, juiced and zested","40g poppy seeds","2 tbsp oil"}', '{"Begin by sifting the flour into a large bowl to remove any lumps. Add the sugar, baking powder and salt.","In a measuring jug, whisk together the egg, poppy seeds, lemon juice and zest.","Create a well in the flour and pour in the wet ingredients. Using a wooden spoon, stir until just combined. Do not overmix.","Heat a lightly oiled non stick frying pan over low heat. Add one ladle of batter and cook for about 3 minutes, or until bubbles form on the surface.","Flip the pancake and cook for a further 2 minutes or until cooked through.","Repeat with the remaining batter. Serve with fresh lemon before serving."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 3, NULL, '{vegetarian}', NULL, 40);
INSERT INTO public.recipes VALUES (29, 'Stacked Berry Parfait', 'Layered parfait with greek yogurt, berries and coconut', 318, 29, 19, 14, '/uploads/recipes/stacked-berry-parfait.png', '{"1/4 tsp vanilla extract","45g desiccated coconut","15g calorie free sweetener (sucralose)","250g blueberries","150g raspberries","500g 0% strained greek yoghurt"}', '{"Combine the yoghurt, 1/2 teaspoon of sweetener and vanilla extract in a medium bowl and mix well.","Puree raspberries and remaining sweetener in a blender.","In tall glasses, alternate layers of yoghurt, raspberry puree, blueberries and coconut, making two layers of each.","Refrigerate for 20 mins and serve."}', NULL, 'breakfast', '2026-01-26 11:01:56.569942', NULL, 2, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (226, 'Green Eggs & Ham', 'Protein-packed egg muffins loaded with broccoli, spinach, feta and ham. Perfect for meal prep and great served hot or cold.', 120, 11, 1, 8, NULL, '{"35g broccoli, finely chopped","60g spinach, finely chopped","50g feta, crumbled","50g ham, finely chopped","6 eggs","Salt & cracked pepper"}', '{"Preheat oven to 180°C/350°F gas 4. Lightly spray a cupcake tin with olive oil cooking spray.","Divide broccoli, spinach, feta and ham evenly between six muffin cups.","In a medium-sized bowl, whisk the eggs.","Pour the egg mix evenly into each cup.","Place in the oven and cook for 15 minutes or until eggs have set.","Serve straight away, or refrigerate in an airtight container for up to 4 days."}', '{side,eggs,"meal prep","high protein"}', 'side', '2026-02-06 07:37:45.026654', NULL, 8, '{eggs,dairy}', '{gluten-free,low-carb,high-protein}', '{eggs,broccoli,spinach,feta,ham}', 25);
INSERT INTO public.recipes VALUES (171, 'Mediterranean Chickpea Tray Bake', 'Simple one-tray Mediterranean roasted chickpeas with vegetables', 294, 15, 36, 10, '/uploads/recipes/mediterranean-chickpea-tray-bake.png', '{"2 tins chickpeas drained","1 red onion wedges","1 courgette chunks","1 red pepper chunks","1 tbsp olive oil","1 tsp oregano","Lemon juice"}', '{"Toss everything with oil and oregano","Roast at 200C for 30 minutes","Finish with lemon juice"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 3, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 40);
INSERT INTO public.recipes VALUES (172, 'Black Bean Sweet Potato Bowl', 'Nourishing bowl with roasted sweet potato, black beans and avocado', 344, 14, 45, 12, '/uploads/recipes/black-bean-sweet-potato-bowl.png', '{"1 large sweet potato cubed","1 tin black beans drained","1 tsp smoked paprika","1 tbsp olive oil","Avocado slices","Lime juice"}', '{"Roast sweet potato with paprika and oil","Warm beans in pan","Assemble bowl and finish with lime"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 35);
INSERT INTO public.recipes VALUES (173, 'Crispy Tofu Lettuce Wraps', 'Light and fresh lettuce wraps filled with crispy tofu', 253, 20, 14, 13, '/uploads/recipes/crispy-tofu-lettuce-wraps.png', '{"200g tofu","1 tbsp cornflour","1 tbsp soy sauce","1 tsp sesame oil","Butter lettuce leaves","Grated carrot"}', '{"Coat tofu in cornflour and fry until crisp","Toss with soy and sesame oil","Spoon into lettuce leaves with carrot"}', '{Vegan,Low-carb}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 25);
INSERT INTO public.recipes VALUES (174, 'Creamy White Bean and Rosemary Bake', 'Comforting baked white beans with rosemary and oat cream', 287, 14, 33, 11, '/uploads/recipes/creamy-white-bean-rosemary-bake.png', '{"2 tins butter beans drained","2 cloves garlic","1 tbsp olive oil","1 tsp dried rosemary","100ml oat cream","Black pepper"}', '{"Sauté garlic in oil","Add beans, rosemary and oat cream","Bake at 190C for 20 minutes"}', '{Vegan,Dairy-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 3, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 35);
INSERT INTO public.recipes VALUES (227, 'Rocket, Egg and Charred Asparagus', 'A fresh and vibrant salad with charred asparagus, hard-boiled eggs and peppery rocket, finished with a tangy yoghurt and mustard dressing.', 154, 10, 6, 10, NULL, '{"4 eggs","1 tbsp extra-virgin olive oil","140g asparagus, trimmed","60ml Greek yoghurt","1 tablespoon Dijon mustard","15ml lemon juice","150g rocket","A pinch salt and black pepper"}', '{"Begin by placing your eggs in a high heat pot.","Meanwhile, bring a saucepan of water to the boil. Add the eggs and cook for 6-8 minutes until done.","Once the eggs are cooked, run under cold water and peel.","Char the asparagus in olive oil, seasoning with salt & pepper.","In a bowl whisk together the yoghurt, mustard and lemon juice.","Place the asparagus on a baking tray and drizzle over olive oil and a pinch of salt and pepper.","Grill for 3 minutes until lightly charred, then remove from the grill and chop into 3cm pieces.","In a small bowl mix the salad dressing by combining the yoghurt, lemon juice and seasoning.","Add the rocket to a large bowl and add the dressing.","Top with the asparagus and hard-boiled eggs.","Serve immediately."}', '{side,salad,eggs,asparagus}', 'side', '2026-02-06 07:47:28.493602', NULL, 4, '{eggs,dairy}', '{gluten-free,low-carb}', '{eggs,asparagus,rocket,"Greek yoghurt"}', 20);
INSERT INTO public.recipes VALUES (86, 'PB and J Overnight Oats', 'Classic peanut butter and jam flavors in creamy overnight oats with chia seeds.', 365, 12, 50, 13, '/uploads/recipes/pb-j-overnight-oats.png', '{"120g rolled oats","240ml unsweetened almond milk","2 tbsp chia seeds","1 tbsp maple syrup","1 tbsp peanut butter","1 tbsp jam"}', '{"Mix the oats, almond milk, chia seeds, maple syrup and peanut butter together in a bowl or jar.","Cover and place in the fridge overnight.","Before serving, top with jam. Add a splash of extra almond milk if needed and stir through."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 2, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (24, 'Raspberry and Lemon Breakfast Crackerbreads', 'Light and refreshing breakfast with rye breads topped with lemon curd yogurt and raspberries', 366, 22, 47, 10, '/uploads/recipes/raspberry-lemon-breakfast-crackerbreads.png', '{"4 crunchy rye breads","170g 5% strained greek yoghurt","45g lemon curd","60g raspberries"}', '{"Lightly mix the lemon curd through the yogurt and spread onto the crunchy rye breads then top with the berries to serve."}', NULL, 'breakfast', '2026-01-26 11:01:35.793708', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (175, 'Thai Green Tofu Curry', 'Fragrant Thai green curry with tofu and crisp vegetables', 302, 17, 18, 18, '/uploads/recipes/thai-green-tofu-curry.png', '{"200g tofu","1 tbsp green curry paste","200ml coconut milk","1 red pepper",Mangetout,"Lime juice"}', '{"Fry curry paste briefly","Add coconut milk and vegetables","Stir in tofu and simmer","Finish with lime"}', '{Vegan,Dairy-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 3, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 30);
INSERT INTO public.recipes VALUES (228, 'Roasted Brussels Sprouts with Cranberries', 'Perfectly roasted Brussels sprouts with caramelised dried cranberries. A simple yet flavourful side dish.', 86, 4, 7, 5, NULL, '{"450g Brussels sprouts, trimmed and halved","2 tbsp olive oil","A pinch salt and black pepper","1 tablespoon dried cranberries"}', '{"Begin by preheating your oven to 200°C/400°F gas 6.","In a large bowl, toss the Brussels sprouts with olive oil before spreading them out evenly across a baking tray.","Season the sprouts with salt & pepper before roasting them in the oven for 15 minutes.","Remove the sprouts from the oven and scatter over the cranberries. Return to the oven and roast for a further 10 minutes, or until the sprouts have begun to slightly char and the cranberries are caramelised.","Serve as a delicious accompaniment to any main meal or as a healthy snack."}', '{side,roasted,"brussels sprouts",cranberries}', 'side', '2026-02-06 07:47:28.493602', NULL, 4, '{}', '{vegan,dairy-free,gluten-free}', '{"Brussels sprouts",cranberries}', 35);
INSERT INTO public.recipes VALUES (112, 'Tofu Nori Rolls', 'Fresh nori rolls filled with crispy tofu, avocado and crunchy vegetables.', 542, 34, 16, 38, '/uploads/recipes/tofu-nori-rolls.jpg', '{"2 tsp peanut oil","200g tofu, thinly sliced","2 nori sheets","1/2 avocado, sliced","1/2 red pepper, sliced","1 Lebanese cucumber, cut into matchsticks"}', '{"Heat oil in a frying pan over medium heat. Cook tofu 4 to 5 minutes each side.","Place nori sheet on board. Add tofu and vegetables.","Roll tightly and slice into 3 to 4 pieces.","Serve with soy sauce and pickled ginger if desired."}', '{Vegan,Low-carb}', 'main', '2026-01-27 07:12:24.669501', NULL, 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu}', 45);
INSERT INTO public.recipes VALUES (119, 'Creamy Chickpea Pasta', 'Penne pasta in a creamy sauce with chickpeas, nutritional yeast and paprika.', 1446, 54, 186, 54, '/uploads/recipes/creamy-chickpea-pasta.jpg', '{"150g penne (uncooked)","2 tbsp olive oil","2 brown onions, diced","2 cloves garlic, minced","2 stalks celery, diced","1 tbsp all purpose flour","1 tbsp nutritional yeast","1 tsp paprika","250ml almond coconut milk","250ml vegetable stock","1 x (400g) tin chickpeas, rinsed and drained"}', '{"Cook pasta according to packet instructions.","Heat olive oil in a large frying pan. Add onions and cook 5 minutes until translucent.","Add garlic and celery and cook another 5 minutes.","Stir in flour, nutritional yeast, paprika, almond coconut milk and vegetable stock.","Add chickpeas and stir to combine. Bring to a simmer and season with salt and pepper.","Allow sauce to simmer for 3 to 5 minutes, stirring regularly.","Toss cooked penne through the sauce and divide between 3 bowls."}', '{Vegan}', 'main', '2026-01-27 07:13:27.444112', NULL, 3, NULL, '{vegan,dairy-free}', NULL, 40);
INSERT INTO public.recipes VALUES (229, 'Parmesan Mashed Potatoes', 'Creamy mashed potatoes and parsnips folded through with Parmesan cheese and butter. Ultimate comfort food side.', 187, 8, 23, 7, NULL, '{"450g red skinned potatoes, cleaned and halved","340g parsnips, peeled and chopped","2 tablespoons butter","60ml milk","85g Parmesan cheese, grated"}', '{"After thoroughly cleaning the potatoes and parsnips, add them to a large saucepan of boiling water.","Cook for around 20 minutes, or until the vegetables are tender.","Using a masher, mash the potatoes and parsnips into a smooth puree.","Add the butter and milk, then fold through the Parmesan cheese.","Season to taste with salt and pepper and serve hot."}', '{side,mashed,potatoes,"comfort food"}', 'side', '2026-02-06 07:47:28.493602', NULL, 6, '{dairy}', '{gluten-free,vegetarian}', '{potatoes,parsnips,"Parmesan cheese",butter}', 35);
INSERT INTO public.recipes VALUES (57, 'Vanilla Buckwheat Porridge with Strawberries', 'Warm buckwheat porridge with vanilla, cinnamon, orange zest, and fresh strawberries - a hearty, nutritious start.', 291, 9, 48, 7, '/uploads/recipes/vanilla-buckwheat-porridge-strawberries.png', '{"170g raw buckwheat groats","1 1/2 cups water","1/2 cup almond milk","1/2 teaspoon vanilla extract","1 tablespoon ground cinnamon","1 teaspoon orange zest","2 tablespoons maple syrup","3 tablespoons strawberries","2 tablespoons orange juice, fresh","2 tablespoons ground flax seeds"}', '{"Rinse the buckwheat using a fine-mesh strainer. Add to a saucepan with water and bring to a boil, then reduce heat and simmer 20 minutes until tender.","Drain excess water if necessary.","In a bowl, combine almond milk, vanilla, cinnamon, orange zest, maple syrup, strawberries, orange juice and flax seeds.","Divide buckwheat among bowls and top with strawberry mixture."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 4, NULL, '{vegetarian}', NULL, 20);
INSERT INTO public.recipes VALUES (230, 'Baked Vegan Sweet Potato Fries', 'Crispy baked sweet potato fries seasoned with paprika and cayenne pepper. A simple, flavourful vegan side.', 151, 2, 20, 7, NULL, '{"1 sweet potato","1 tablespoon extra-virgin olive oil","1 teaspoon paprika","1 teaspoon sea salt","1 teaspoon cayenne pepper","1 tablespoon coconut oil"}', '{"Begin by preheating your oven to 200°C/400°F gas 6.","Wash your sweet potato and peel if desired. Cut into fries.","Place the sweet potato fries into a bowl and toss with olive oil, paprika, cayenne pepper and salt.","Spread the fries evenly across a baking tray and cook for 35-40 minutes, turning once.","Serve hot with your favourite condiments."}', '{side,fries,"sweet potato",spicy}', 'side', '2026-02-06 07:47:28.493602', NULL, 4, '{}', '{vegan,dairy-free,gluten-free}', '{"sweet potato",paprika,"cayenne pepper"}', 40);
INSERT INTO public.recipes VALUES (231, 'Caprese Salad', 'A classic Italian salad with colourful tomatoes, fresh mozzarella, basil and a drizzle of balsamic vinegar. Quick and elegant.', 100, 3, 4, 8, NULL, '{"150g different coloured tomatoes, halved","120g mozzarella balls","2 tablespoons extra-virgin olive oil","15g fresh basil","1 tablespoon balsamic vinegar"}', '{"In a large bowl, combine all the ingredients except the basil.","Gently toss the ingredients to combine.","Serve and top with fresh basil leaves."}', '{side,salad,italian,caprese}', 'side', '2026-02-06 07:47:28.493602', NULL, 6, '{dairy}', '{gluten-free,vegetarian}', '{tomatoes,mozzarella,basil,"balsamic vinegar"}', 10);
INSERT INTO public.recipes VALUES (60, 'Yogurt Granola Bowl', 'A quick assembly bowl with coconut yogurt, keto granola, fresh berries, chia seeds, and hemp hearts.', 451, 8, 19, 38, '/uploads/recipes/yogurt-granola-bowl.png', '{"150g coconut yogurt","30g vanilla maple keto granola","2 strawberries","1 tablespoon toasted coconut","50g fresh blueberries","1 tablespoon chia seeds","1 tablespoon hemp hearts","Fresh mint, optional as garnish"}', '{"Add the coconut yogurt to a bowl and arrange the other ingredients over the top. Enjoy!"}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (37, 'Toasted Malt Loaf with Blue Cheese and Apple', 'Sweet and savory combination of malt loaf with blue cheese and fresh apple', 474, 22, 65, 14, '/uploads/recipes/toasted-malt-loaf-blue-cheese-apple.png', '{"2 slices (70g) malt loaf","35g blue cheese","1/2 apple sliced thinly","15g greek or 0% greek yoghurt","1 tbsp honey"}', '{"Cheese always melts best from room temperature so take your cheese out before eating.","Slice your malt loaf and add to a toaster until crisped edges and fragrant twist on cut bread.","Mix the blue cheese and greek to a bowl with the blue cheese and mix together, then add over the slices of toast evenly. Layer your apple slices and finish both with honey.","Eat warm."}', NULL, 'breakfast', '2026-01-26 11:06:22.743455', NULL, 1, NULL, '{vegetarian}', NULL, 6);
INSERT INTO public.recipes VALUES (232, 'Parmesan Roasted Cauliflower', 'Golden roasted cauliflower florets with garlic and a crispy Parmesan crust. Irresistibly crunchy and cheesy.', 249, 14, 10, 17, NULL, '{"1 cauliflower, cut into florets","2 tablespoons olive oil","4 garlic cloves, crushed","60g Parmesan cheese, grated","A pinch salt and black pepper"}', '{"Begin by preheating your oven to 220°C/425°F gas 7.","In a large bowl, toss the cauliflower florets with olive oil, garlic, salt and pepper.","Once evenly coated, spread the cauliflower out on a baking tray.","Roast for 30 minutes, then remove from the oven and scatter over the Parmesan cheese.","Return to the oven for a further 10 minutes until golden and crispy.","Serve hot."}', '{side,roasted,cauliflower,cheesy}', 'side', '2026-02-06 07:47:28.493602', NULL, 4, '{dairy}', '{gluten-free,vegetarian,low-carb}', '{cauliflower,"Parmesan cheese",garlic}', 40);
INSERT INTO public.recipes VALUES (16, 'Mango Coconut Green Smoothie', 'A nutrient-packed green smoothie with hidden veggies and tropical flavor', 466, 33, 25, 26, '/uploads/recipes/mango-coconut-green-smoothie.png', '{"50g frozen cauliflower florets","25g frozen broccoli florets","85g frozen mango","250ml soya milk","60g full fat coconut milk","25g vanilla whey protein","15g cashew butter"}', '{"Place all ingredients into a high quality blender and blend for 30 seconds until smooth.","Give the mix a stir or shake and blend again for another 30 seconds.","Pour into a glass or on the go flask."}', NULL, 'breakfast', '2026-01-26 09:45:26.857146', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (233, 'Savoury Cheddar & Chive Scones', 'Wholesome scones packed with cheddar cheese, fresh chives and grated courgette. Perfect alongside soups or as a savoury snack.', 246, 10, 24, 13, NULL, '{"1 courgette, grated","187g wholemeal flour","24g baking powder","340g sour cream","90g cheddar cheese","12g fresh chives","Salt & cracked pepper"}', '{"Preheat oven to 200°C/400°F gas 6. Line a square baking dish with baking paper.","Place all ingredients into a large bowl and mix to combine.","Lightly flour a large board and place dough on the bench. Knead the dough for about 5 minutes.","Transfer dough to the prepared baking dish and score with a knife into 8 scones.","Cook for 40-45 minutes.","Remove from oven and cool for 10 minutes before serving."}', '{side,scones,baking,cheese}', 'side', '2026-02-06 07:47:28.493602', NULL, 8, '{dairy,gluten}', '{vegetarian}', '{"wholemeal flour","cheddar cheese",chives,courgette,"sour cream"}', 50);
INSERT INTO public.recipes VALUES (67, 'Rasp-Apple Smoothie', 'A tangy raspberry and green apple smoothie with Greek yogurt and psyllium husk for extra fiber.', 216, 11, 28, 7, '/uploads/recipes/rasp-apple-smoothie.png', '{"1 green apple","80g frozen raspberries","200g Greek yoghurt","125ml almond milk","1 tbsp psyllium husk","8 ice cubes"}', '{"Add all ingredients to a blender and blitz until combined."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (15, 'Salted Caramel Oats', 'Delicious overnight oats with dark chocolate and crushed peanuts', 556, 32, 53, 24, '/uploads/recipes/salted-caramel-oats.png', '{"45g oats","20g whey protein, chocolate flavoured","1/2 tsp maca powder","250ml almond milk","20g 70% dark chocolate","1 tsp coconut oil","1 tbsp crushed peanuts"}', '{"Mix all of the ingredients for the base and stir well, pour in a jar and leave to set.","Add the chocolate and coconut oil to a microwaveable bowl and microwave on full power for 10 second blasts until fully melted, mix to combine.","Add the peanuts on top of the jar of oats and top with the chocolate mixture.","Allow to fully cool until the top has set, refrigerate for 30 minutes or ideally overnight."}', NULL, 'breakfast', '2026-01-26 09:45:26.857146', NULL, 1, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (234, 'Bacon Avocado Chips', 'Crispy bacon-wrapped avocado slices baked until golden. A high-protein, low-carb side that''s irresistibly crunchy.', 200, 11, 1, 17, NULL, '{"2 avocados, cut into 1cm thick slices","12 slices bacon"}', '{"Preheat oven to 220°C/425°F gas 7. Line a baking tray with baking paper.","Wrap each slice of avocado in bacon and place them on the tray seam side down.","Place in the oven and cook for 15 minutes or until crispy."}', '{side,bacon,avocado,"low carb",crispy}', 'side', '2026-02-06 15:27:08.476574', NULL, 6, '{}', '{gluten-free,dairy-free,low-carb,high-protein}', '{avocado,bacon}', 25);
INSERT INTO public.recipes VALUES (235, 'Beet & Buckwheat Salad', 'Earthy beetroot and nutty buckwheat tossed with creamy goats cheese and fresh parsley. A hearty, colourful salad.', 270, 9, 26, 14, NULL, '{"70g buckwheat","2 tbsp olive oil","2 cooked beetroots, quartered","120g goats cheese","15g fresh parsley, leaves picked"}', '{"Start by cooking the buckwheat according to packet instructions. Once cooked, drain, cool and add to a medium sized bowl.","Stir through the beetroot, goats cheese and parsley.","Season with salt & cracked pepper."}', '{side,salad,beetroot,buckwheat}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{dairy}', '{gluten-free,vegetarian}', '{buckwheat,beetroot,"goats cheese",parsley}', 25);
INSERT INTO public.recipes VALUES (236, 'Tuna Cups', 'Light and fresh tuna and avocado mix served in crisp lettuce cups with a zesty lemon and mustard dressing.', 249, 21, 9, 14, NULL, '{"300g tuna in springwater, drained","2 medium avocado","1 tbsp mayonnaise","2 tbsp lemon juice","1 tsp Dijon mustard","2 tomatoes, diced","70g red onion, diced","8 iceberg lettuce leaves"}', '{"Place the tuna and avocado in a large mixing bowl. Mash up the tuna chunks and avocado with a wooden spoon and mix to combine.","Next, stir through the mayonnaise, lemon juice and Dijon mustard.","Gently stir through the tomatoes and red onion.","Divide the tuna mix between the lettuce cups and season with a little salt & cracked pepper."}', '{side,tuna,"lettuce cups",light}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{fish,eggs}', '{gluten-free,dairy-free,high-protein,low-carb}', '{tuna,avocado,lettuce,"lemon juice"}', 20);
INSERT INTO public.recipes VALUES (33, 'Apricot Breakfast Shake', 'Quick protein shake with dried apricots and peanut butter', 329, 40, 22, 9, '/uploads/recipes/apricot-breakfast-shake.png', '{"225g water","40g vanilla whey protein","40g dried apricot halves","20g peanut butter","225g plain low fat strained greek yoghurt","Pinch of cinnamon"}', '{"Add all of your ingredients to a blender and blitz for 45-60s.","Decant into a glass and top with a pinch of cinnamon."}', NULL, 'breakfast', '2026-01-26 11:01:56.569942', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (237, 'Potato Cakes', 'Golden pan-fried potato cakes loaded with cheese. Crispy on the outside, fluffy on the inside.', 217, 7, 21, 12, NULL, '{"625g mashed potato (chilled)","100g cheese","85g flour","1 egg","3 tbsp milk","1/2 tsp onion powder","60ml olive oil"}', '{"Mix all ingredients besides the oil in a large mixing bowl.","Heat the oil in a large frying pan over medium heat. Use a tablespoon to transfer the potato mix to the pan, frying each side until golden on the back of your spoon.","Cook for about 4 minutes each side or until golden. (Add more olive oil if needed).","Serve with a little chutney or sweet chilli sauce."}', '{side,potato,pan-fried,"comfort food"}', 'side', '2026-02-06 15:27:08.476574', NULL, 8, '{dairy,eggs,gluten}', '{vegetarian}', '{potato,cheese,flour,egg}', 20);
INSERT INTO public.recipes VALUES (238, 'Sweet Rice Cakes', 'Quick and easy rice cakes topped with creamy peanut butter and fresh banana slices. A perfect energy-boosting snack.', 346, 12, 43, 15, NULL, '{"2 rice cakes","2 tbsp peanut butter","1 banana, thinly sliced"}', '{"Spread each rice cake with peanut butter and top with banana slices."}', '{side,snack,quick,energy}', 'side', '2026-02-06 15:27:08.476574', NULL, 1, '{peanuts}', '{vegan,dairy-free,gluten-free}', '{"rice cakes","peanut butter",banana}', 5);
INSERT INTO public.recipes VALUES (239, 'Baked Ziti Pasta', 'Classic baked pasta with ricotta, marinara sauce and melted mozzarella. A crowd-pleasing comfort food side.', 558, 29, 70, 18, NULL, '{"32 ounces marinara sauce","15 ounces ricotta cheese","2 tbsp olive oil","1 garlic clove, minced","1 tsp dried oregano","1 tsp dried basil","1 tsp dried red pepper flakes","1 pound penne pasta","1/2 cup pasta water","1 pound fresh mozzarella cheese","1/2 cup grated pecorino or Parmesan cheese","Chopped fresh parsley and/or torn basil leaves, for garnish"}', '{"Preheat the oven to 200°C/400°F.","Bring a large pot of salted water to a boil. Add the penne and cook according to package instructions until just al dente.","In a large pan, heat olive oil and sauté garlic, oregano, basil and red pepper flakes.","Add marinara sauce and simmer for 5 minutes.","Stir ricotta into sauce.","Drain pasta, reserving pasta water. Combine pasta with sauce and a splash of pasta water.","Transfer to baking dish, top with mozzarella and Parmesan.","Bake for 15 minutes or until cheese is melted and golden."}', '{side,pasta,baked,italian,"comfort food"}', 'side', '2026-02-06 15:27:08.476574', NULL, 6, '{dairy,gluten}', '{vegetarian}', '{"penne pasta",ricotta,mozzarella,"marinara sauce"}', 35);
INSERT INTO public.recipes VALUES (240, 'Creamy Vegan Polenta with Mushrooms', 'Rich and creamy coconut polenta topped with garlic sautéed mushrooms and crunchy pine nuts. A satisfying vegan side.', 582, 19, 77, 22, NULL, '{"150g polenta","200ml full fat coconut milk","300ml vegetable broth","2-3 tbsp nutritional yeast flakes or vegan parmesan","1 tbsp olive oil or coconut oil","200g mushrooms, sliced","2 cloves garlic, minced","1-2 tbsp soy sauce","Salt & cracked pepper to taste","2-3 tbsp pine nuts"}', '{"Bring coconut milk and vegetable broth to a boil. Stir in polenta by whisking continuously. Reduce heat and simmer until thick.","Heat oil in a pan, sauté mushrooms and garlic until golden. Add soy sauce.","Serve polenta topped with mushrooms and pine nuts."}', '{side,polenta,mushrooms,vegan,creamy}', 'side', '2026-02-06 15:27:08.476574', NULL, 2, '{soy}', '{vegan,dairy-free,gluten-free}', '{polenta,mushrooms,"coconut milk","pine nuts"}', 15);
INSERT INTO public.recipes VALUES (40, 'Mango Smoothie', 'Simple tropical mango and banana smoothie', 273, 3, 63, 1, '/uploads/recipes/mango-smoothie.png', '{"2 mangoes","2 bananas","200ml orange juice","2 tablespoons honey"}', '{"Peel and cut the mangoes and bananas into chunks, then put them in a blender with orange juice and honey.","Whizz until smooth."}', NULL, 'breakfast', '2026-01-26 11:06:36.201073', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (241, 'Crispy Tofu', 'Baked tofu with a crispy coating of cornstarch and Asian spices, served over rice with edamame.', 539, 23, 51, 27, NULL, '{"7 ounces extra firm tofu, drained and cut into slices","1 tbsp tamari or soy sauce","2 tbsp cornstarch","1 tsp brown sugar","1/2 tsp garlic powder","1/2 tsp ground ginger","1/2 tsp sesame oil","1 tbsp vegetable oil","1/2 cup cooked rice","1/2 cup edamame"}', '{"Preheat oven to 200°C.","Toss tofu with soy sauce, cornstarch, sugar and spices.","Bake for 30 minutes, flipping halfway.","Serve over rice with edamame."}', '{side,tofu,asian,crispy,baked}', 'side', '2026-02-06 15:27:08.476574', NULL, 2, '{soy}', '{vegan,dairy-free}', '{tofu,tamari,rice,edamame}', 40);
INSERT INTO public.recipes VALUES (242, 'Avocado Hummus', 'Silky smooth hummus blended with creamy avocado, tahini and lemon. A healthy dip for chips or veggies.', 337, 6, 22, 25, NULL, '{"1 can chickpeas, drained and rinsed","1/4 cup lemon juice","1/2 avocado, peeled and chopped","2 tbsp tahini","2 tbsp olive oil","1 clove garlic","Salt & cracked pepper"}', '{"Combine all ingredients in a food processor or high speed blender.","Blend until smooth and creamy. Serve with tortilla chips or vegetables."}', '{side,hummus,dip,avocado}', 'side', '2026-02-06 15:27:08.476574', NULL, 2, '{sesame}', '{vegan,dairy-free,gluten-free}', '{chickpeas,avocado,tahini,"lemon juice"}', 5);
INSERT INTO public.recipes VALUES (243, 'Caprese Pesto Salad', 'Roasted cherry tomatoes with fresh bocconcini, pesto and a balsamic glaze drizzle. A warm twist on the classic caprese.', 251, 7, 4, 23, NULL, '{"3 tbsp extra virgin olive oil","150g cherry tomatoes, halved","2 tbsp pesto","125g bocconcini","2 tbsp balsamic glaze"}', '{"Preheat oven to 180°C.","Place tomatoes on a baking tray and roast for 10 minutes.","Combine tomatoes, bocconcini and pesto.","Drizzle with balsamic glaze before serving."}', '{side,salad,caprese,pesto,italian}', 'side', '2026-02-06 15:27:08.476574', NULL, 6, '{dairy,nuts}', '{gluten-free,vegetarian}', '{"cherry tomatoes",bocconcini,pesto,"balsamic glaze"}', 20);
INSERT INTO public.recipes VALUES (36, 'Almond Butter Baked Oats', 'Protein-packed baked oats with a hidden almond butter center', 353, 24, 35, 13, '/uploads/recipes/almond-butter-baked-oats.png', '{"45g oats","4g almond butter","45g whey protein","1/4 tsp baking powder","80ml almond milk","1 egg white","Drop of almond extract","Low calorie spray oil"}', '{"Pre heat your oven to 180C/350F/Gas Mark 4.","Collect all of your ingredients and blend them into a batter.","Lightly spray an oven safe ramekin or dish with low calorie spray oil, adding half of the batter to the dish. Add 1 tsp of almond butter to the middle and top with the second half of the batter.","Bake for 15 minutes, allow to cool for 2 minutes before eating and add any of your favourite toppings."}', NULL, 'breakfast', '2026-01-26 11:06:22.743455', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 20);
INSERT INTO public.recipes VALUES (61, 'Raspberries and Cheese Cream Crepes', 'Delicate cream cheese crepes filled with warm raspberry sauce - a special occasion breakfast treat.', 262, 15, 19, 14, '/uploads/recipes/raspberries-cheese-cream-crepes.png', '{"2 oz. cream cheese","2 large eggs","1 tablespoon rice malt syrup","1/4 teaspoon cinnamon","1/4 teaspoon baking soda","1 teaspoon sea salt","4 oz coconut cream","1/2 teaspoon vanilla extract","1 tablespoon brown sugar","8 oz raspberries","2 tablespoons brown sugar"}', '{"Combine cream cheese and eggs in a bowl and beat until smooth.","Add rice malt syrup, cinnamon, baking soda, salt, coconut cream and vanilla and mix well.","Heat a non-stick pan, lightly grease and pour in batter to form thin crepes. Cook both sides until golden.","Repeat to make 4 crepes.","Cook raspberries with brown sugar over low heat until they break down into a sauce.","Fill crepes, drizzle with raspberry sauce, roll up and serve."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 2, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (44, 'Easy Green Shakshuka', 'A vibrant green shakshuka loaded with asparagus, peas, and broad beans, topped with perfectly cooked eggs.', 414, 26, 28, 25, '/uploads/recipes/easy-green-shakshuka.png', '{"12 asparagus tips","100g peas","100g double podded broad beans","2 cloves garlic, shredded","1 tablespoon olive oil","1 tablespoon butter","2 baby leeks, sliced","1 garlic clove, sliced","2 tablespoons chopped herbs","4-6 eggs","chilli flakes, chopped","salt and pepper"}', '{"Bring a pan of salted water to a boil then add the asparagus and cook for 30 seconds. Add the peas and beans and cook for another 30 seconds then drain and refresh in cold water.","Heat the oil and butter in a frying pan. Add the garlic and leeks and cook gently until soft.","Add the blanched vegetables and cook for 3-4 minutes. Season well.","Make small holes and crack the eggs into the pan. Cover with a lid and cook until the whites are set but the yolks remain runny.","Scatter over herbs and chilli flakes and serve."}', '{Vegetarian}', 'breakfast', '2026-01-26 11:48:11.668489', NULL, 2, NULL, '{vegetarian}', '{Eggs}', 30);
INSERT INTO public.recipes VALUES (39, 'Green Smoothie', 'Refreshing green smoothie with spinach, cucumber and fresh mint', 263, 12, 38, 7, '/uploads/recipes/green-smoothie.png', '{"100g blueberries","10g fresh ginger","1 banana","3-4 fresh mint leaves","100g cucumber","50g washed spinach","250ml almond milk"}', '{"Add all of the ingredients to a blender and blitz for 45 to 60 seconds until fully incorporated.","Pour into a glass with ice."}', NULL, 'breakfast', '2026-01-26 11:06:36.201073', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 6);
INSERT INTO public.recipes VALUES (69, 'Chia Breakfast Bowl', 'Overnight chia pudding with sunflower seeds, almonds, dates, and fresh orange slices.', 586, 18, 59, 29, '/uploads/recipes/chia-breakfast-bowl.png', '{"6 tbsp chia seeds","2 tbsp sunflower seeds","2 tsp cinnamon","220ml almond milk","2 tbsp almonds, chopped","6 dates, chopped","6 slices orange"}', '{"Divide chia seeds, sunflower seeds, cinnamon and almond milk between two bowls or jars and mix well.","Place in fridge overnight.","In the morning, top each bowl with almonds, dates and slices of orange."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 10);
INSERT INTO public.recipes VALUES (58, 'Egg Cups with Courgette', 'Baked egg cups with courgette ribbons, ham, cherry tomatoes, and melted cheddar - perfect for meal prep.', 295, 24, 7, 19, '/uploads/recipes/egg-cups-with-courgette.png', '{"2 courgette, peeled into strips","60g ham, chopped","40g cherry tomatoes, quartered","4 eggs, beaten","100g cheddar cheese, grated","1 teaspoon salt and pepper","1/2 teaspoon thyme","200g shredded cheddar cheese","Cooking spray, for pan"}', '{"Preheat oven to 400°F (200°C) and grease a muffin tin with cooking spray.","Line the tin with courgette strips to form a cup.","Add ham and tomatoes to the cups.","Whisk eggs with salt, pepper and thyme, then pour into cups.","Top with cheese and bake until eggs are set and cheese melted, about 20-30 minutes."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 4, NULL, '{vegetarian,gluten-free}', '{Eggs}', 40);
INSERT INTO public.recipes VALUES (23, 'Mango and Coconut Chia Pudding', 'Creamy chia pudding with tropical mango and coconut toppings', 422, 27, 38, 18, '/uploads/recipes/mango-coconut-chia-pudding.png', '{"125g light coconut milk","60g chia seeds","400g 0% strained greek yoghurt","30g maple syrup","80g mango, sliced","12g coconut flakes"}', '{"In a medium bowl, whisk together coconut milk, chia seeds, yogurt, syrup and add 1/4 tsp salt.","Cover and refrigerate 6-8 hours or overnight.","Spoon pudding into bowls.","Top with the mango and coconut."}', NULL, 'breakfast', '2026-01-26 09:45:47.067631', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 360);
INSERT INTO public.recipes VALUES (38, 'Apple Almond Butter Salad', 'Sweet breakfast salad with apple, oats and dark chocolate', 339, 8, 34, 19, '/uploads/recipes/apple-almond-butter-salad.png', '{"80g apple diced","1 tbsp oats","12g crunchy almond butter","18g honey","10g 70% dark chocolate diced","Juice of 1/4 lemon","Powdered sweetener to taste"}', '{"Place your nut butter and lemon juice into a mixing bowl and break down the almond butter.","Add oats, apple, dark chocolate and honey and toss very well to combine and coat all ingredients.","Serve by itself or with your favourite Skyr or protein yoghurt."}', NULL, 'breakfast', '2026-01-26 11:06:22.743455', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 6);
INSERT INTO public.recipes VALUES (42, 'Fruit Salad with Crunchy Nuts', 'Fresh fruit salad with mixed seeds and nuts', 464, 17, 54, 20, '/uploads/recipes/fruit-salad-crunchy-nuts.png', '{"2 large oranges","2 kiwis","2 cups strawberries","25g pumpkin seeds","15g sunflower seeds","1/2 tablespoon honey","15g Greek yoghurt","20g almonds, chopped"}', '{"Peel and remove the pith from the oranges. Deep zest and slice juice, then slice the orange segments removing seeds and membrane. Place orange segments into a bowl.","Slice the kiwis and strawberries and add to the orange.","Mix together the seeds and honey and scatter over the fruit.","Top with yoghurt and chopped almonds and serve."}', NULL, 'breakfast', '2026-01-26 11:06:36.201073', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 10);
INSERT INTO public.recipes VALUES (68, 'Good Morning Smoothie', 'A tropical wake-up blend of orange juice, pineapple, frozen banana, maca, and lime.', 219, 3, 53, 1, '/uploads/recipes/good-morning-smoothie.png', '{"125ml orange juice","100g tinned pineapple","1 frozen banana, peeled","1 tsp maca","1/2 lime, juiced"}', '{"Add all ingredients to a blender and blitz until combined."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (73, 'Cherry Ripe Smoothie', 'A rich chocolate and cherry smoothie with coconut milk, topped with cacao nibs.', 407, 25, 34, 19, '/uploads/recipes/cherry-ripe-smoothie.png', '{"250ml coconut milk","1 scoop chocolate protein powder (vegan if required)","140g cherries, pitted","1 tbsp desiccated coconut","1 tbsp cacao nibs"}', '{"Blend all ingredients except cacao nibs until smooth.","Pour into glass and top with cacao nibs and extra cherries."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (27, 'Ham and Swiss Cheese Baked Eggs', 'Savory baked eggs with ham, swiss cheese and asparagus', 342, 34, 2, 22, '/uploads/recipes/ham-swiss-cheese-baked-eggs.png', '{"10g butter","20g onion diced","4 eggs","40g egg whites","40g sliced ham","60g swiss cheese, grated","60g asparagus, trimmed and diced","10g american mustard"}', '{"Pre heat a small non-stick pan with a heatproof handle over medium heat and grill to high.","Melt butter and then add onion and cook until softened.","Whisk eggs and whites, salt, pepper and half of the cheese in a mixing bowl and then add to the pan.","Cook, stirring constantly, until the eggs form soft, creamy curds, about 5 minutes.","Remove from heat, sprinkle remaining cheese over top of eggs.","Place the cooked eggs under a hot grill; cook until cheese is bubbly and golden, about 3 minutes. Carefully remove.","To remove frittata whole, tip the pan to one side and use a spatula to loosen edges. Slide onto a serving plate."}', NULL, 'breakfast', '2026-01-26 11:01:35.793708', NULL, 2, NULL, '{high-protein}', '{Pork,Eggs}', 20);
INSERT INTO public.recipes VALUES (72, 'Breakfast Sausage Burrito', 'Warm tortillas filled with savory breakfast sausage, bell peppers, fresh avocado, and tomato.', 491, 15, 38, 31, '/uploads/recipes/breakfast-sausage-burrito.png', '{"2 tsp olive oil","1 brown onion, diced","250g breakfast sausage","150g bell pepper, diced","3 tortillas (gluten free if required)","1/2 avocado, sliced","1 large tomato, sliced"}', '{"Heat oil in frying pan and cook onion for 5 minutes.","Add sausage and bell pepper. Cook for about 7 minutes until fully cooked.","Heat tortillas in microwave for 40 seconds.","Spoon sausage mixture into tortillas and top with avocado and tomato."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 3, NULL, '{high-protein}', NULL, 20);
INSERT INTO public.recipes VALUES (76, 'Miso Mushrooms on Toast', 'Savory umami mushrooms in miso and tamari sauce served on toasted rye bread.', 390, 12, 45, 18, '/uploads/recipes/miso-mushrooms-on-toast.png', '{"1 tbsp olive oil","1 clove garlic, minced","200g mushrooms","30g white miso paste","10ml tamari","120ml water","1 tsp chives","1 slice rye bread, toasted (gluten free if required)"}', '{"In a medium sized frying pan, heat the olive oil. Add the mushrooms and cook for 5 minutes or until browned.","Stir in the miso, tamari and water and cook for another 2 to 3 minutes.","Top toast with mushrooms, chives, salt & cracked pepper."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 1, NULL, '{vegetarian}', NULL, 15);
INSERT INTO public.recipes VALUES (54, 'Banana Almond Milk Smoothie', 'A creamy, protein-rich smoothie with banana, almond butter, and hemp seeds - perfect for a quick energy boost.', 424, 11, 32, 28, '/uploads/recipes/banana-almond-milk-smoothie.png', '{"1 banana","2 tablespoons almond butter","120ml almond milk","2 tablespoons honey","1 tablespoon hemp seed","1/2 teaspoon ground cinnamon","8-10 ice cubes"}', '{"Add all the ingredients to a blender.","Blend until smooth and creamy.","Replace the honey with maple syrup to make this dish vegan."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (59, 'Bell Peppers Ham Cheese and Eggs Breakfast', 'Eggs baked in colorful bell pepper rings with ham, feta cheese, and fresh herbs.', 158, 24, 11, 2, '/uploads/recipes/bell-peppers-ham-cheese-eggs.png', '{"2 bell peppers, sliced into rings","6 eggs, beaten","100g ham, chopped","1 teaspoon salt and freshly ground black pepper","1 tablespoon chopped parsley","2 teaspoons chopped chives","75g feta cheese, crumbled"}', '{"In a medium bowl whisk together eggs, feta cheese and chopped bacon. Add salt and black pepper to taste.","Place a skillet over medium heat and coat with cooking spray.","Add pepper rings and cook 2 minutes.","Pour egg mixture into pepper rings. Cover and cook 6-8 minutes until egg is set.","Garnish with chopped parsley."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 3, NULL, '{high-protein}', '{Pork,Eggs}', 20);
INSERT INTO public.recipes VALUES (31, 'Bacon Egg Cups on Wholemeal Toast', 'Savory bacon egg cups served on wholemeal toast with cream cheese', 488, 35, 33, 24, '/uploads/recipes/bacon-egg-cups-wholemeal-toast.png', '{"4 rashers back bacon (120g)","2 eggs","30g cheddar","15g chives","4 medium slices wholemeal bread","4 x thin slice of beef tomato","120g low fat spreadable cream cheese"}', '{"Pre heat oven to 200C/400F/Gas Mark 6.","Place each rasher of bacon into a section of a muffin tray covering the base and sides, fold up.","Bake for 8 minutes.","Meanwhile, beat the eggs, add chives and seasoning.","When the bacon has firmed, pour equal amounts of the egg mixture into each rasher and place back into the oven for a further 8 minutes until the egg is cooked.","Remove from oven, allow to cool slightly.","Spread 30g of low fat spreadable cream cheese over each toast and add a slice of beef tomato.","Place the bacon cups on top and serve."}', NULL, 'breakfast', '2026-01-26 11:01:56.569942', NULL, 2, NULL, '{high-protein}', '{Pork,Eggs}', 20);
INSERT INTO public.recipes VALUES (244, 'Carrot and Ginger Soup', 'Warming carrot soup with fresh ginger, turmeric and coconut milk. Silky smooth and full of flavour.', 401, 7, 55, 17, NULL, '{"2 pounds carrots, chopped","1 large onion, chopped","1 tablespoon salt","1 1/2 teaspoons turmeric","2 tablespoons fresh ginger, minced","700ml vegetable stock","1 can light coconut milk","2 tablespoons olive oil","1 teaspoon black pepper"}', '{"Heat a large saucepan over medium heat. Add in olive oil and carrots, fry for 10 minutes, until the carrots are slightly tender. Add in the onion and salt, and cook until softened. Stir in turmeric, fresh ginger and vegetable stock. Bring to a simmer and cook for 30 minutes.","Once cooked, blend until smooth. Add in the coconut milk and black pepper. Taste and adjust seasoning if required."}', '{side,soup,carrot,ginger,warming}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{}', '{vegan,dairy-free,gluten-free}', '{carrots,ginger,turmeric,"coconut milk"}', 80);
INSERT INTO public.recipes VALUES (53, 'Gingerbread French Toast', 'Warm spiced French toast with cinnamon, nutmeg, ginger, and cloves, dusted with powdered sugar.', 422, 16, 58, 14, '/uploads/recipes/gingerbread-french-toast.png', '{"2 eggs","125ml milk","1/2 teaspoon ground cinnamon","1/2 teaspoon ground nutmeg","1/2 teaspoon ground ginger","1/4 teaspoon ground cloves","4 slices bread","1 tablespoon butter","1 tablespoon powdered sugar"}', '{"Whisk together eggs, milk and spices.","Submerge bread in mixture, turning to coat.","Heat butter in non-stick pan and cook bread slices for 3-4 minutes each side until golden.","Serve with powdered sugar and berries."}', '{Vegetarian}', 'breakfast', '2026-01-26 11:48:42.378923', NULL, 4, NULL, '{vegetarian}', NULL, 20);
INSERT INTO public.recipes VALUES (181, 'Peanut Lime Tempeh Noodles', 'Satisfying noodle bowl with tempeh and zesty peanut lime sauce', 415, 24, 46, 15, '/uploads/recipes/peanut-lime-tempeh-noodles.png', '{"150g tempeh","100g wholewheat noodles","1 tbsp peanut butter","Lime juice","Soy sauce","Spring onions"}', '{"Cook noodles","Pan fry tempeh","Stir peanut butter, soy and lime","Toss together and top with onions"}', '{Vegan,"High protein"}', 'main', '2026-01-27 21:04:45.357141', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Grains}', 30);
INSERT INTO public.recipes VALUES (182, 'Roasted Cauliflower and Lentil Salad', 'Warm salad with roasted cauliflower, lentils and tahini dressing', 309, 14, 34, 13, '/uploads/recipes/roasted-cauliflower-lentil-salad.png', '{"1 small cauliflower florets","150g cooked lentils","1 tbsp olive oil","Tahini drizzle","Lemon juice",Parsley}', '{"Roast cauliflower with olive oil","Toss with lentils","Finish with tahini and lemon"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:45.357141', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 35);
INSERT INTO public.recipes VALUES (183, 'Stuffed Peppers with Herby Beans', 'Roasted peppers filled with herb-infused mixed beans', 257, 13, 31, 9, '/uploads/recipes/stuffed-peppers-herby-beans.png', '{"3 red peppers halved","1 tin mixed beans","1 tbsp olive oil",Garlic,"Fresh herbs","Lemon zest"}', '{"Roast peppers for 20 minutes","Warm beans with garlic and herbs","Spoon beans into peppers and bake 10 minutes more"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:45.357141', 'Easy', 3, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 45);
INSERT INTO public.recipes VALUES (184, 'Ginger Garlic Tofu with Broccoli', 'Simple stir-fried tofu with ginger, garlic and tender broccoli', 263, 22, 10, 15, '/uploads/recipes/ginger-garlic-tofu-broccoli.png', '{"200g tofu","1 tbsp olive oil","1 clove garlic","Fresh ginger","200g broccoli","Soy sauce"}', '{"Fry tofu until golden","Add garlic and ginger","Stir in broccoli and soy","Cook until tender"}', '{Vegan,"High protein",Low-carb}', 'main', '2026-01-27 21:04:45.357141', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 25);
INSERT INTO public.recipes VALUES (245, 'Satay Dipping Sauce', 'A rich and spicy peanut dipping sauce with chilli and rice wine vinegar. Served with fresh cucumber sticks.', 273, 6, 6, 25, NULL, '{"60ml peanut oil","2 long red chillies, sliced","75g peanuts","25ml rice wine vinegar","1 large cucumber, sliced into matchsticks"}', '{"Place the oil in a small saucepan on medium heat. Add the chillies, peanuts and rice wine vinegar and cook stirring continuously for 5 minutes.","Transfer the peanuts and sauce to a blender and blitz until combined.","Serve with cucumber sticks."}', '{side,sauce,dip,satay,peanut}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{peanuts}', '{vegan,dairy-free,gluten-free}', '{peanuts,chillies,"rice wine vinegar",cucumber}', 15);
INSERT INTO public.recipes VALUES (246, 'Mushroom, Spinach and Caramelised Onion Pizza', 'Homemade pizza topped with caramelised onions, sautéed mushrooms, baby spinach and melted cheese with sun-dried tomatoes.', 195, 10, 14, 11, NULL, '{"1 package pizza crust dough","1 tablespoon olive oil","1 tablespoon butter","1 onion, thinly sliced","1/4 teaspoon salt","250g sliced button mushrooms","2 cloves garlic, minced","20g baby spinach leaves","120g shredded mozzarella cheese","45g parmesan cheese","1 teaspoon chopped fresh thyme leaves","30g sun-dried tomatoes"}', '{"Heat oven to 200°C/400°F. On medium heat, melt butter and olive oil in a pan. Add onion, cook for 10 minutes until caramelised. Remove from heat.","Sauté mushrooms and garlic until softened. Stir in spinach.","Roll pizza dough out and top with onion, mushroom mixture, cheeses, thyme and sun-dried tomatoes.","Bake for 15 minutes until golden and cooked."}', '{side,pizza,mushroom,spinach}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{dairy,gluten}', '{vegetarian}', '{"pizza dough",mushrooms,spinach,mozzarella,onion}', 30);
INSERT INTO public.recipes VALUES (247, 'BBQ Corn', 'Chargrilled corn cobs smothered in pesto and sprinkled with cheddar and Parmesan cheese.', 324, 15, 25, 18, NULL, '{"4 corn cobs","4 tbsp pesto sauce","60g cheddar cheese","50g parmesan cheese","Salt & cracked pepper"}', '{"Preheat grill to high heat. Add corn and cook, turning regularly, for about 10 minutes or until charred all over.","Spread 1 tbsp pesto on each cob, sprinkle with cheese and season with salt & pepper."}', '{side,corn,bbq,grilled,cheesy}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{dairy,nuts}', '{gluten-free,vegetarian}', '{corn,pesto,"cheddar cheese","parmesan cheese"}', 20);
INSERT INTO public.recipes VALUES (248, 'Ham and Corn Savoury Muffins', 'Fluffy savoury muffins packed with ham, cheese and creamed corn. Great for lunchboxes and meal prep.', 197, 7, 20, 10, NULL, '{"300g self raising flour","100g shaved ham","175ml milk","1 egg, beaten","50ml olive oil","100g tasty cheese","100g creamed corn"}', '{"Preheat oven to 180°C/350°F gas 4. Grease a 12 cup muffin tray with olive oil cooking spray.","In a large bowl, mix together the flour, ham and cheese.","In a separate bowl, mix milk, egg and olive oil, then combine with flour mixture.","Spoon mixture into the muffin tray and bake for 20 minutes.","Allow to cool for 5 minutes before serving."}', '{side,muffins,savoury,ham,"meal prep"}', 'side', '2026-02-06 15:27:08.476574', NULL, 12, '{dairy,eggs,gluten}', '{}', '{flour,ham,cheese,corn,egg}', 40);
INSERT INTO public.recipes VALUES (249, 'Tomato Bisque', 'A rich and velvety tomato soup finished with heavy cream. Classic comfort in a bowl.', 253, 5, 14, 20, NULL, '{"2 tbsp olive oil","3 strips spring onion, diced","1 clove garlic, finely chopped","1 carrot, chopped","1 stick celery, chopped","1/2 tsp salt","1/2 tsp cracked pepper","1 tbsp dried oregano","1 tsp dried parsley","1 bay leaf","1 vegetable stock","800g crushed tomatoes","250ml heavy cream"}', '{"Add olive oil to a large saucepan over high heat. Add the spring onion and garlic and cook, stirring continuously for 3-4 minutes.","Add carrot and celery and cook for another 5 minutes.","Next add the salt & cracked pepper, oregano, parsley, bay leaf, vegetable stock, and tomatoes.","Reduce the heat and simmer for 30-40 minutes.","Transfer to a blender or use a stick blender and blitz until smooth.","Finish by stirring the cream.","Divide between 4 bowls and season with salt & cracked pepper."}', '{side,soup,tomato,creamy,"comfort food"}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{dairy}', '{gluten-free,vegetarian}', '{"crushed tomatoes","heavy cream","vegetable stock",celery}', 60);
INSERT INTO public.recipes VALUES (78, 'Overnight Espresso Oats', 'Coffee-infused overnight oats with chocolate protein and coconut yogurt, topped with cacao nibs.', 415, 38, 41, 11, '/uploads/recipes/overnight-espresso-oats.png', '{"45g oats (gluten free if required)","1 tbsp honey","125g coconut yoghurt","60ml espresso","1 scoop chocolate protein powder (vegan if required)","1/2 tbsp cacao nibs"}', '{"Add the oats to a bowl or jar along with the honey, coconut yoghurt, espresso and protein powder.","Mix to combine, cover and place in the fridge overnight.","Before serving top with cacao nibs."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (63, 'Oatmeal Hot Cereal', 'A low-carb, coconut-based hot cereal with flaxseed and vanilla - warm and satisfying.', 83, 7, 7, 3, '/uploads/recipes/oatmeal-hot-cereal.png', '{"35g unsweetened coconut flakes","310ml almond milk","310ml water","2 tablespoons coconut flour","2 tablespoons flaxseed meal (or chia seed)","1 teaspoon vanilla extract","8 drops monk fruit liquid extract (or 6 drops stevia)"}', '{"Toast coconut flakes in a medium pot over medium-high heat.","Bring almond milk and water to boil, stir in coconut flour, flaxseed meal and vanilla.","Reduce heat and simmer for 10 minutes, stirring occasionally.","Remove from heat and add remaining ingredients."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 15);
INSERT INTO public.recipes VALUES (77, 'Basil Eggs', 'Soft-boiled eggs tossed with fresh basil, spinach, and lemon, served alongside crispy bacon.', 415, 27, 3, 33, '/uploads/recipes/basil-eggs.png', '{"8 rashers bacon","8 eggs","1 avocado","1/2 bunch basil, chopped","150g spinach","1/2 lemon, juiced"}', '{"Start by boiling the eggs. Place them in a medium sized saucepan, cover with water and bring to a boil. Once boiling cook for 4 to 5 minutes.","Meanwhile, bring a large non stick frying pan to medium high heat and cook bacon rashers for 3 to 4 minutes each side.","Once eggs are cooked, peel under cold running water. Slice the eggs into halves.","Toss the eggs with basil, spinach, lemon juice, salt & cracked pepper.","Divide eggs and bacon on 4 plates and serve hot."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 4, NULL, '{vegetarian,high-protein}', '{Eggs}', 20);
INSERT INTO public.recipes VALUES (250, 'Roasted Carrots', 'Simple cumin-spiced roasted carrots with sweet raisins and fresh parsley. A colourful, flavourful side.', 124, 2, 20, 4, NULL, '{"8 carrots, sliced","1 red onion, diced","2 tbsp olive oil","1/2 tsp cumin","40g raisins","10g fresh parsley"}', '{"Preheat oven to 180°C/350°F gas 4. Line a baking tray with baking paper.","In a large bowl toss together the carrots, onion, olive oil and cumin. Lay on tray.","Roast carrots for 25 minutes then add raisins and cook.","Once cooked, toss through the raisins and sprinkle with fresh parsley."}', '{side,roasted,carrots,cumin}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{}', '{vegan,dairy-free,gluten-free}', '{carrots,cumin,raisins,parsley}', 45);
INSERT INTO public.recipes VALUES (251, 'Lamb with Houmous', 'Spiced harissa lamb mince served with houmous, fresh tomatoes and warm wholemeal pittas.', 478, 41, 39, 16, NULL, '{"1 tbsp olive oil","1 onion, finely chopped","500g lamb, minced","1 clove garlic, minced","1/2 tbsp harissa spice","50g sultanas","4 tomatoes, chopped","1/2 red onion, diced","120g houmous","4 wholemeal pittas"}', '{"Heat oil in a frying pan over medium heat. Add onion and cook for 5 minutes or until softened.","Add the garlic, lamb and harissa and cook for 5-7 minutes or until lamb is cooked.","Place the rocket on a serving plate and top with lamb.","Add chopped tomatoes, cucumber and red onion and serve on the side of the lamb with houmous and pittas."}', '{side,lamb,harissa,"middle eastern"}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{gluten,sesame}', '{high-protein}', '{"lamb mince",harissa,houmous,"wholemeal pittas"}', 25);
INSERT INTO public.recipes VALUES (252, 'Parmesan Courgette', 'Quick pan-fried courgette with garlic, basil and a squeeze of lemon, finished with grated Parmesan.', 155, 9, 6, 11, NULL, '{"1 tbsp olive oil","1 clove garlic","1 courgette, diced","2 tbsp dried basil","Salt & cracked pepper","1/2 lemon, juiced","2 tbsp Parmesan cheese, grated"}', '{"Start by heating the olive oil in a medium sized frying pan. Add the garlic, courgette, basil, salt & cracked pepper and cook for 5-7 minutes or until courgette is tender.","Stir through the lemon juice and remove from the heat.","Transfer to serving dish and sprinkle with Parmesan cheese."}', '{side,courgette,quick,parmesan}', 'side', '2026-02-06 15:27:08.476574', NULL, 2, '{dairy}', '{gluten-free,vegetarian,low-carb}', '{courgette,"Parmesan cheese",garlic,lemon}', 15);
INSERT INTO public.recipes VALUES (253, 'Hasselback Potatoes', 'Impressive fan-cut potatoes roasted with garlic and rosemary, topped with Parmesan and breadcrumbs.', 273, 8, 45, 7, NULL, '{"1kg desiree potatoes","1 tbsp olive oil","2 tbsp garlic, minced","2 tbsp fresh rosemary, chopped","Salt & cracked pepper","20g parmesan cheese","20g breadcrumbs (gluten free if required)"}', '{"Preheat oven to 200°C/400°F gas 6. Line a baking tray with baking paper and lightly grease with olive oil cooking spray.","Cut slits into each potato, 3mm apart. The cuts should be deep but not all the way through.","Mix together 2 tbsp olive oil and the garlic in a small bowl. Brush the potatoes with oil & garlic.","Place in the oven and cook for 60 minutes.","Carefully remove the potatoes from the oven and sprinkle with cheese, breadcrumbs and rosemary.","Return to oven and cook for 10 minutes.","Allow to cool for 5 minutes before serving."}', '{side,potatoes,roasted,hasselback}', 'side', '2026-02-06 15:27:08.476574', NULL, 4, '{dairy,gluten}', '{vegetarian}', '{potatoes,garlic,rosemary,"parmesan cheese"}', 80);
INSERT INTO public.recipes VALUES (155, 'Chicken Pasta Salad', 'Cold pasta salad with chicken, pesto, tomatoes and a creamy dressing.', 2802, 156, 396, 66, '/uploads/recipes/chicken-pasta-salad.jpg', '{"2 tbsp olive oil","250g chicken breast, sliced","250g shell pasta","150g cherry tomatoes, diced","200g sweet corn","3 spring onions, thinly sliced","80g green pesto","150g mayonnaise","80g Greek yoghurt","1 tbsp lemon juice","2 tsp white vinegar","1 tsp Dijon mustard","1 tbsp dried oregano","Salt and cracked pepper"}', '{"Cook pasta according to packet instructions. Drain and rinse under cold water.","Heat oil in a frying pan. Cook chicken for 7 minutes or until cooked through. Allow to cool.","Mix all dressing ingredients in a bowl.","Toss pasta, chicken, vegetables and corn together in a large bowl.","Add dressing and toss to coat. Refrigerate until serving."}', '{}', 'main', '2026-01-27 08:30:35.639229', NULL, 6, NULL, '{high-protein}', '{Chicken}', 45);
INSERT INTO public.recipes VALUES (157, 'Pasta Primavera', 'Light spring pasta with asparagus, peas and Parmesan.', 1700, 88, 268, 28, '/uploads/recipes/pasta-primavera.jpg', '{"350g farfalle pasta","200g asparagus, chopped","170g frozen green peas","135g fresh rocket","2 tbsp lemon juice","4 tbsp Parmesan"}', '{"Cook pasta according to packet instructions. Drain and set aside.","Boil asparagus and peas for 3 to 4 minutes.","Mix lemon juice and Parmesan in a small bowl.","Toss vegetables and sauce through the pasta.","Divide between bowls and season with salt and cracked pepper."}', '{Vegetarian}', 'main', '2026-01-27 08:30:35.639229', NULL, 4, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (176, 'Lentil and Mushroom Shepherds Pie', 'Classic comfort food made vegan with lentils and mushrooms', 321, 16, 44, 9, '/uploads/recipes/lentil-mushroom-shepherds-pie.png', '{"200g green lentils","250g mushrooms chopped","1 onion","500g potatoes mashed","1 tbsp olive oil",Thyme}', '{"Cook lentils until tender","Sauté mushrooms and onion","Combine and top with mash","Bake at 200C for 25 minutes"}', '{Vegan}', 'main', '2026-01-27 21:04:24.529492', 'Medium', 4, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 55);
INSERT INTO public.recipes VALUES (178, 'Smoky Bean Chilli', 'Hearty vegan chilli loaded with kidney and black beans', 270, 15, 39, 6, '/uploads/recipes/smoky-bean-chilli.png', '{"1 tin kidney beans","1 tin black beans","400g chopped tomatoes","1 onion","1 tbsp tomato puree","1 tsp smoked paprika",Cumin}', '{"Sauté onion","Add spices and tomato puree","Stir in beans and tomatoes","Simmer for 25 minutes"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 4, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 40);
INSERT INTO public.recipes VALUES (180, 'Chickpea Flour Socca with Roasted Veg', 'Crispy chickpea flour pancake served with Mediterranean roasted vegetables', 288, 17, 28, 12, '/uploads/recipes/chickpea-flour-socca.png', '{"100g chickpea flour","150ml water","1 tbsp olive oil","Mixed roasted vegetables","Sea salt"}', '{"Whisk flour and water with salt","Cook batter in hot pan","Serve with roasted vegetables"}', '{Vegan,Gluten-free}', 'main', '2026-01-27 21:04:45.357141', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 30);
INSERT INTO public.recipes VALUES (75, 'Eggs with Hollandaise', 'Classic eggs served on toasted English scones with shaved ham and rich hollandaise sauce.', 528, 36, 33, 28, '/uploads/recipes/eggs-with-hollandaise.png', '{"4 eggs","60ml milk","2 tsp butter","2 English scones, halved (gluten free if required), toasted","200g shaved ham","2 tbsp hollandaise sauce"}', '{"Start by whisking the eggs and the milk together.","Melt the butter in a medium sized frying pan. Add the eggs and cook on a low medium heat, gently moving the eggs. Remove from heat.","Top the toasted scones with egg, ham and hollandaise sauce. Season with salt & cracked pepper."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 2, NULL, '{vegetarian,high-protein}', '{Eggs}', 15);
INSERT INTO public.recipes VALUES (21, 'Full Breakfast Stack', 'A complete savory breakfast stack with eggs, bacon, and black pudding', 389, 26, 15, 25, '/uploads/recipes/full-breakfast-stack.png', '{"1cm thick slice of beef tomato","60g slice of black pudding","1 reduced fat pork sausage, sliced in half","1 rasher of back bacon","1 medium egg","Handful of spinach"}', '{"Heat an oven grill to a medium high temperature.","Arrange black pudding, sausage, tomato and bacon across a grill pan and cook for 8 minutes, turning occasionally.","Meanwhile, prepare the poached egg by first placing it in a mug of boiling water for 1 minute - this will begin to thicken the egg white. Bring a pan of salted water to the boil, reduce the heat low and carefully crack the egg into the middle and poach for 2 minutes. Remove with a slotted spoon and leave to drain on kitchen paper.","Arrange your breakfast stack with a handful of spinach at the base, tomato, then black pudding followed by the sausage, rashers of bacon and top with the poached egg."}', NULL, 'breakfast', '2026-01-26 09:45:47.067631', NULL, 1, NULL, '{vegetarian,high-protein}', NULL, 17);
INSERT INTO public.recipes VALUES (70, 'Egg Toast', 'Classic egg-in-a-hole toast with melted cheddar cheese - simple and satisfying.', 326, 18, 18, 21, '/uploads/recipes/egg-toast.png', '{"2 slices wholemeal bread (gluten free if required)","2 tsp butter","2 eggs","20g cheddar cheese, grated"}', '{"Using a cookie cutter or glass, cut a hole in each slice of bread.","Heat pan and cook bread for 2 minutes until golden.","Flip bread, crack egg into hole and sprinkle with cheese.","Cook for 3 to 4 minutes or until egg is cooked to preference.","Season with salt & cracked pepper and serve."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 2, NULL, '{vegetarian,high-protein}', '{Eggs}', 10);
INSERT INTO public.recipes VALUES (177, 'Edamame and Quinoa Protein Salad', 'High protein salad with quinoa, edamame and fresh vegetables', 308, 18, 32, 12, '/uploads/recipes/edamame-quinoa-protein-salad.png', '{"150g cooked quinoa","100g edamame beans","Cucumber diced","Cherry tomatoes","1 tbsp olive oil","Lemon juice"}', '{"Combine everything in a bowl","Toss with olive oil and lemon","Serve chilled"}', '{Vegan,"High protein",Gluten-free}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables,Grains}', 20);
INSERT INTO public.recipes VALUES (179, 'Courgette Noodle Satay', 'Light courgetti with crispy tofu and creamy peanut satay sauce', 258, 19, 14, 14, '/uploads/recipes/courgette-noodle-satay.png', '{"2 courgettes spiralised","150g tofu strips","1 tbsp peanut butter","1 tsp soy sauce","Lime juice","Chilli flakes"}', '{"Pan fry tofu","Stir peanut butter, soy and lime into sauce","Toss courgette noodles through"}', '{Vegan,Low-carb}', 'main', '2026-01-27 21:04:24.529492', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 20);
INSERT INTO public.recipes VALUES (96, 'Black Bean and Corn Quesadillas', 'Quick vegetarian quesadillas packed with black beans, sweetcorn and melted cheddar cheese.', 2024, 88, 256, 72, '/uploads/recipes/black-bean-and-corn-quesadillas.jpg', '{"400 grams tin black beans, drained and rinsed","130 grams sweet corn","60 grams salsa","2 teaspoons taco seasoning","A handful fresh coriander, chopped","30 grams cheddar cheese, grated","8 tortilla wraps"}', '{"In a medium bowl, combine the beans, sweet corn, salsa, taco seasoning and coriander.","Heat a large frying pan over medium heat and place one tortilla inside.","Spread the bean mixture over half of the tortilla and sprinkle with cheese.","Fold the tortilla over and cook until golden on both sides.","Repeat with remaining tortillas.","Serve hot with guacamole, sour cream or hot sauce."}', '{}', 'main', '2026-01-27 06:41:45.44209', NULL, 4, NULL, '{vegan,dairy-free}', NULL, 15);
INSERT INTO public.recipes VALUES (71, 'Green Protein Pancakes', 'Spinach-packed protein pancakes made with buckwheat flour, served with fresh avocado.', 401, 30, 32, 17, '/uploads/recipes/green-protein-pancakes.png', '{"200g spinach","280ml buttermilk","2 eggs, beaten","1 tbsp lemon protein powder","75g buckwheat flour","1 tsp baking powder","2 tsp salt","1 tbsp avocado oil","1 avocado"}', '{"Place spinach in colander and pour over boiling water. Squeeze excess liquid.","Blend spinach with buttermilk and egg until smooth.","Mix dry ingredients in a bowl.","Combine wet and dry ingredients.","Cook pancakes in avocado oil, 2 to 3 minutes per side.","Serve with sliced avocado."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 3, NULL, '{vegetarian,high-protein}', NULL, 35);
INSERT INTO public.recipes VALUES (88, 'Black Forest Overnight Oats', 'Chocolate and cherry overnight oats topped with dark chocolate chips and coconut yogurt.', 238, 16, 30, 6, '/uploads/recipes/black-forest-overnight-oats.png', '{"65g rolled oats","1 tbsp unsweetened cacao powder","2 tbsp unsweetened almond milk","1 tbsp maple syrup","1 tbsp vanilla extract","65g frozen dark cherries","1 tbsp dark chocolate chips","2 tsp chia seeds","2 tbsp coconut yoghurt"}', '{"Mix the oats, cacao powder, almond milk, maple syrup and vanilla extract together in a bowl or jar.","Add the cherries and dark chocolate chips and stir to combine.","Cover and place in the fridge overnight.","Before serving, top with coconut yoghurt."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 2, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (56, 'Easy Berry Parfaits', 'Fresh strawberries and blueberries layered with Greek yogurt, mint, and a light raspberry vinaigrette.', 179, 5, 24, 7, '/uploads/recipes/easy-berry-parfaits.png', '{"400g fresh strawberries, cut into pieces","340g fresh blueberries","2 teaspoons reduced-fat raspberry walnut vinaigrette","410g Greek yoghurt","2 teaspoons fresh mint, chopped","Shredded coconut, optional"}', '{"Place strawberries and blueberries in separate bowls. Drizzle each with vinaigrette and toss to coat.","In a small bowl, mix yoghurt and mint.","Spoon fruit into 4 parfait glasses, alternating with yoghurt and mint. If desired, top with coconut and fresh chopped mint."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 4, NULL, '{vegetarian}', NULL, 15);
INSERT INTO public.recipes VALUES (93, 'Prawn Linguine', 'Classic garlic prawns tossed with linguine in a light lemon butter sauce.', 1608, 132, 180, 40, '/uploads/recipes/prawn-linguine.jpg', '{"220 grams linguine pasta","2 tablespoons unsalted butter","450 grams prawns, peeled and deveined","3 garlic cloves, crushed","½ teaspoon crushed red pepper","50 millilitres white wine","1 lemon, juiced and zested","A pinch of salt and black pepper","A handful parsley, chopped","A handful Parmesan cheese, grated"}', '{"Cook the linguine in salted boiling water until al dente.","Meanwhile, melt the butter in a large pan over medium heat. Add the prawns, garlic and crushed red pepper. Cook for 3 minutes until the prawns turn pink.","Add the white wine and lemon juice, then simmer for a further 2 minutes.","Drain the pasta and toss with the prawn sauce. Add lemon zest, seasoning and parsley.","Serve immediately topped with grated Parmesan."}', '{}', 'main', '2026-01-27 06:41:10.138129', NULL, 4, NULL, '{high-protein,gluten-free}', '{Seafood}', 25);
INSERT INTO public.recipes VALUES (123, 'Chicken and Sweetcorn Soup', 'Hearty Chinese-style chicken soup with egg strands and creamed corn.', 1484, 220, 88, 28, '/uploads/recipes/chicken-and-sweetcorn-soup.jpg', '{"1kg chicken","2 carrots, chopped","2 sticks celery, chopped","3 brown onions","1 tsp peppercorns","10g lemon thyme","2 tsp sesame oil","1 tbsp soy sauce","1 chicken stock cube","1 x (400g) tin creamed corn","2 tbsp corn flour","2 tbsp soy sauce","2 egg whites"}', '{"Place chicken, vegetables, thyme and peppercorns in a large pot. Cover with water and bring to the boil.","Simmer for 45 minutes until chicken is cooked. Remove chicken and shred meat.","Heat sesame oil with vegetables, add stock cube and creamed corn, bring to boil.","Mix corn flour and soy sauce in a bowl and stir into soup. Simmer 2 minutes.","Beat egg whites and trickle into soup to create egg strands.","Return shredded chicken to pot and remove from heat. Serve."}', '{}', 'main', '2026-01-27 07:13:27.444112', NULL, 4, NULL, '{high-protein}', '{Chicken}', 80);
INSERT INTO public.recipes VALUES (192, 'Savoury Breakfast Lentils', 'Warm lentils with cherry tomatoes and lemon', 222, 14, 28, 6, '/uploads/recipes/savoury-breakfast-lentils.png', '{"150g cooked lentils","1 tsp olive oil","Cherry tomatoes","Lemon juice"}', '{"Warm lentils in pan with oil","Add tomatoes and lemon","Season and serve"}', '{Vegan,"High protein",Gluten-free}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free,gluten-free}', '{Vegetables}', 15);
INSERT INTO public.recipes VALUES (193, 'Coconut Yogurt Granola Bowl', 'Creamy coconut yogurt with granola and kiwi', 258, 7, 26, 14, '/uploads/recipes/coconut-yogurt-granola-bowl.png', '{"150g coconut yogurt","30g granola","1 kiwi sliced",Seeds}', '{"Add yogurt to bowl","Top with granola and fruit"}', '{Vegan,Dairy-free}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (194, 'Toasted Hummus Breakfast Sandwich', 'Savoury toast with hummus, tomato and rocket', 270, 11, 34, 10, '/uploads/recipes/toasted-hummus-sandwich.png', '{"2 slices wholegrain bread","2 tbsp hummus","Tomato slices",Rocket}', '{"Toast bread","Spread hummus and add fillings","Serve warm"}', '{Vegan}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Vegetables,Grains}', 10);
INSERT INTO public.recipes VALUES (25, 'Cream Cheese and Strawberries on Sourdough', 'Sweet protein-packed toast with cream cheese and fresh strawberries', 326, 26, 42, 6, '/uploads/recipes/cream-cheese-strawberries-sourdough.png', '{"80g non-fat cream cheese","1 medium slice (50g) sourdough","100g strawberries","70g honey","15g whey protein"}', '{"Toast your sourdough until golden.","Meanwhile, slice strawberries and add the lightest cream cheese to a bowl with the protein powder. Beat together very well and spread onto toast.","Layer over the strawberries evenly and finish with a drizzle of honey."}', NULL, 'breakfast', '2026-01-26 11:01:35.793708', NULL, 1, NULL, '{vegetarian}', NULL, 6);
INSERT INTO public.recipes VALUES (26, 'Apple and Walnut Flapjack', 'Hearty gluten-free flapjacks with apple and walnuts', 270, 10, 26, 14, '/uploads/recipes/apple-walnut-flapjack.png', '{"225g gluten free rolled oats","40g desiccated coconut","60g vanilla protein powder","1 tsp ground cinnamon","60g walnuts, roughly chopped","40g peanut butter","60g maple syrup","2 medium apples","320g apple sauce"}', '{"Pre heat the oven to 180C/350F/Gas Mark 4.","Line a 9\" square baking tin or deep tray with baking paper.","In a large bowl combine oats, desiccated coconut, protein powder, walnuts, cinnamon and baking powder.","In a saucepan add peanut butter, maple syrup and coconut oil and melt on low heat. Remove from the heat, add grated apple and apple sauce.","Add the wet mixture to the dry ingredients, combine thoroughly and add to the lined baking tin.","Use a slightly wet spatula to press the mixture into the tray until evenly spread.","Bake for 20 minutes until the edges start to darken and the centre is a golden brown.","Remove from the oven and allow to cool completely before slicing."}', NULL, 'breakfast', '2026-01-26 11:01:35.793708', NULL, 10, NULL, '{vegetarian}', NULL, 35);
INSERT INTO public.recipes VALUES (35, 'Greek Yoghurt with Banana, Granola, Coconut and Raisins', 'Layered yogurt bowl with banana, crunchy granola and tropical toppings', 426, 28, 47, 14, '/uploads/recipes/greek-yoghurt-banana-granola-coconut-raisins.png', '{"225g low fat Greek yoghurt","30g granola","80g banana fresh","10g coconut","8g raisins"}', '{"Collect your ingredients and a bowl to layer up your meal.","Add the yoghurt first, then slice your banana lengthways and add into the yoghurt. Add your granola, chunks of coconut and finally your granola and raisins.","Eat immediately."}', NULL, 'breakfast', '2026-01-26 11:06:22.743455', NULL, 1, NULL, '{vegetarian}', NULL, 6);
INSERT INTO public.recipes VALUES (64, 'Breakfast Salad', 'A hearty salad with vegetarian sausages, kale, cherry tomatoes, and a tangy Dijon dressing.', 368, 13, 20, 25, '/uploads/recipes/breakfast-salad.png', '{"4 vegetarian sausages","1 bunch kale","100g cherry tomatoes","30g cheddar cheese","2 tbsp olive oil","1 tsp apple cider vinegar","1 tsp lemon juice","1 tbsp Dijon mustard","Salt & cracked pepper"}', '{"Preheat oven to 200°C/180°C fan. Line baking tray with baking paper.","Place the sausages on the tray and cook for 16 minutes.","Toss the kale and tomatoes together in a medium sized bowl.","Add all the dressing ingredients to a small bowl and whisk to combine. Pour dressing over the kale and tomatoes.","Divide salad between 2 plates and serve with sausages."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 2, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (17, 'Banana Bread', 'Classic banana bread with walnuts and oats, perfect for meal prep', 264, 8, 40, 8, '/uploads/recipes/banana-bread.png', '{"3 medium bananas, well ripened","125g plain white flour","125g spelt flour","95g ground oats","500ml soya milk","50g walnuts, roughly chopped","1 tsp baking soda","1/2 tsp cinnamon"}', '{"Pre heat oven to 200C/400F/Gas Mark 6.","Mash the banana with a fork and mix it with all of the ingredients plus a big pinch of sea salt in a large mixing bowl, except for the walnuts.","Line a 9\" bread tin with baking parchment and then pour in the batter, add the walnuts on top and bake for 35 to 40 minutes.","Allow to fully cool and using the parchment, pull from the loaf tin using the edges of the parchment and slice."}', NULL, 'breakfast', '2026-01-26 09:45:26.857146', NULL, 8, NULL, '{vegetarian}', NULL, 50);
INSERT INTO public.recipes VALUES (19, 'Overnight Bran', 'Simple high-fiber overnight breakfast with Greek yogurt and raspberries', 246, 16, 41, 2, '/uploads/recipes/overnight-bran.png', '{"40g bran flake cereal","150g 0% fat greek style yoghurt","80g frozen raspberries","1 tsp stevia or powdered sweetener"}', '{"Combine all ingredients in a bowl or jar and mix thoroughly.","Leave to set in the fridge overnight."}', NULL, 'breakfast', '2026-01-26 09:45:26.857146', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (20, 'Cinnamon Apple Breakfast Bowl', 'Protein-rich cottage cheese bowl with fresh apple and maple syrup', 444, 31, 26, 24, '/uploads/recipes/cinnamon-apple-breakfast-bowl.png', '{"250g cottage cheese","35g apple, diced","30g chopped walnuts","1 tbsp maple syrup","1 pinch cinnamon"}', '{"Add all ingredients to a bowl or container.","Enjoy immediately or refrigerate in an airtight container for up to four days."}', NULL, 'breakfast', '2026-01-26 09:45:47.067631', NULL, 1, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (22, 'Cherry Chocolate Overnight Oats', 'Indulgent chocolate overnight oats with dark cherries', 463, 35, 56, 11, '/uploads/recipes/cherry-chocolate-overnight-oats.png', '{"65g rolled oats","1 tbsp cocoa powder","125ml unsweetened almond milk","65g frozen dark cherries","30g chocolate whey protein"}', '{"Add all ingredients into a serving bowl and mix until very well combined.","Cover and place in the fridge overnight, by which point the oats will have absorbed the liquid and defrosted the cherries.","When ready to serve add extra almond milk if needed."}', NULL, 'breakfast', '2026-01-26 09:45:47.067631', NULL, 1, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (126, 'Parmesan Crusted Chicken', 'Crispy Parmesan and thyme crusted chicken breasts baked to perfection.', 1928, 240, 152, 40, '/uploads/recipes/parmesan-crusted-chicken.jpg', '{"4 slices rye bread","60g parmesan cheese","1 tsp dried thyme","1/2 lemon, juiced and zested","Salt and cracked pepper","4 small chicken breasts"}', '{"Preheat oven to 200°C and line tray with baking paper.","Blitz bread into crumbs using food processor.","Mix breadcrumbs, parmesan, thyme, lemon zest, salt and pepper.","Dip chicken into lemon juice then coat in crumb mixture.","Bake for 20 minutes or until cooked through. Serve immediately."}', '{"High protein"}', 'main', '2026-01-27 07:13:59.301718', NULL, 4, NULL, '{high-protein}', '{Chicken}', 45);
INSERT INTO public.recipes VALUES (202, 'Frozen Berry Chocolate Bark', 'Dark chocolate bark topped with berries and seeds', 149, 3, 14, 9, '/uploads/recipes/frozen-berry-chocolate-bark.png', '{"100g dark vegan chocolate","Mixed berries",Seeds}', '{"Melt chocolate and spread thin","Top with berries and seeds","Freeze and break into pieces"}', '{Vegan,Gluten-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 6, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 10);
INSERT INTO public.recipes VALUES (203, 'Peanut Butter Stuffed Dates', 'Sweet dates filled with creamy peanut butter', 108, 3, 15, 4, '/uploads/recipes/peanut-butter-stuffed-dates.png', '{"6 dates","2 tbsp peanut butter"}', '{"Slice dates open","Fill with peanut butter","Chill if desired"}', '{Vegan,Gluten-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 6, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (204, 'Baked Oat Chocolate Cups', 'Mini baked oat cups with chocolate', 116, 4, 16, 4, '/uploads/recipes/baked-oat-chocolate-cups.png', '{"80g oats","1 tbsp cocoa powder","2 tbsp maple syrup","2 tbsp soy milk"}', '{"Mix ingredients into paste","Press into muffin tray","Bake at 180C for 15 minutes"}', '{Vegan}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 6, NULL, '{vegan,dairy-free}', '{Grains}', 25);
INSERT INTO public.recipes VALUES (30, 'No Bake Carrot Cake Flapjacks', 'Healthy no-bake flapjacks with carrot and warming spices', 308, 11, 30, 16, '/uploads/recipes/no-bake-carrot-cake-flapjacks.png', '{"80g oats","35g honey","20g coconut oil","72g carrot, grated","2 tbsp pumpkin seeds","30g desiccated coconut","2 tbsp raisins","30g vanilla protein","3 tbsp almond milk","1/2 tsp cinnamon","1/2 tsp vanilla essence"}', '{"Line a tupperware bowl with greaseproof paper and melt the coconut oil in a small pan.","Add all of the dry ingredients to a bowl and mix very well, pour in the coconut oil.","Add the honey and carrot then stir and mix very well until all of the oats and carrot are fully coated and combined.","Press the mixture into the tupperware and smooth out evenly on the top.","Freeze for 30 minutes to firm it up quickly then cut into five bars and store in the fridge."}', NULL, 'breakfast', '2026-01-26 11:01:56.569942', NULL, 5, NULL, '{vegetarian}', NULL, 40);
INSERT INTO public.recipes VALUES (32, 'Date and Banana Oats and Whey', 'Warming oatmeal with dates, banana and protein', 481, 35, 56, 13, '/uploads/recipes/date-banana-oats-whey.png', '{"100g oats","50g banana, mashed","38g dates, diced","300g almond milk","1/2 tsp honey","1/4 tsp cinnamon","40g ground almonds","40g whey protein"}', '{"Add all of the ingredients to a large saucepan over a medium heat and bring to a low boil.","Stir frequently for 5 minutes cooking until desired thick consistency.","Divide between two and eat warm."}', NULL, 'breakfast', '2026-01-26 11:01:56.569942', NULL, 2, NULL, '{vegetarian}', NULL, 8);
INSERT INTO public.recipes VALUES (41, 'Mango & Coconut Rice Pudding', 'Creamy coconut rice pudding topped with fresh mango', 335, 4, 37, 19, '/uploads/recipes/mango-coconut-rice-pudding.png', '{"100g basmati rice","1/2 teaspoon vanilla extract","1 tablespoon coconut flakes, toasted","1 mango","250ml coconut milk"}', '{"Place the dairy free coconut milk, rice and vanilla extract in a heavy based saucepan and cook gently for 25 to 30 minutes, stirring frequently until the rice has cooked and the pudding is thick.","Divide into serving bowls and top with chopped mango and toasted coconut."}', NULL, 'breakfast', '2026-01-26 11:06:36.201073', NULL, 4, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (43, 'Orange, Almond & Quinoa Porridge', 'Protein-rich quinoa porridge with orange and toasted almonds', 540, 11, 61, 28, '/uploads/recipes/orange-almond-quinoa-porridge.png', '{"100g quinoa","200ml almond milk","1 teaspoon vanilla extract","1 tablespoon maple syrup, plus extra to serve","1 orange, peeled and pith removed, cut into rounds","1 tablespoon toasted flaked almonds"}', '{"Put the quinoa, almond milk, vanilla extract and 100ml water in a small saucepan. Bring to the boil, then reduce to a simmer. Add the remaining milk and continue to cook gently for 20 minutes until the quinoa is tender.","Divide the porridge between bowls and drizzle with maple syrup if desired.","Scatter over orange segments and toasted almonds."}', NULL, 'breakfast', '2026-01-26 11:06:36.201073', NULL, 2, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (79, 'Almond Butter Pancakes', 'Fluffy wholemeal pancakes with creamy almond butter - hearty and satisfying.', 375, 11, 31, 23, '/uploads/recipes/almond-butter-pancakes.png', '{"150g wholemeal flour","1 tsp baking powder","Pinch of sea salt","300ml almond milk","100g almond butter","1 tbsp honey","2 tbsp coconut oil"}', '{"Start by mixing together the flour, baking powder and salt.","Whisk together the almond milk, almond butter and honey. Pour the wet mixture into the dry mixture and whisk to combine.","Heat coconut oil in frying pan over medium heat.","Pour the mixture into the frying pan and cook for about four minutes or until you see bubbles appearing. Flip and cook for another minute on the other side.","Keep cooked pancakes warm while you prepare the rest.","Serve with a little maple syrup, optional."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 3, NULL, '{vegetarian}', NULL, 20);
INSERT INTO public.recipes VALUES (80, 'Avocado and Pineapple Smoothie', 'A creamy tropical smoothie with avocado, spinach, pineapple, and refreshing coconut water.', 227, 4, 28, 11, '/uploads/recipes/avocado-pineapple-smoothie.png', '{"1/2 avocado, peeled","Handful spinach","50g frozen pineapple, chopped","50g pineapple chunks","300ml coconut water","15 to 20 ice cubes"}', '{"Place all ingredients in the blender and blitz until smooth. Pour into a tall glass."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 1, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (81, 'Granola', 'Homemade crunchy granola with oats, almonds, cashews, and pumpkin seeds in maple and peanut butter.', 227, 6, 17, 15, '/uploads/recipes/granola.png', '{"360g old fashioned oats (gluten free if required)","60g almonds, sliced","50g pumpkin seeds","120g cashews, sliced","2 tbsp cinnamon","1 tsp salt","125ml coconut oil","125ml maple syrup","60ml peanut butter"}', '{"Start by preheating oven to 180°C. Line a baking tray with baking paper.","In a large bowl, mix together the oats, almonds, cashews, pumpkin seeds, cinnamon and salt.","In a small saucepan, slowly melt the coconut oil, maple syrup and peanut butter. Pour over the granola mix and stir to combine.","Spread evenly across the tray and cook for 20 to 25 minutes or until golden.","Serve with Greek yoghurt, optional."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 2, NULL, '{vegetarian}', NULL, 45);
INSERT INTO public.recipes VALUES (82, 'Choc Banana Oats', 'Warm chocolate protein oats with peanut butter and fresh banana slices.', 390, 24, 42, 14, '/uploads/recipes/choc-banana-oats.png', '{"90g old fashioned oats (gluten free if required)","250ml almond milk","1 scoop vegan chocolate protein powder","2 tbsp peanut butter","1 banana, sliced"}', '{"Add the oats and almond milk to a small saucepan and bring to boil. Reduce to a simmer and stir frequently.","Add the protein powder, peanut butter and 3/4 of the banana, continuing to stir.","Once the milk has absorbed (about five minutes), transfer to a serving bowl.","Top with extra sliced banana."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 2, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (83, 'Mediterranean Toast', 'Toasted rye bread topped with hummus, fresh tomatoes, red onion, and black olives.', 331, 10, 48, 11, '/uploads/recipes/mediterranean-toast.png', '{"4 slices rye bread (gluten free if required)","2 tbsp hummus","2 tomatoes, diced","1/4 red onion, diced","40g black olives, sliced"}', '{"Toast your bread and spread each slice with hummus.","Top with tomatoes, onion, olives and salt & cracked pepper."}', NULL, 'breakfast', '2026-01-26 14:28:58.549168', NULL, 2, NULL, '{vegetarian}', NULL, 15);
INSERT INTO public.recipes VALUES (135, 'Slow Cooker Pulled Pork', 'Tender slow-cooked pork shoulder in cider with honey and herbs.', 1908, 126, 174, 78, '/uploads/recipes/slow-cooker-pulled-pork.jpg', '{"2 tsp olive oil","450g pork shoulder","150ml cider","1 onion, chopped","125ml apple cider vinegar","125ml chicken stock","1 tbsp honey","1 tsp garlic powder","1 tsp chilli powder","1 tsp dried thyme","Salt & cracked pepper"}', '{"Place the olive oil in the slow cooker and add the pork.","Add all remaining ingredients and mix gently.","Cook on high for 6 hours.","Shred the pork using two forks before serving."}', '{}', 'main', '2026-01-27 08:28:47.662929', NULL, 6, NULL, '{high-protein}', '{Pork}', 390);
INSERT INTO public.recipes VALUES (18, 'Chickpea Protein Breakfast Bars', 'High-protein grab-and-go breakfast bars with chickpeas and oats', 189, 6, 21, 9, '/uploads/recipes/chickpea-protein-breakfast-bars.png', '{"200g oats","125g almonds, roughly chopped","75g raisins, chopped","75g dried apricots, chopped","3 tbsp ground flaxseed","125g almond milk","400g can of chickpeas, rinsed and drained","120g peanut butter","110g dates, pitted","60g honey","1 tsp ground cinnamon"}', '{"Line a 9 x 13 inch baking pan with foil or parchment paper and rub a small amount of olive oil onto the paper to cover.","Pre heat the oven to 180C/350F/Gas Mark 4.","Spread the oats and the nuts on a large baking sheet. Bake in the pre heated oven for 6 to 8 minutes, shaking halfway through, until golden and fragrant; transfer to the bowl of a food processor and allow to cool.","Pulse the oats and nuts until coarsely chopped; transfer to a large bowl and add the dried fruit.","Meanwhile, combine the flaxseed meal and warm milk in a small bowl and stand for 5 minutes. Place the chickpeas, peanut butter, dates, honey, cinnamon, a pinch of salt and flaxseed mix in the food processor; process until the mixture is smooth.","Add the chickpea mixture to the oats mixture, mix until coated and transfer to the prepared pan. Spread and flatten the mixture evenly in the pan.","Bake for 15-18 minutes or until the edges are golden brown and the top appears slightly dried. Transfer to a wire rack and cool completely.","Using the liner, lift the mixture from the pan and transfer to a cutting board. Cut into 20 bars."}', NULL, 'breakfast', '2026-01-26 09:45:26.857146', NULL, 20, NULL, '{vegan,dairy-free,high-protein}', NULL, 40);
INSERT INTO public.recipes VALUES (28, 'Coffee and Cream Smoothie', 'Creamy coffee smoothie packed with protein', 378, 37, 26, 14, '/uploads/recipes/coffee-cream-smoothie.png', '{"125g ice","125g brewed and cooled coffee","150g almond milk","10g vanilla whey protein","200g 0% strained greek yoghurt","20g double cream","20g banana (frozen)","1/2 tsp vanilla extract"}', '{"Add all ingredients to a blender and blend until smooth. If it''s too thick, add more almond milk to a consistency you prefer."}', NULL, 'breakfast', '2026-01-26 11:01:35.793708', NULL, 1, NULL, '{vegetarian,gluten-free}', NULL, 10);
INSERT INTO public.recipes VALUES (150, 'BBQ Lamb', 'Simple grilled lamb steaks with rosemary and balsamic, served with broccolini.', 392, 66, 6, 12, '/uploads/recipes/bbq-lamb.jpg', '{"2 lamb steaks","2 sprigs rosemary","1 tbsp balsamic vinegar","1 bunch broccolini"}', '{"Marinate lamb 10 minutes.","Grill lamb 4 to 5 minutes each side.","Serve with steamed broccoli."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 08:30:05.468959', NULL, 2, NULL, '{high-protein}', NULL, 50);
INSERT INTO public.recipes VALUES (148, 'Rich Tomato and Tuna Pasta', 'Hearty pasta with tuna, aubergine and fresh tomatoes.', 1960, 92, 344, 28, '/uploads/recipes/rich-tomato-and-tuna-pasta.jpg', '{"1 tbsp olive oil","1 onion, diced","100g aubergine, sliced","150g red chilli, sliced","750g ripe tomatoes","125g tinned tuna, drained","400g chopped basil","400g penne pasta"}', '{"Heat oil and cook onion and aubergine 10 minutes.","Add tomatoes and cook 15 minutes.","Stir through tuna and basil.","Mix through cooked pasta and serve."}', '{}', 'main', '2026-01-27 08:29:42.814641', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 35);
INSERT INTO public.recipes VALUES (152, 'Tuna and Quinoa Sushi', 'Healthy sushi rolls with quinoa, tuna and avocado.', 826, 54, 68, 38, '/uploads/recipes/tuna-and-quinoa-sushi.jpg', '{"90g quinoa","4 nori sheets","1 avocado","1/2 cucumber","1 x 125g tuna","2 tsp sesame seeds"}', '{"Cook quinoa and cool.","Assemble rolls with fillings.","Slice and serve."}', '{}', 'main', '2026-01-27 08:30:05.468959', NULL, 2, NULL, '{high-protein,gluten-free}', '{Fish}', 40);
INSERT INTO public.recipes VALUES (151, 'Barley and Mushroom Soup', 'Hearty soup with pearl barley and earthy mushrooms.', 1172, 36, 180, 36, '/uploads/recipes/barley-and-mushroom-soup.jpg', '{"2 tbsp olive oil","1 brown onion","1 carrot, diced","1 celery stalk","2 cloves garlic","400g mushrooms","200g pearl barley","900ml vegetable stock"}', '{"Cook vegetables in oil for 10 minutes.","Add stock and barley.","Simmer 60 minutes.","Serve hot."}', '{Vegan}', 'main', '2026-01-27 08:30:05.468959', NULL, 4, NULL, '{vegetarian}', NULL, 85);
INSERT INTO public.recipes VALUES (185, 'Protein Peanut Overnight Oats', 'High protein overnight oats with peanut butter and banana', 382, 16, 48, 14, '/uploads/recipes/protein-peanut-overnight-oats.png', '{"60g oats","200ml unsweetened soy milk","1 tbsp peanut butter","1 tbsp chia seeds","1 small banana sliced"}', '{"Combine all ingredients in a jar","Stir well and refrigerate overnight","Eat cold or warm gently before serving"}', '{Vegan,"High protein"}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Grains}', 5);
INSERT INTO public.recipes VALUES (186, 'Tofu Scramble with Spinach', 'Savoury tofu scramble with spinach and nutritional yeast', 234, 21, 6, 14, '/uploads/recipes/tofu-scramble-spinach.png', '{"150g firm tofu","1 tsp olive oil","1 handful spinach","1 tbsp nutritional yeast","Turmeric, salt, pepper"}', '{"Crumble tofu into pan with olive oil","Add seasoning and cook for 5 minutes","Stir in spinach and nutritional yeast","Cook until wilted"}', '{Vegan,"High protein",Low-carb}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu,Vegetables}', 15);
INSERT INTO public.recipes VALUES (187, 'High Protein Chia Pudding', 'Creamy chia pudding topped with fresh berries', 240, 13, 20, 12, '/uploads/recipes/high-protein-chia-pudding.png', '{"3 tbsp chia seeds","200ml soy milk","100g berries","1 tsp maple syrup"}', '{"Stir chia and soy milk","Refrigerate until thick","Top with berries and maple syrup"}', '{Vegan,"High protein",Gluten-free}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (188, 'Avocado Chickpea Toast', 'Protein-packed avocado and chickpea toast on sourdough', 290, 9, 32, 14, '/uploads/recipes/avocado-chickpea-toast.png', '{"1 slice sourdough","1/2 avocado","3 tbsp mashed chickpeas","Lemon juice, salt"}', '{"Toast bread","Mash avocado and chickpeas together","Spread on toast and season"}', '{Vegan}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Vegetables,Grains}', 10);
INSERT INTO public.recipes VALUES (117, 'Chicken Hot Dogs', 'Grilled chicken sausages in brown buns with avocado, pickles and honey mustard.', 1400, 72, 224, 24, '/uploads/recipes/chicken-hot-dogs.jpg', '{"3 tbsp yellow mustard","1/2 tbsp honey","1/2 red onion, diced","4 chicken sausages","4 brown buns","1 avocado, thinly sliced","4 dill pickles","Small romaine lettuce heart, sliced"}', '{"Mix mustard, honey and onion. Set aside.","Cook sausages until browned.","Assemble buns with sausage, lettuce, avocado and pickles.","Drizzle over sauce and serve."}', '{}', 'main', '2026-01-27 07:12:52.433764', NULL, 4, NULL, '{high-protein}', '{Chicken}', 30);
INSERT INTO public.recipes VALUES (149, 'Healthy Hamburgers', 'Lean beef patties with hidden vegetables served in burger buns.', 2112, 90, 150, 126, '/uploads/recipes/healthy-hamburgers.jpg', '{"350g lean mince","1 large carrot, grated","2 courgettes, grated","150g breadcrumbs","2 eggs","2 garlic cloves","1 tsp mustard","1 tsp Worcestershire sauce","Salt and pepper","6 burger buns","Lettuce, tomato, mayonnaise"}', '{"Mix ingredients and shape into patties.","Refrigerate for 60 minutes.","Cook burgers 5 to 6 minutes each side.","Serve in buns with fillings."}', '{}', 'main', '2026-01-27 08:30:05.468959', NULL, 6, NULL, '{high-protein}', '{Beef,Pork}', 100);
INSERT INTO public.recipes VALUES (160, 'Green Stir Fry', 'Quick vegetable stir fry with bok choy, mangetout and cashews over rice.', 784, 28, 98, 32, '/uploads/recipes/green-stir-fry.jpg', '{"100g brown rice (uncooked)","1 tbsp coconut oil","2 tsp fresh ginger, minced","2 cloves garlic, minced","1 tsp chilli flakes","200g mangetout","100g green beans, sliced","100g bok choy, sliced","4 tbsp cashew nuts, chopped"}', '{"Cook rice according to packet instructions.","Heat oil in a wok. Add ginger, garlic and chilli flakes and cook 1 minute.","Add mangetout and beans and cook 2 to 3 minutes.","Add bok choy and cook a further 1 to 2 minutes.","Serve vegetables over rice and sprinkle with cashews."}', '{Vegan}', 'main', '2026-01-27 08:31:06.784205', NULL, 2, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (189, 'Berry Protein Smoothie', 'Quick protein-packed berry smoothie with flaxseed', 231, 24, 18, 7, '/uploads/recipes/berry-protein-smoothie.png', '{"200ml soy milk","1 scoop vegan protein powder","100g frozen berries","1 tbsp ground flaxseed"}', '{"Blend all ingredients until smooth","Serve immediately"}', '{Vegan,"High protein",Gluten-free}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (190, 'Peanut Banana Breakfast Wrap', 'Simple wrap with peanut butter and banana', 316, 10, 42, 12, '/uploads/recipes/peanut-banana-wrap.png', '{"1 wholemeal wrap","1 tbsp peanut butter","1 banana",Cinnamon}', '{"Spread peanut butter on wrap","Add banana and cinnamon","Roll and slice"}', '{Vegan}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Fruit,Grains}', 10);
INSERT INTO public.recipes VALUES (191, 'Warm Apple Cinnamon Oats', 'Comforting porridge with apple and cinnamon', 275, 8, 45, 7, '/uploads/recipes/warm-apple-cinnamon-oats.png', '{"60g oats","200ml oat milk","1/2 apple diced",Cinnamon}', '{"Simmer oats and milk","Stir in apple and cinnamon","Cook until soft"}', '{Vegan,Dairy-free}', 'breakfast', '2026-01-27 21:17:26.747715', 'Easy', 1, NULL, '{vegan,dairy-free}', '{Fruit,Grains}', 10);
INSERT INTO public.recipes VALUES (195, 'Dark Chocolate Chickpea Brownies', 'Fudgy vegan brownies made with chickpeas', 141, 6, 18, 5, '/uploads/recipes/dark-chocolate-chickpea-brownies.png', '{"1 tin chickpeas","3 tbsp cocoa powder","3 tbsp maple syrup","2 tbsp peanut butter","1 tsp baking powder"}', '{"Blend all ingredients","Bake at 180C for 25 minutes","Cool before slicing"}', '{Vegan,Gluten-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 8, NULL, '{vegan,dairy-free}', '{Vegetables}', 35);
INSERT INTO public.recipes VALUES (127, 'Pumpkin Mac and Cheese', 'Creamy vegan mac and cheese with roasted pumpkin, sage and nutritional yeast.', 1992, 68, 304, 56, '/uploads/recipes/pumpkin-mac-and-cheese.jpg', '{"1kg pumpkin","2 tbsp olive oil","250g penne pasta, uncooked","1/2 tsp nutmeg","20g fresh sage, finely chopped","2 tbsp arrowroot flour","200ml almond milk","4 tbsp nutritional yeast","4 tbsp vegan parmesan cheese"}', '{"Preheat oven to 200°C. Toss pumpkin in olive oil and bake 40 to 45 minutes.","Cook pasta according to packet instructions.","Heat remaining oil in pan, add onion and cook 5 minutes.","Stir in arrowroot flour, cook 1 minute then whisk in almond milk, nutmeg and yeast.","Add roasted pumpkin to sauce and stir through.","Mix sauce with cooked pasta and divide between bowls. Top with sage and seasoning."}', '{Vegan}', 'main', '2026-01-27 07:13:59.301718', NULL, 4, NULL, '{vegetarian}', NULL, 65);
INSERT INTO public.recipes VALUES (128, 'Easy Pilaf', 'Fragrant basmati rice pilaf with courgette, raisins and toasted pistachios.', 1956, 52, 320, 52, '/uploads/recipes/easy-pilaf.jpg', '{"1 tbsp olive oil","1 brown onion, diced","200g basmati rice","3 tbsp dried parsley","1 cinnamon stick","1/2 tsp onion powder","650ml vegetable stock","1 courgette","60g raisins","60g pistachios"}', '{"Heat olive oil in pan. Add onion and cook 5 minutes until translucent.","Add rice, courgette, parsley, cinnamon and onion powder. Cook 3 minutes.","Add stock and raisins, stir and cover with lid.","Cook on low heat for 25 minutes until rice is cooked.","Divide between bowls and top with pistachios."}', '{Vegan}', 'main', '2026-01-27 07:13:59.301718', NULL, 4, NULL, '{vegetarian}', NULL, 35);
INSERT INTO public.recipes VALUES (196, 'Vegan Banana Nice Cream', 'Creamy frozen banana ice cream with peanut butter', 206, 6, 32, 6, '/uploads/recipes/vegan-banana-nice-cream.png', '{"3 frozen bananas","1 tbsp peanut butter","Splash of soy milk"}', '{"Blend everything until creamy","Serve immediately"}', '{Vegan,Gluten-free,Dairy-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (197, 'Coconut Chia Pudding Pots', 'Tropical chia pudding with coconut and mango', 239, 6, 20, 15, '/uploads/recipes/coconut-chia-pudding-pots.png', '{"3 tbsp chia seeds","200ml coconut milk","Mango chunks"}', '{"Stir chia and coconut milk","Chill until set","Top with mango"}', '{Vegan,Gluten-free,Dairy-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (198, 'Baked Cinnamon Apples', 'Simple baked apples with cinnamon and maple', 92, 1, 22, 0, '/uploads/recipes/baked-cinnamon-apples.png', '{"2 apples sliced",Cinnamon,"1 tsp maple syrup"}', '{"Bake apples at 190C for 15 minutes","Sprinkle with cinnamon"}', '{Vegan,Gluten-free,Low-carb}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 20);
INSERT INTO public.recipes VALUES (91, 'BBQ Chicken Tortilla Pizza', 'Quick and easy tortilla-based pizza with BBQ chicken, mozzarella and Parmesan cheese.', 996, 72, 78, 44, '/uploads/recipes/bbq-chicken-tortilla-pizza.jpg', '{"2 flour tortillas","1 white onion, diced","85 grams cooked chicken, shredded","10 millilitres barbecue sauce","1 teaspoon balsamic vinegar","50 grams cherry tomatoes, sliced","100 grams mozzarella cheese, grated","50 grams Parmesan cheese, grated"}', '{"Begin by preheating your grill to a medium heat.","Place the tortillas under the grill for around 1 minute, or until lightly toasted all over. Remove from the grill and set aside.","To soften the onion, gently sauté in a pan for 5 minutes or cook in a microwave for 2 minutes.","In a bowl, combine the shredded chicken with the barbecue sauce and balsamic vinegar.","Spread the tortillas with barbecue sauce and scatter over the chicken, onions and tomatoes. Top with the mozzarella and Parmesan.","Place under the grill again until the cheese has melted and is beginning to brown, then remove and serve."}', '{}', 'main', '2026-01-27 06:41:10.138129', NULL, 2, NULL, '{high-protein}', '{Chicken}', 16);
INSERT INTO public.recipes VALUES (158, 'Hokkien Noodles with Beef', 'Spicy stir-fried Hokkien noodles with beef and vegetables.', 1528, 112, 124, 68, '/uploads/recipes/hokkien-noodles-with-beef.jpg', '{"450g Hokkien noodles","2 tbsp peanut oil","250g beef strips","3 cloves garlic, minced","1 long red chilli, deseeded and sliced","1 tbsp red curry paste","1 courgette, cut into matchsticks","1 red bell pepper, cut into matchsticks","1 tbsp fish sauce","1 tbsp lime juice","125ml water"}', '{"Cook noodles according to packet instructions. Drain and set aside.","Heat 1 tbsp oil in a hot pan and cook beef for 3 to 4 minutes. Remove and set aside.","Add remaining oil, garlic, chilli and curry paste and cook for 1 minute.","Add vegetables and cook for 3 minutes.","Add noodles, beef and water. Simmer for 2 to 3 minutes.","Stir in fish sauce and lime juice and divide between bowls."}', '{}', 'main', '2026-01-27 08:30:35.639229', NULL, 4, NULL, '{high-protein}', '{Beef}', 25);
INSERT INTO public.recipes VALUES (201, 'Vegan Lemon Yogurt Pots', 'Light and tangy lemon soy yogurt dessert', 121, 9, 10, 5, '/uploads/recipes/vegan-lemon-yogurt-pots.png', '{"200g soy yogurt","Lemon zest","1 tsp maple syrup"}', '{"Stir all ingredients","Chill and serve"}', '{Vegan,Gluten-free}', 'dessert', '2026-01-27 21:17:58.164559', 'Easy', 2, NULL, '{vegan,dairy-free,gluten-free}', '{Fruit}', 5);
INSERT INTO public.recipes VALUES (140, 'Bangkok Bolognese', 'Thai-inspired beef bolognese with red curry paste and coconut cream.', 3360, 138, 216, 216, '/uploads/recipes/bangkok-bolognese.jpg', '{"200g spaghetti","1 tbsp olive oil","1 spring onion, diced","1 tbsp red chilli, chopped","1 clove garlic, minced","1 red bell pepper, diced","400g beef mince","2 tbsp red curry paste","400ml coconut cream","15g coriander leaves"}', '{"Cook spaghetti according to packet instructions.","Sauté aromatics, then brown mince.","Add curry paste and cook for 5-7 minutes.","Stir in coconut cream and simmer for 10-15 minutes.","Combine with spaghetti and garnish with coriander."}', '{}', 'main', '2026-01-27 08:29:13.172787', NULL, 6, NULL, '{high-protein}', NULL, 40);
INSERT INTO public.recipes VALUES (162, 'Red Curry Chicken', 'Thai red curry with chicken thighs served over fresh rice noodles.', 1652, 80, 120, 96, '/uploads/recipes/red-curry-chicken.jpg', '{"300g fresh rice noodles","1 tbsp olive oil","4 chicken thighs","2 tbsp honey","1 tbsp red curry paste","1 clove garlic, minced","1 spring onion, minced","125ml chicken stock","200ml coconut milk"}', '{"Cook noodles according to packet instructions.","Cook chicken thighs in a pan until fully cooked, turning halfway.","Heat curry paste, garlic, spring onion, stock and coconut milk in a small pan. Simmer 5 minutes.","Divide noodles between bowls, top with chicken and drizzle with curry sauce."}', '{}', 'main', '2026-01-27 08:31:06.784205', NULL, 4, NULL, '{high-protein}', '{Chicken}', 30);
INSERT INTO public.recipes VALUES (143, 'Creamy Chicken', 'Spiced chicken in a creamy coconut lime sauce with potatoes.', 998, 66, 64, 54, '/uploads/recipes/creamy-chicken.jpg', '{"1 tbsp olive oil","200g chicken breast, sliced","1/4 tsp onion powder","1/4 tsp cayenne pepper","1 tbsp paprika","1/4 tsp dried thyme","1/2 tsp salt","1/2 tsp black pepper","250g potato, cubed","1 brown onion, diced","1 clove garlic, minced","1 lime, juiced","200ml coconut milk","10g fresh coriander"}', '{"Cook chicken with spices in olive oil, then remove.","Cook potatoes, onion and garlic in same pan.","Add lime juice and coconut milk, simmer 10 minutes.","Return chicken and cook another 10 minutes.","Garnish with fresh coriander before serving."}', '{}', 'main', '2026-01-27 08:29:13.172787', NULL, 2, NULL, '{high-protein}', '{Chicken}', 35);
INSERT INTO public.recipes VALUES (142, 'Pumpkin and Macadamia Salad', 'Roasted butternut pumpkin with feta, macadamias and pomegranate.', 1636, 52, 160, 84, '/uploads/recipes/pumpkin-macadamia-salad.jpg', '{"1 butternut pumpkin, diced","2 tbsp olive oil","2 tbsp maple syrup","2 tbsp cracked pepper","4 tbsp macadamia nuts, chopped","4 tbsp pomegranate seeds","3 tbsp fresh mint, chopped","200g feta, crumbled"}', '{"Roast pumpkin with oil, maple and pepper at 200°C for 30-35 minutes.","Allow to cool slightly.","Mix with remaining ingredients in a bowl.","Serve with a drizzle of olive oil."}', '{Vegetarian}', 'main', '2026-01-27 08:29:13.172787', NULL, 4, NULL, '{vegetarian}', NULL, 45);
INSERT INTO public.recipes VALUES (114, 'Teriyaki Tofu', 'Marinated baked tofu in a sweet teriyaki glaze served with steamed bok choy.', 1230, 72, 114, 54, '/uploads/recipes/teriyaki-tofu.jpg', '{"60ml tamari","2 tbsp coconut sugar","2 tbsp mirin","2 tbsp sesame oil","450g firm tofu","450g bok choy","1 tbsp sesame seeds"}', '{"Mix tamari, sugar, mirin and sesame oil.","Slice tofu and marinate for at least 60 minutes.","Bake tofu at 180°C for 20 minutes, turning halfway.","Steam bok choy for 5 to 6 minutes.","Serve tofu with bok choy and sprinkle with sesame seeds."}', '{Vegan,"High protein"}', 'main', '2026-01-27 07:12:52.433764', NULL, 3, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu}', 80);
INSERT INTO public.recipes VALUES (121, 'Thai Beef Salad', 'Grilled rump steak over a fresh vegetable salad with tamari chilli dressing.', 1496, 220, 28, 56, '/uploads/recipes/thai-beef-salad.jpg', '{"2 tsp olive oil","2 tbsp tamari","2 tsp chilli flakes","Salt and cracked pepper","500g beef rump steak","1 red bell pepper, sliced into matchsticks","1 large cucumber, sliced into matchsticks","1 large carrot, cut into matchsticks","100g rocket"}', '{"Mix olive oil, tamari, chilli flakes, salt and pepper in a bowl.","Coat steak in marinade and leave for 10 minutes.","Toss vegetables together to form salad base.","Cook steak in a hot griddle pan for 3 to 4 minutes each side.","Rest steak for 5 minutes then slice thinly.","Place steak over salad, drizzle with remaining dressing and serve."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 07:13:27.444112', NULL, 4, NULL, '{high-protein}', '{Beef}', 35);
INSERT INTO public.recipes VALUES (130, 'Chargrilled Steak', 'Juicy chargrilled rump steak with olive and cashew tapenade over fresh spinach.', 1304, 106, 30, 84, '/uploads/recipes/chargrilled-steak.jpg', '{"1/2 bunch parsley, chopped","1 clove garlic, minced","100g kalamata olives, chopped","50g cashews, chopped","1 1/2 tbsp olive oil","Salt & cracked pepper","2 x 200g beef rump steaks","100g spinach"}', '{"Add the parsley, garlic, olives and cashews to a medium-sized bowl and blitz with a stick blender until combined but still a little chunky.","Stir through 1 tbsp olive oil, season with salt & cracked pepper and set aside.","Rub the remaining 1/2 tbsp of oil into the steaks and again, season with salt & cracked pepper.","Bring the chargrill plate to medium-high heat and cook steaks for 4-5 minutes each side or until cooked to your liking.","Allow the steaks to rest for a couple of minutes, then place on a bed of spinach and drizzle tapenade all over."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 08:28:01.749239', NULL, 2, NULL, '{high-protein}', '{Beef}', 35);
INSERT INTO public.recipes VALUES (94, 'Cod Provencal', 'Baked cod with cherry tomatoes, fennel and thyme in a Mediterranean-inspired dish.', 980, 92, 36, 52, '/uploads/recipes/cod-provencal.jpg', '{"260 grams cherry tomatoes, quartered","1 garlic clove, crushed","1 teaspoon ground fennel seeds","½ teaspoon ground black pepper","2 tablespoons of extra virgin olive oil","A pinch of salt","1 fennel bulb, trimmed with leaves reserved","1 lemon, juiced","4 cod fillets, cut into 3 centimetre pieces","A handful fresh thyme","1 tablespoon of butter","4 tablespoons of aniseed liqueur"}', '{"Preheat the oven to 200°C.","In a large bowl, toss together the tomatoes, garlic, fennel seed, pepper, olive oil and salt.","Transfer the mixture to a baking dish and place the cod on top. Drizzle with lemon juice.","Scatter over the fennel leaves and thyme, then dot with butter.","Bake for 10 to 15 minutes until the fish flakes easily.","Finish with the aniseed liqueur and serve immediately."}', '{}', 'main', '2026-01-27 06:41:10.138129', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 25);
INSERT INTO public.recipes VALUES (138, 'Vietnamese Curry', 'Aromatic curry with roasted sweet potato, vegetables and peanut coconut sauce.', 2080, 32, 288, 96, '/uploads/recipes/vietnamese-curry.jpg', '{"1kg sweet potato, cubed","1 tbsp olive oil","1 stalk lemongrass, chopped","2 cloves garlic, minced","1 tsp ginger paste","1 tbsp yellow curry paste","1 brown onion, diced","3 carrots, chopped","1 head broccoli, chopped","400ml coconut milk","2 tbsp peanut butter","2 tbsp fish sauce","15g coriander leaves"}', '{"Roast sweet potatoes at 200°C for 25-30 minutes.","Cook aromatics in a pan, then add curry paste.","Add vegetables, coconut milk, peanut butter and fish sauce.","Simmer for 5 minutes, combine with sweet potatoes and garnish."}', '{}', 'main', '2026-01-27 08:28:47.662929', NULL, 4, NULL, '{high-protein}', NULL, 50);
INSERT INTO public.recipes VALUES (153, 'Seafood Paella', 'Spanish-style rice with prawns, mussels and calamari.', 1348, 104, 172, 28, '/uploads/recipes/seafood-paella.jpg', '{"600ml vegetable stock","175g brown rice","1 tbsp olive oil","1 onion, diced","1 courgette, sliced","1 red bell pepper","200g tomatoes","100g prawns","150g mussels","100g calamari","1 tsp paprika","14g fresh parsley","1 lemon, juiced"}', '{"Cook rice according to instructions.","Cook vegetables in pan.","Add seafood and cook through.","Finish with parsley and lemon."}', '{}', 'main', '2026-01-27 08:30:05.468959', NULL, 4, NULL, '{high-protein,gluten-free}', '{Seafood}', 45);
INSERT INTO public.recipes VALUES (92, 'Salmon Quinoa Bowl', 'A nutritious bowl with fluffy quinoa, salmon, avocado and a creamy feta oregano dressing.', 401, 19, 34, 21, '/uploads/recipes/salmon-quinoa-bowl.jpg', '{"45 grams uncooked quinoa","125 millilitres water","A pinch of salt and black pepper","1 tablespoon low fat natural yoghurt","½ a red tomato, sliced","2 tablespoons avocado","30 grams cooked salmon","A handful of rocket","1 tablespoon feta cheese","2 teaspoons dried oregano"}', '{"Bring the quinoa and water to the boil in a medium heat pan. Cover and cook for 10 to 15 minutes until absorbed and fluffy.","Drain the quinoa and transfer to a bowl. Once cooled slightly, stir in the avocado, tomato, salmon and rocket.","Mix the yoghurt, feta cheese and oregano in a small bowl to create a dressing.","Serve by drizzling the dressing over the quinoa and enjoy."}', '{Gluten-free}', 'main', '2026-01-27 06:41:10.138129', NULL, 1, NULL, '{high-protein,gluten-free}', '{Fish}', 20);
INSERT INTO public.recipes VALUES (159, 'White Fish Hotpot', 'Baked white fish in a spiced tomato broth with rice noodles.', 1464, 148, 152, 28, '/uploads/recipes/white-fish-hotpot.jpg', '{"1 tbsp olive oil","2 cloves garlic, minced","1 long red chilli, deseeded and diced","1 brown onion, diced","1 tsp paprika","1/2 tsp turmeric","500ml passata","500ml chicken stock","85g rice noodles","600g white fish","15g coriander, leaves picked"}', '{"Preheat oven to 220°C and use an ovenproof pot.","Heat oil and sauté garlic, chilli and onion for 2 to 3 minutes.","Add spices, passata and stock and bring to a boil.","Stir in fish and cover with lid.","Bake in oven for 15 minutes until fish is cooked and flakes easily.","Serve hot and garnish with coriander."}', '{}', 'main', '2026-01-27 08:31:06.784205', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 30);
INSERT INTO public.recipes VALUES (139, 'Sweet Chilli Fish', 'Simple baked white fish with carrots in sweet chilli sauce.', 554, 68, 62, 4, '/uploads/recipes/sweet-chilli-fish.jpg', '{"400g white fish","2 carrots, cut into strips","125ml sweet chilli sauce"}', '{"Preheat oven to 200°C.","Place fish and carrots in a baking tray.","Bake for 15-18 minutes.","Serve with rice if desired."}', '{}', 'main', '2026-01-27 08:29:13.172787', NULL, 2, NULL, '{high-protein,gluten-free}', '{Fish}', 30);
INSERT INTO public.recipes VALUES (132, 'Salmon Risotto', 'Creamy arborio risotto with smoked salmon, peas and fresh dill.', 1808, 120, 196, 60, '/uploads/recipes/salmon-risotto.jpg', '{"1 tbsp olive oil","1 brown onion, diced","2 cloves garlic, minced","200g arborio rice","500ml vegetable stock","100g peas","1/2 lemon juiced and zested","10g dill, finely chopped","250g smoked salmon"}', '{"Heat half the olive oil in a large frying pan. Add the onion and garlic and cook for 5 minutes or until onion is translucent.","Add the rice and cook, stirring continuously for 2 minutes.","Add the stock and bring to a boil. Reduce the heat and simmer, cover and cook for 10 minutes.","You may need to give it a couple of stirs to stop it from sticking.","Stir through the peas and cook for another 5 minutes or until all the water has been absorbed.","In a small bowl, whisk together the remaining olive oil, lemon juice, lemon zest, dill, salt & cracked pepper.","Remove risotto from the heat and stir through the lemon dressing.","Divide between 4 bowls and top with shreds of smoked salmon."}', '{}', 'main', '2026-01-27 08:28:01.749239', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 40);
INSERT INTO public.recipes VALUES (99, 'Cheesy Chicken Orzo', 'Creamy orzo pasta with tender chicken pieces and melted cheddar cheese.', 1704, 120, 108, 88, '/uploads/recipes/cheesy-chicken-orzo.jpg', '{"2 tablespoons olive oil","350 grams chicken breast, chopped into 2 centimetre pieces","200 grams orzo pasta","50 grams cheddar cheese, grated","2 tablespoons double cream","60 millilitres milk"}', '{"Heat the olive oil in a large frying pan. Add the chicken and cook over a medium heat for around 5 minutes until cooked through. Set aside.","Bring a large saucepan of water to the boil. Add the orzo pasta and cook until al dente. Drain and return to the pan.","Add the cream and milk to the pasta and stir until a smooth, creamy sauce forms.","Stir in the cooked chicken. Season with salt and black pepper.","Serve immediately."}', '{}', 'main', '2026-01-27 07:11:20.615291', NULL, 4, NULL, '{high-protein}', '{Chicken}', 35);
INSERT INTO public.recipes VALUES (102, 'Baked Sweet and Sour Chicken', 'Crispy baked chicken pieces in a homemade sweet and sour sauce with peppers.', 1380, 120, 108, 52, '/uploads/recipes/baked-sweet-and-sour-chicken.jpg', '{"450 grams skinless chicken breasts, cut into 2 centimetre pieces","2 tablespoons cornflour","1 tablespoon olive oil","2 tablespoons sweet chilli sauce","1 tablespoon soy sauce","1 tablespoon honey","1 tablespoon rice vinegar","1 tablespoon sesame oil","1 red pepper, chopped","1 green pepper, chopped","2 spring onions, sliced"}', '{"Preheat oven to 200°C.","Place chicken and cornflour into a sealable bag and shake to coat.","Heat olive oil in a wok or frying pan. Brown the chicken for 2 minutes.","Transfer chicken to a baking dish.","Mix sweet chilli sauce, soy sauce, honey, rice vinegar and sesame oil in a bowl.","Pour sauce over chicken and add peppers. Stir to coat evenly.","Bake for 45 minutes, stirring once, until chicken is cooked through.","Scatter spring onions over the dish before serving."}', '{}', 'main', '2026-01-27 07:11:20.615291', NULL, 4, NULL, '{high-protein}', '{Chicken}', 60);
INSERT INTO public.recipes VALUES (101, 'Quick Fish Curry', 'A speedy coconut fish curry with garam masala and fresh coriander.', 804, 120, 36, 20, '/uploads/recipes/quick-fish-curry.jpg', '{"1 tablespoon vegetable oil","1 white onion, diced","1 garlic clove, crushed","1 tablespoon garam masala","1 x 400 gram tin tomatoes","200 millilitres coconut milk","400 grams white fish fillets, skinned and cut into large pieces","A handful fresh coriander, chopped"}', '{"Gently sauté the onion and garlic in oil for around 5 minutes until softened.","Stir in the garam masala and cook for 1 minute to release the flavours.","Add the tomatoes and coconut milk and bring to a simmer.","Add the fish and cook gently for around 10 minutes until soft and flaky.","Serve immediately topped with fresh coriander."}', '{}', 'main', '2026-01-27 07:11:20.615291', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 15);
INSERT INTO public.recipes VALUES (122, 'Prawns and Scallops', 'Pan-seared prawns and scallops over radicchio and rocket with honey vinaigrette.', 1116, 196, 20, 28, '/uploads/recipes/prawns-and-scallops.jpg', '{"1 radicchio, cut into thin wedges","60g rocket","2 tbsp red wine vinegar","2 tbsp olive oil","1 tsp honey","Salt and cracked pepper","500g peeled king prawns","400g scallops"}', '{"Arrange radicchio and rocket on a serving plate.","Whisk vinegar, olive oil, honey, salt and pepper to make dressing.","Heat grill pan and cook scallops 1 to 2 minutes each side.","Cook prawns until pink and cooked through.","Place seafood over salad and drizzle with dressing."}', '{"High protein"}', 'main', '2026-01-27 07:13:27.444112', NULL, 4, NULL, '{high-protein,gluten-free}', '{Seafood}', 30);
INSERT INTO public.recipes VALUES (34, 'Tofu Scramble', 'Vegan-friendly scrambled tofu with spinach and tomatoes on toast', 223, 13, 18, 11, '/uploads/recipes/tofu-scramble.png', '{"225g tofu","20g spinach","1 medium tomatoes","2 spring onion diced","1 tbsp olive oil","2 medium slices of wholemeal bread","1/4 tsp turmeric"}', '{"Chop the tofu and place in a bowl to crumble it into small pieces.","Heat the oil in a pan over medium heat and add the tofu, spring onion, spinach, tomatoes, turmeric and a pinch of salt and pepper. Stir frequently and cook for 5 to 10 minutes.","Meanwhile, add bread to a toaster and cook to your preference, slice your tomatoes. Layer toast with tomatoes, a pinch of salt, the scramble and serve."}', '{Vegetarian}', 'breakfast', '2026-01-26 11:06:22.743455', NULL, 2, NULL, '{vegan,dairy-free}', '{Tofu}', 15);
INSERT INTO public.recipes VALUES (98, 'Mushroom Bolognese', 'A rich vegetarian bolognese using porcini and chestnut mushrooms for deep umami flavour.', 2100, 84, 360, 36, '/uploads/recipes/mushroom-bolognese.jpg', '{"30 grams dried porcini mushrooms","2 tablespoons olive oil","500 grams chestnut mushrooms, finely diced","2 white onions, diced","4 garlic cloves, crushed","2 carrots, grated","2 celery stalks, diced","A handful thyme leaves, chopped","1 teaspoon salt","2 tablespoons tomato purée","2 x 400 gram tins chopped tomatoes","A handful basil, chopped","400 grams tagliatelle"}', '{"Soak the dried porcini mushrooms in hot water and set aside.","In a large pan, heat the oil and sauté the chestnut mushrooms until reduced and caramelised.","Add the onions, garlic, carrots and celery, cooking until softened.","Stir in thyme, salt, tomato purée and chopped tomatoes. Simmer gently.","Chop the soaked porcini and add to the sauce with some of the soaking liquid for richness.","Cook the pasta separately and combine with the sauce before serving."}', '{Vegetarian}', 'main', '2026-01-27 06:41:45.44209', NULL, 6, NULL, '{vegetarian}', NULL, 76);
INSERT INTO public.recipes VALUES (147, 'Soba Noodle Slaw', 'Cold soba noodles with crunchy vegetables in a peanut ginger dressing.', 1408, 56, 156, 60, '/uploads/recipes/soba-noodle-slaw.jpg', '{"120g soba noodles (uncooked)","140g red cabbage, shredded","1 large carrot, grated","1 large cucumber, thinly sliced","100g peanut butter","3 tbsp tamari","1 tbsp honey","2 tsp lime juice","1 tbsp sesame oil","2 cloves garlic, minced","1/2 tbsp ginger, grated","10g coriander","40g red chilli, sliced"}', '{"Cook noodles and rinse under cold water.","Combine vegetables in large bowl.","Whisk sauce ingredients together.","Toss everything together and garnish."}', '{Vegan}', 'main', '2026-01-27 08:29:42.814641', NULL, 4, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (154, 'Broccoli Noodle Bowl', 'Soba noodles with tender broccoli in a sweet soy maple dressing.', 646, 36, 92, 18, '/uploads/recipes/broccoli-noodle-bowl.jpg', '{"100g soba noodles","400g broccoli, florets chopped","2 tbsp sesame seeds","12 spring onions, stems removed and leaves chopped","2 tbsp coconut oil","2 tbsp garlic, minced","2 tbsp soy sauce","2 tbsp rice wine vinegar","1 tbsp maple syrup","2 tsp lemon juice"}', '{"Cook noodles according to packet instructions. Drain and set aside.","Bring a large pot of water to the boil. Add broccoli and cook for 4 to 5 minutes until tender.","Heat coconut oil in a pan. Add garlic and cook for 1 minute.","Mix soy sauce, vinegar, maple syrup and lemon juice to form dressing.","Arrange noodles and broccoli in bowls. Top with spring onions and drizzle dressing over."}', '{Vegan}', 'main', '2026-01-27 08:30:35.639229', NULL, 2, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (156, 'Moroccan Soup', 'Rich lamb and lentil soup with warming North African spices.', 2180, 260, 175, 55, '/uploads/recipes/moroccan-soup.jpg', '{"1 tbsp olive oil","850g lamb, cut into cubes","1 brown onion, diced","1 large carrot, diced","2 stalks celery, diced","2 cloves garlic, minced","2 tsp ground cumin","1 tsp paprika","1/2 tsp cinnamon","1 tsp turmeric","1 tsp ground ginger","2 x (400g) tinned chopped tomatoes","1L chicken stock","180g dried red lentils"}', '{"Heat oil in a large deep pot. Add lamb and brown for 3 minutes.","Add onion, carrot and celery and cook for 5 minutes.","Stir in garlic and spices and cook for 2 to 3 minutes.","Add tomatoes, stock and lentils and bring to a boil.","Reduce to a low simmer and cook covered for 90 minutes.","Remove lid and cook a further 20 to 30 minutes until thickened."}', '{}', 'main', '2026-01-27 08:30:35.639229', NULL, 5, NULL, '{vegetarian}', NULL, 140);
INSERT INTO public.recipes VALUES (129, 'Singapore Noodles', 'Stir-fried Singapore noodles with crispy tofu, vegetables and a peanut tamari sauce.', 1560, 68, 212, 48, '/uploads/recipes/singapore-noodles.jpg', '{"1 tbsp peanut butter","1 tbsp tamari","2 tsp lime juice","1 tbsp sesame oil","200g firm tofu, cut into cubes","1 clove garlic, minced","1 brown onion, diced","1 yellow bell pepper, sliced","1 head broccoli, florets chopped","150g baby corn","150g Singapore noodles"}', '{"Add the peanut butter, tamari, and lime juice to a medium-sized bowl and stir to combine. Add the tofu and gently toss to coat.","Add 2 tsp of sesame oil to a large frying pan. Add tofu and cook for about 5 minutes each side or until golden. Remove from the heat and set aside.","Meanwhile, add the noodles to a bowl of boiling water and allow to stand for 5 minutes. Drain and set aside.","Add the remaining sesame oil to the same frying pan, along with the garlic and onion. Cook for 3-4 minutes.","Add the bell pepper, broccoli and corn and cook for another 4-5 minutes.","Toss the noodles through the rest of the dish and divide between bowls."}', '{Vegan}', 'main', '2026-01-27 08:28:01.749239', NULL, 4, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (47, 'Apple Cinnamon Breakfast Quesadillas', 'Sweet and savory breakfast quesadillas with chunky applesauce, melted cheddar, and warm cinnamon sugar.', 261, 11, 25, 13, '/uploads/recipes/apple-cinnamon-breakfast-quesadillas.png', '{"4 (10 inch) whole-grain flour tortillas","250g chunky applesauce","230g cheddar, grated","2 tablespoons light brown sugar","1 teaspoon ground cinnamon","2 tablespoons melted butter","250g sour cream"}', '{"Preheat oven to 200C/400F.","Spread applesauce over two tortillas. Top with cheese and remaining tortillas.","Mix brown sugar and cinnamon and sprinkle over both sides.","Brush with melted butter and bake for 8-10 minutes until crisp.","Cut into quarters and serve with sour cream."}', '{Vegetarian}', 'breakfast', '2026-01-26 11:48:11.668489', NULL, 4, NULL, '{vegetarian}', NULL, 10);
INSERT INTO public.recipes VALUES (134, 'Courgette Risotto', 'Classic risotto with courgette, garlic mushrooms and two types of cheese.', 1708, 48, 280, 32, '/uploads/recipes/courgette-risotto.jpg', '{"1 tbsp olive oil","1 brown onion, diced","1 tbsp fresh thyme","300g risotto rice","125ml white wine","1L vegetable stock","150g courgette, sliced","200g garlic mushrooms","40g parmesan, grated","40g vegan cheese","1/2 lemon, juiced","1/2 small bunch parsley"}', '{"Heat the olive oil in a pan and cook the onion for 5 minutes until translucent.","Add the thyme and rice, cook for 1 minute while stirring.","Pour in the white wine and allow to absorb.","Add the stock gradually over 20 minutes, stirring frequently.","Cook mushrooms and courgette in a separate pan until golden.","Stir vegetables, cheeses, and lemon juice into the risotto.","Season, divide into bowls and garnish with parsley."}', '{Vegetarian}', 'main', '2026-01-27 08:28:47.662929', NULL, 4, NULL, '{vegetarian}', NULL, 40);
INSERT INTO public.recipes VALUES (97, 'Egg and Parmentier Potatoes', 'Crispy roasted potatoes with mushrooms and baked eggs for a satisfying brunch or breakfast.', 888, 44, 88, 40, '/uploads/recipes/egg-and-parmentier-potatoes.jpg', '{"500 grams potatoes, peeled and diced","2 shallots, quartered","1 tablespoon olive oil","2 teaspoons dried oregano","200 grams button mushrooms, sliced","4 eggs"}', '{"Preheat the oven to 200°C.","In a roasting tray, toss the potatoes and shallots in oil and sprinkle with oregano.","Roast for 45 minutes, stirring occasionally, until golden brown.","Add the mushrooms and cook for a further 5 minutes.","Make four wells in the vegetables and crack an egg into each.","Return to the oven for 6 minutes for softly cooked eggs, or longer for firmer eggs."}', '{Vegetarian}', 'main', '2026-01-27 06:41:45.44209', NULL, 4, NULL, '{vegetarian}', '{Eggs}', 70);
INSERT INTO public.recipes VALUES (52, 'Overnight Oats with Berries', 'Creamy overnight oats soaked with chia seeds, almond milk, and whey protein, topped with fresh berries and nuts.', 468, 21, 33, 28, '/uploads/recipes/overnight-oats-berries.png', '{"80g rolled oats","2 tablespoons chia seeds","360ml almond milk","245g yoghurt (non-dairy)","2 tablespoons whey protein","2 tablespoons hemp seed","60g raspberries, strawberries or mix","75g nuts, chopped"}', '{"Mix oats, chia seeds, almond milk, yoghurt and whey protein into a bowl or mason jar.","Let soak overnight.","Remove from refrigerator and top with chopped nuts, hemp seeds and berries."}', '{Vegetarian}', 'breakfast', '2026-01-26 11:48:42.378923', NULL, 4, NULL, '{vegetarian}', NULL, 5);
INSERT INTO public.recipes VALUES (108, 'Fettuccine Stroganoff', 'Creamy mushroom stroganoff with tofu served over fettuccine pasta.', 1293, 54, 168, 45, '/uploads/recipes/fettuccine-stroganoff.jpg', '{"190 grams fettuccine","1 tablespoon olive oil","150 grams firm tofu, cut into strips","1 brown onion, sliced","1 clove garlic, minced","250 grams mushrooms, sliced","2 tablespoons paprika","1 tablespoon vegetable stock","1 tablespoon soy sauce","1 tablespoon tomato paste","1 tablespoon flour","1 tablespoon coconut milk"}', '{"Cook pasta according to packet instructions.","Heat olive oil in a large frying pan and cook tofu strips for 5 minutes each side.","Add onion and garlic and cook for 5 minutes.","Add mushrooms and cook for another 5 minutes, stirring regularly.","Stir in paprika and cook for 3 to 4 minutes.","Add stock and soy sauce to the pan.","In a small bowl, mix tomato paste and flour. Stir into the pan to thicken the sauce.","Simmer for around 10 minutes until thickened.","Stir in coconut milk, remove from heat.","Divide pasta between bowls, top with sauce and season to taste."}', '{Vegan}', 'main', '2026-01-27 07:11:53.393263', NULL, 3, NULL, '{vegetarian}', NULL, 35);
INSERT INTO public.recipes VALUES (133, 'Pumpkin Penne', 'Creamy pumpkin pasta with sage, leek and Parmesan.', 2176, 64, 228, 104, '/uploads/recipes/pumpkin-penne.jpg', '{"300g penne","20g butter","1 leek, diced","150g pumpkin puree","2 tbsp fresh sage","200ml heavy cream","50g Parmesan, grated"}', '{"Cook the penne according to packet instructions. Drain and set aside.","In a large frying pan, add leek and cook for 3-4 minutes.","Add the pumpkin puree, fresh sage, cream and Parmesan. Simmer on low for 10 minutes.","Remove from the heat and toss penne through the sauce.","Season with salt & cracked pepper and divide between 4 bowls."}', '{Vegetarian}', 'main', '2026-01-27 08:28:01.749239', NULL, 4, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (109, 'Lentil Pilaf', 'Aromatic brown rice pilaf with lentils and warming Middle Eastern spices.', 1263, 48, 234, 15, '/uploads/recipes/lentil-pilaf.jpg', '{"185g brown rice (raw)","1 brown onion, diced","1 x (400g) tin lentils, rinsed and drained","2 tsp ground cumin","1 tsp ground cinnamon","1 tsp ground coriander","1/2 tsp ground turmeric","1 tbsp chopped parsley","1 tbsp tomato paste","1 courgette, grated","1 carrot, grated","550ml vegetable stock"}', '{"Start by cooking the rice according to packet instructions. Once cooked, drain well.","Heat olive oil in a large saucepan. Add the onion and cook for 5 minutes until softened.","Add the courgette, carrot and spices. Stir and cook for 2 minutes.","Add lentils, tomato paste and stock. Bring to the boil, then reduce to low heat and cover.","Cook for 15 minutes. If too much liquid remains, remove lid and simmer until absorbed."}', '{Vegan}', 'main', '2026-01-27 07:12:24.669501', NULL, 3, NULL, '{vegan,dairy-free,gluten-free}', NULL, 40);
INSERT INTO public.recipes VALUES (110, 'Butterbean Tacos', 'Spiced butter beans in corn tortillas with fresh mango and spinach.', 1892, 76, 316, 36, '/uploads/recipes/butterbean-tacos.jpg', '{"1 tbsp olive oil","1 x (400g) tin butter beans","1 tsp ground cumin","1 tsp paprika","1/2 tsp dried oregano","1/2 tsp chilli flakes","8 corn tortillas","2 tbsp spinach","1/2 red onion, thinly sliced","330g mango, diced"}', '{"Heat oil in a frying pan over medium heat.","Add butter beans, cumin, paprika, oregano and chilli flakes. Cook for 3 to 4 minutes, stirring.","Heat tortillas in microwave for 40 seconds.","Top tortillas with spinach, onion, mango and cooked beans."}', '{Vegan}', 'main', '2026-01-27 07:12:24.669501', NULL, 4, NULL, '{vegan,dairy-free,gluten-free}', NULL, 20);
INSERT INTO public.recipes VALUES (136, 'Mango Salad', 'Fresh Asian-inspired salad with mango, mangetout and a tangy lime dressing.', 656, 20, 122, 12, '/uploads/recipes/mango-salad.jpg', '{"2 large mangoes, sliced","1 red bell pepper, sliced into matchsticks","1 large cucumber, sliced into matchsticks","200g mangetout, sliced","100g bean shoots","1 long red chilli, sliced","1 tbsp coriander leaves","3 tbsp lime juice","1 tbsp tamari","1 tsp sesame oil","1 tsp maple syrup"}', '{"Add all salad ingredients to a large bowl.","Shake dressing ingredients in a jar for 2 minutes.","Pour dressing over salad and toss to combine."}', '{Vegan}', 'main', '2026-01-27 08:28:47.662929', NULL, 2, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (141, 'Warming Soup', 'Roasted root vegetable soup blended until smooth and creamy.', 788, 24, 84, 40, '/uploads/recipes/warming-soup.jpg', '{"300g parsnips","300g carrots","300g cauliflower","2 tbsp coconut oil","1 brown onion, diced","2 cloves garlic","1/2 tbsp thyme","1.4L vegetable stock","Salt & cracked pepper"}', '{"Roast vegetables at 200°C for 30-35 minutes.","Cook onion and garlic in a pan.","Add vegetables and stock, simmer for 10 minutes.","Blend until smooth and season to taste."}', '{Vegan}', 'main', '2026-01-27 08:29:13.172787', NULL, 4, NULL, '{vegetarian}', NULL, 45);
INSERT INTO public.recipes VALUES (161, 'Vegetarian Rogan Josh', 'Rich Indian curry with roasted butternut squash, chickpeas and yoghurt.', 1660, 80, 176, 72, '/uploads/recipes/vegetarian-rogan-josh.jpg', '{"2 tbsp olive oil","1 medium butternut squash, cut into small chunks","1 brown onion, diced","1 head broccoli, florets chopped","1 large carrot, sliced","2 cloves garlic, minced","3 tbsp Rogan Josh paste","1 x (400g) tin chickpeas","1/2 bunch coriander, leaves picked","250g natural yoghurt"}', '{"Preheat oven to 200°C and line a tray with baking paper.","Toss squash in 1 tbsp oil and roast for 30 to 35 minutes.","Heat remaining oil in a pan and cook onion for 5 minutes.","Add garlic, paste, vegetables and chickpeas. Cook 2 to 3 minutes.","Stir in roasted squash and coriander and remove from heat.","Serve with natural yoghurt."}', '{Vegetarian}', 'main', '2026-01-27 08:31:06.784205', NULL, 4, NULL, '{vegetarian}', NULL, 45);
INSERT INTO public.recipes VALUES (116, 'Aubergine Parmigiana', 'Layers of golden aubergine with passata, melted mozzarella and crispy breadcrumbs.', 1440, 32, 184, 64, '/uploads/recipes/aubergine-parmigiana.jpg', '{"2 tbsp olive oil","1 large aubergine, sliced","500g passata","200g mozzarella","1 tsp dried oregano","150g breadcrumbs","Salt and cracked pepper"}', '{"Preheat oven to 200°C.","Pan fry aubergine slices until golden.","Layer passata, aubergine and mozzarella in baking dish.","Mix breadcrumbs, oregano and seasoning and sprinkle on top.","Bake for 30 minutes and serve."}', '{Vegetarian}', 'main', '2026-01-27 07:12:52.433764', NULL, 4, NULL, '{vegetarian}', NULL, 45);
INSERT INTO public.recipes VALUES (120, 'Vegetarian Green Curry', 'Aromatic Thai green curry with broccoli and vermicelli noodles.', 1347, 42, 126, 75, '/uploads/recipes/vegetarian-green-curry.jpg', '{"100g dried vermicelli noodles","2 tbsp green curry paste","1/2 brown onion","1/2 red onion","60g spinach","100ml vegetable stock","2 tsp avocado oil","2 tsp sesame oil","500g broccoli","200ml coconut milk","2 tbsp lime juice","Fresh coriander, leaves picked"}', '{"Cook noodles according to packet instructions. Drain and set aside.","Blend onion, spinach and vegetable stock until smooth.","Heat avocado oil in a large frying pan. Add broccoli and stir fry for 8 minutes.","Reduce heat and allow vegetables to soften for 10 minutes.","Stir through green curry paste, coconut milk and lime juice. Simmer for 5 minutes.","Divide noodles between bowls, spoon curry over and top with fresh coriander."}', '{Vegetarian,Vegan}', 'main', '2026-01-27 07:13:27.444112', NULL, 3, NULL, '{vegetarian}', NULL, 40);
INSERT INTO public.recipes VALUES (107, 'Mexican Soup', 'A hearty spiced vegetable soup with black beans and peppers.', 972, 52, 128, 28, '/uploads/recipes/mexican-soup.jpg', '{"1 tablespoon olive oil","1 brown onion","1 red bell pepper, cut into small chunks","2 green bell peppers, cut into small chunks","1 courgette, sliced","1 x 400 gram tin black beans, drained and rinsed","1 tablespoon paprika","1 teaspoon cayenne pepper","1 teaspoon cumin","1 teaspoon chilli flakes","1 vegetable stock cube","1 x 400 gram tin chopped tomatoes"}', '{"Heat olive oil in a large saucepan.","Add onion and cook for 5 minutes until softened.","Add peppers and courgette and cook for a further 5 minutes.","Add spices, stock cube, tomatoes and black beans.","Simmer for 10 minutes before serving."}', '{Vegan}', 'main', '2026-01-27 07:11:53.393263', NULL, 4, NULL, '{vegetarian}', NULL, 30);
INSERT INTO public.recipes VALUES (48, 'Strawberry Pudding', 'A quick frozen strawberry pudding blended with peanut butter, cottage cheese, and honey, topped with chia seeds and almonds.', 292, 17, 29, 12, '/uploads/recipes/strawberry-pudding.png', '{"1 large strawberries, chopped and frozen","1 tablespoon peanut butter","1/4 cup low-fat cottage cheese","3 tablespoons honey","1/2 tablespoon vanilla extract","2 tablespoons chia seeds","1 tablespoon almonds, chopped"}', '{"In a blender or food processor add all ingredients except chia seeds and almonds and blend until smooth.","Pour into bowls, sprinkle with chia seeds and almonds, chill 15 minutes before serving. Store remaining serving in freezer."}', '{Vegetarian,Gluten-free}', 'breakfast', '2026-01-26 11:48:11.668489', NULL, 2, NULL, '{vegetarian,gluten-free}', NULL, 5);
INSERT INTO public.recipes VALUES (49, 'Red Bean Breakfast', 'A hearty Mexican-inspired breakfast with crispy potatoes, spiced red beans, fried eggs, and fresh avocado.', 447, 19, 50, 19, '/uploads/recipes/red-bean-breakfast.png', '{"2 medium potatoes","1 tablespoon olive oil","400g tin red beans, drained","1 teaspoon chilli powder","1 teaspoon smoked paprika","1 teaspoon chipotle hot sauce","salt and black pepper, to taste","4 eggs","1 avocado, diced","small handful fresh coriander"}', '{"Wash potatoes and prick with a couple of times with a fork. Cook in microwave for 6-7 minutes until tender, then chop into chunks.","Heat oil in a frying pan, add potatoes and fry until golden. Add beans, spices and hot sauce and cook for 5 minutes.","Meanwhile fry eggs. Serve beans and potatoes topped with egg, avocado and coriander."}', '{Vegetarian,Gluten-free}', 'breakfast', '2026-01-26 11:48:42.378923', NULL, 4, NULL, '{vegetarian,gluten-free}', NULL, 20);
INSERT INTO public.recipes VALUES (115, 'Hummus Wraps', 'Wholesome wraps filled with sautéed vegetables, chickpeas and creamy hummus.', 810, 26, 100, 34, '/uploads/recipes/hummus-wraps.jpg', '{"1 tsp olive oil","1 onion, diced","100g bell peppers, diced","1 red mushroom, sliced","1/2 x (400g) tin chickpeas, rinsed","2 large wholegrain wraps","40g hummus","40g spinach","25g black olives"}', '{"Heat oil and cook onion 3 minutes.","Add peppers and mushrooms. Cook 3 more minutes.","Heat chickpeas in microwave 30 seconds.","Spread hummus over wraps, top with vegetables, chickpeas, spinach and olives."}', '{Vegan}', 'main', '2026-01-27 07:12:52.433764', NULL, 2, NULL, '{vegetarian}', NULL, 20);
INSERT INTO public.recipes VALUES (46, 'Orange Smoothie', 'A refreshing citrus smoothie with frozen bananas, peanut butter, hemp seeds, and fresh ginger.', 418, 9, 51, 23, '/uploads/recipes/orange-smoothie.png', '{"2 bananas, frozen","125ml almond milk","2 oranges, juice and some zest","1 tablespoon peanut butter","1/2 teaspoon grated ginger","2 tablespoon hemp seeds","handful of ice"}', '{"Combine all ingredients in a blender and blend until smooth. Add more ice if you would like."}', '{Vegan,Gluten-free,Dairy-free}', 'breakfast', '2026-01-26 11:48:11.668489', NULL, 2, NULL, '{vegan,gluten-free,dairy-free}', NULL, 5);
INSERT INTO public.recipes VALUES (51, 'Mashed Beans and Avocado Sandwich', 'A protein-packed open sandwich with mashed pinto beans, fresh avocado, spinach, and a kick of sriracha.', 535, 22, 78, 15, '/uploads/recipes/mashed-beans-avocado-sandwich.png', '{"45g pinto beans","1 tablespoon salsa","1/2 teaspoon cumin, ground","1 teaspoon paprika","1 slice whole-grain bread","1/2 avocado, sliced","handful baby spinach","2 tomato slices","1 tablespoon chopped chives","1 teaspoon sriracha hot sauce"}', '{"Use half a cup of pinto beans, then mash with salsa, cumin and paprika.","Spread on toast, top with avocado, spinach, tomato and chives.","Drizzle with sriracha and serve."}', '{Vegan,Dairy-free}', 'breakfast', '2026-01-26 11:48:42.378923', NULL, 1, NULL, '{vegan,dairy-free}', NULL, 10);
INSERT INTO public.recipes VALUES (45, 'Mocha Porridge', 'Creamy oat porridge with espresso-cocoa syrup, dates, cinnamon, and crunchy almond toppings.', 518, 17, 66, 23, '/uploads/recipes/mocha-porridge.png', '{"1 tablespoon soft light brown sugar","2 teaspoon dark cocoa powder","70ml freshly brewed espresso","1 teaspoon vanilla extract","100g porridge oats","500ml unsweetened almond milk","2 dates, halved and stoned","1/2 teaspoon ground cinnamon","80g dairy free yoghurt","2 teaspoon toasted almond flakes","1 teaspoon cacao nibs"}', '{"Put the sugar and cocoa powder in a small pan, gradually add the espresso and vanilla, stirring until the sugar has dissolved. Bring to the boil and simmer for 6-8 minutes until syrup thickens.","Reduce the heat and simmer the almond milk and oats together for 4-5 minutes, stirring frequently. Remove from heat and stir in the dates, cinnamon and a pinch of salt.","Divide the porridge between bowls, top with yoghurt, drizzle of mocha syrup, almonds and cacao nibs."}', '{Vegan,Dairy-free}', 'breakfast', '2026-01-26 11:48:11.668489', NULL, 2, NULL, '{vegan,dairy-free}', NULL, 15);
INSERT INTO public.recipes VALUES (50, 'Baked Granola Bars', 'Healthy homemade granola bars with oats, chia seeds, mixed seeds, and dried cranberries.', 137, 3, 20, 5, '/uploads/recipes/baked-granola-bars.png', '{"3/4 cup gluten-free rolled oats, ground into a flour","1 cup water","3/4 cup spiced mixed dates","1/2 cup chia seeds","1/4 cup raw sunflower seeds","1/4 cup raw pumpkin seeds","1/4 cup dried cranberries, finely chopped","1 teaspoon pure vanilla extract","1/4 teaspoon fine grain sea salt"}', '{"Preheat oven to 325F and line a baking pan with foil or parchment.","Blend dates, water and vanilla to a paste. Stir in remaining ingredients.","Press mixture firmly into pan and bake for 20 minutes until golden.","Cool completely before slicing into bars."}', '{Vegan,Gluten-free,Dairy-free}', 'breakfast', '2026-01-26 11:48:42.378923', NULL, 12, NULL, '{vegan,gluten-free,dairy-free}', NULL, 25);
INSERT INTO public.recipes VALUES (113, 'Hokkien Noodles', 'Stir-fried rice noodles with vegetables in a zesty peanut lime sauce.', 981, 27, 144, 33, '/uploads/recipes/hokkien-noodles.jpg', '{"2 tbsp lime juice","1/2 tbsp peanut butter","1 tsp tamari","1/2 tsp chilli flakes","450g fresh rice noodles","2 tsp sesame oil","4 spring onions, diced","1 tsp ginger, minced","1 carrot, cut into matchsticks","1/2 courgette, cut into matchsticks","50g bean sprouts","60g mushrooms, chopped"}', '{"Cook noodles according to packet. Drain and set aside.","Heat sesame oil in wok. Add onion, ginger and cook 2 minutes.","Add carrot, courgette and mushrooms. Cook 5 minutes.","Add noodles and sauce ingredients. Stir fry 2 to 3 minutes.","Serve topped with bean sprouts."}', '{Vegan}', 'main', '2026-01-27 07:12:24.669501', NULL, 3, NULL, '{vegetarian}', NULL, 35);
INSERT INTO public.recipes VALUES (111, 'Stuffed Sweet Potatoes', 'Baked sweet potatoes loaded with spiced black beans, corn and fresh rocket.', 912, 28, 156, 20, '/uploads/recipes/stuffed-sweet-potatoes.jpg', '{"2 medium sweet potatoes","1 tbsp olive oil","Salt and cracked pepper","314g cooked black beans, drained and rinsed","80g corn kernels","1 large tomato, diced","1 tsp paprika","125g rocket"}', '{"Preheat oven to 200°C. Line baking tray with baking paper.","Rub sweet potatoes with oil, salt and pepper. Bake for 50 to 60 minutes.","Meanwhile, heat beans, corn, tomato and paprika in a pan for 5 minutes.","Slice open potatoes and top with bean mixture and rocket."}', '{Vegan,Gluten-free}', 'main', '2026-01-27 07:12:24.669501', NULL, 2, NULL, '{vegetarian}', NULL, 70);
INSERT INTO public.recipes VALUES (124, 'Mediterranean Bake', 'Roasted aubergine, courgette and tomatoes with crumbled feta and fresh parsley.', 1280, 64, 76, 80, '/uploads/recipes/mediterranean-bake.jpg', '{"3 aubergines, thinly sliced","2 large courgettes, thinly sliced","500g baby tomatoes","60g olive oil","1 tbsp dried basil","2 cloves garlic, finely chopped","100g feta","Fresh parsley, leaves picked"}', '{"Preheat oven to 200°C.","Arrange vegetables in an ovenproof dish. Drizzle with olive oil, basil and garlic.","Bake for 35 minutes. After 15 minutes, crumble feta over vegetables.","Top with fresh parsley and serve."}', '{Vegetarian,Low-carb}', 'main', '2026-01-27 07:13:59.301718', NULL, 4, NULL, '{vegetarian}', NULL, 50);
INSERT INTO public.recipes VALUES (103, 'Cauliflower Puree with Chickpeas', 'Silky cauliflower mash topped with spiced roasted chickpeas.', 1326, 72, 84, 78, '/uploads/recipes/cauliflower-puree-with-chickpeas.jpg', '{"2 heads cauliflower, cut into big florets","60 millilitres almond milk","3 tablespoons olive oil","3 tablespoons cracked black pepper","1 x 400 gram tin chickpeas, drained","1 tablespoon olive oil","1 teaspoon paprika","1 teaspoon chilli flakes","4 cloves garlic"}', '{"Preheat oven to 200°C and line a baking tray with baking paper.","Bring a large pot of salted water to the boil. Cook cauliflower for 20 to 25 minutes until soft.","Drain cauliflower and allow to cool slightly.","Mash or blend cauliflower with almond milk, olive oil and black pepper until smooth.","Toss chickpeas with olive oil, paprika, chilli flakes and garlic.","Roast chickpeas in the oven for around 10 minutes.","Transfer puree to a serving bowl, top with chickpeas and season to taste."}', '{Vegetarian,Low-carb}', 'main', '2026-01-27 07:11:20.615291', NULL, 6, NULL, '{vegan,dairy-free,gluten-free}', NULL, 45);
INSERT INTO public.recipes VALUES (106, 'Chickpea San Choy Bow', 'Asian-inspired lettuce cups filled with spiced chickpeas and mushrooms.', 1452, 64, 92, 92, '/uploads/recipes/chickpea-san-choy-bow.jpg', '{"2 tablespoons coconut oil","4 spring onions, finely sliced","2 cloves garlic, minced","3 tablespoons fresh ginger, grated","370 grams chickpeas, drained","375 grams mushrooms, chopped","1 tablespoon tamari","75 millilitres coconut milk","2 teaspoons sesame oil","1 long red chilli, sliced","8 leaves cos lettuce","10 grams coriander, leaves picked"}', '{"Heat coconut oil in a large skillet.","Add spring onions, garlic and ginger and cook for 3 minutes.","Add mushrooms and cook for a further 3 minutes.","Stir in chickpeas, tamari, sesame oil and coconut milk. Cook for 2 minutes.","Add chilli and cook for another 2 minutes.","Spoon mixture into lettuce leaves and garnish with coriander."}', '{Vegan,Low-carb}', 'main', '2026-01-27 07:11:53.393263', NULL, 4, NULL, '{vegan,dairy-free,gluten-free}', NULL, 25);
INSERT INTO public.recipes VALUES (145, 'Courgetti with Chicken and Lemon', 'Light courgette noodles with lemon chicken and fresh basil.', 1628, 168, 60, 72, '/uploads/recipes/courgetti-with-chicken-and-lemon.jpg', '{"2 tbsp olive oil","3 cloves garlic, minced","150g onion, diced","250g chicken breast, sliced","1 tsp lemon rind","2 tsp lemon juice","2 tbsp white wine","3 medium courgettes, spiralised","1g fresh basil"}', '{"Heat olive oil in pan. Cook onion and garlic 2 minutes.","Add chicken and cook 7 to 8 minutes.","Add lemon rind, juice and wine.","Add courgette noodles and cook 2 to 3 minutes.","Divide between bowls and season."}', '{Low-carb}', 'main', '2026-01-27 08:29:42.814641', NULL, 4, NULL, '{high-protein}', '{Chicken}', 20);
INSERT INTO public.recipes VALUES (100, 'Greek Style Turkey Burgers', 'Lean turkey burgers with feta, fresh herbs and a tangy yoghurt sauce.', 1008, 128, 16, 48, '/uploads/recipes/greek-style-turkey-burgers.jpg', '{"450 grams turkey mince","60 grams feta cheese, crumbled","1 tablespoon fresh parsley, chopped","1 tablespoon fresh mint, chopped","A handful fresh spinach, chopped","A pinch salt and black pepper","150 grams natural low fat yoghurt","1 lemon, juiced","1 garlic clove, crushed"}', '{"Combine turkey, feta, herbs, spinach and seasoning in a bowl. Mix thoroughly.","Divide mixture into four and shape into burger patties.","Place burgers on a baking tray and cook under a hot grill for 5 minutes. Flip and cook for a further 5 minutes.","Mix all sauce ingredients in a bowl and season to taste.","Serve burgers topped with yoghurt sauce."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 07:11:20.615291', NULL, 4, NULL, '{high-protein}', NULL, 35);
INSERT INTO public.recipes VALUES (95, 'Slow Cooked Spicy Beef Curry', 'A rich and aromatic slow-cooked beef curry with yoghurt marinade and warming spices.', 1602, 180, 126, 42, '/uploads/recipes/slow-cooked-spicy-beef-curry.jpg', '{"150 millilitres low fat natural yoghurt","1 kilogram casserole steak cut into 3 centimetre pieces","1 teaspoon ground cumin","1 teaspoon ground coriander","1 teaspoon ground turmeric","1 tablespoon olive oil","1 white onion diced","2 tablespoons ground coriander","½ teaspoon ground cumin","6 cardamom pods","1 teaspoon ground turmeric","4 teaspoons garam masala","1 red Kashmiri chilli","4 green chillies","3 garlic cloves crushed","1 teaspoon ginger grated","2 tablespoons tomato paste","2 x 400 gram tins chopped tomatoes","1 litre beef stock","1 lemon juiced"}', '{"Begin by combining the yoghurt with cumin, coriander and turmeric in a large bowl. Add the steak and coat thoroughly. Cover and refrigerate for at least 2 hours.","Heat the oil in a large frying pan and cook the marinated steak for 5 minutes until sealed.","Add the onion and spices, cooking gently until fragrant.","Transfer everything to a slow cooker and cook on high for 3 hours or low for 6 hours.","Once cooked, the sauce should be thick and rich. Season to taste.","Serve with fresh chopped coriander and enjoy."}', '{"High protein"}', 'main', '2026-01-27 06:41:45.44209', NULL, 6, NULL, '{high-protein}', '{Beef}', 300);
INSERT INTO public.recipes VALUES (163, 'Dijon Baked Salmon', 'Oven-baked salmon with a Dijon mustard and herb crust.', 726, 74, 2, 46, '/uploads/recipes/dijon-baked-salmon.jpg', '{"2 large salmon fillets","10g fresh parsley","1 tbsp lemon juice","4 lemon slices","1 tsp Dijon mustard","1 tsp olive oil","Salt and cracked pepper"}', '{"Preheat oven to 220°C and line a baking tray with baking paper.","Mix parsley, lemon juice, Dijon, olive oil, salt and pepper.","Spread mixture over salmon and top with lemon slices.","Bake for 12 to 15 minutes until cooked to preference.","Serve with a green side salad."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 08:31:06.784205', NULL, 2, NULL, '{high-protein,gluten-free}', '{Fish}', 25);
INSERT INTO public.recipes VALUES (105, 'Butternut Squash Noodles', 'Roasted butternut squash noodles with toasted pine nuts and vegan Parmesan.', 1848, 36, 48, 168, '/uploads/recipes/butternut-squash-noodles.jpg', '{"450 grams butternut squash noodles","2 tablespoons extra virgin olive oil","Kosher salt and black pepper","Fresh parsley","Pinch crushed red pepper flakes","180 grams pine nuts","30 grams vegan Parmesan"}', '{"Preheat oven to 200°C and line a baking tray with baking paper.","Place noodles on tray, toss with olive oil, salt and pepper.","Bake for around 10 minutes until tender.","Toast pine nuts in a dry pan until golden.","Combine noodles with pine nuts, parsley, chilli flakes and vegan Parmesan.","Serve immediately."}', '{Vegan,Gluten-free,Low-carb}', 'main', '2026-01-27 07:11:53.393263', NULL, 4, NULL, '{vegetarian}', NULL, 25);
INSERT INTO public.recipes VALUES (144, 'Red Lentil Soup', 'Spiced red lentil soup with vegetables and warming Middle Eastern spices.', 1528, 100, 272, 8, '/uploads/recipes/red-lentil-soup.jpg', '{"1 tbsp ground coriander","1 tsp cumin","1 tsp turmeric","1/2 tsp paprika","375g dried red lentils","2L water","1 brown onion, diced","1 large carrot, diced","1 red bell pepper, diced","1 courgette, diced"}', '{"Place coriander, cumin, turmeric and paprika in a dry saucepan and toast for 2 to 3 minutes.","Add all other ingredients and bring to boil.","Reduce heat and simmer for 35 to 40 minutes.","Divide between 4 bowls."}', '{Vegan,"High protein"}', 'main', '2026-01-27 08:29:42.814641', NULL, 4, NULL, '{vegan,dairy-free,gluten-free}', NULL, 45);
INSERT INTO public.recipes VALUES (125, 'Lamb Curry', 'Slow-cooked tender lamb in a rich spiced curry with spinach and cashews.', 2180, 260, 60, 100, '/uploads/recipes/lamb-curry.jpg', '{"2 tsp cumin seeds","2 tsp coriander seeds","1 cinnamon stick","1 tsp chilli flakes","1 tbsp garam masala","1 tbsp tomato puree","1 brown onion, roughly chopped","2 cloves garlic, minced","1 tbsp coconut oil","1kg lamb, cut into cubes","200g tomatoes, chopped","200g spinach","150g chickpeas","50g cashews","150g yoghurt"}', '{"Dry roast cumin, coriander, cinnamon and chilli flakes. Grind to powder.","Heat coconut oil in pan. Add spices and onion and cook 3 minutes.","Add lamb, garlic and tomato puree. Cook until browned.","Add tomatoes and yoghurt. Simmer on low for 1 hour until tender.","Stir through spinach and remove from heat.","Divide into bowls and top with chopped cashews."}', '{"High protein"}', 'main', '2026-01-27 07:13:59.301718', NULL, 5, NULL, '{high-protein}', NULL, 80);
INSERT INTO public.recipes VALUES (146, 'Turkey Salad with Mango', 'Fresh salad with turkey, mango and a minty yoghurt dressing.', 790, 68, 114, 10, '/uploads/recipes/turkey-salad-with-mango.jpg', '{"60g spinach","60g rocket","250g cherry tomatoes","2 Lebanese cucumbers","2 mangoes, cut into cubes","6 mint leaves, diced","60g Greek yoghurt","100g turkey breast slices"}', '{"Toss all vegetables and mango in a bowl.","Mix mint, lemon juice and yoghurt.","Arrange turkey on top and drizzle dressing."}', '{"High protein"}', 'main', '2026-01-27 08:29:42.814641', NULL, 2, NULL, '{high-protein}', NULL, 15);
INSERT INTO public.recipes VALUES (90, 'Turkey Chilli', 'A hearty and spicy lean turkey chilli with kidney beans and sweetcorn, perfect for batch cooking.', 1410, 132, 126, 42, '/uploads/recipes/turkey-chilli.jpg', '{"2 teaspoons olive oil","1 white onion, diced","3 garlic cloves, crushed","1 red pepper, chopped","450 grams lean turkey mince","1 tablespoon chilli powder","2 teaspoons ground cumin","1 teaspoon dried oregano","¼ teaspoon cayenne pepper","½ teaspoon salt","2 x 400 gram tins chopped tomatoes","300 millilitres chicken stock","2 x 400 gram tins kidney beans, drained and rinsed","140 gram tin sweet corn, drained and rinsed"}', '{"In a large frying pan, sauté the onion, garlic and red pepper over a medium heat for around 5 minutes, until the vegetables are tender and beginning to caramelise.","Add the turkey to the pan and cook through before adding the spices.","Let the spices roast in the pan until aromatic before adding the chopped tomatoes, stock, kidney beans and sweet corn.","Bring the chilli to the boil and let it reduce for around 30 minutes, until the sauce is thick and rich.","Season to taste with a pinch of salt and black pepper before removing from the heat.","Serve topped with guacamole, sour cream or hot sauce if desired."}', '{"High protein"}', 'main', '2026-01-27 06:41:10.138129', NULL, 6, NULL, '{high-protein}', NULL, 55);
INSERT INTO public.recipes VALUES (87, 'Avocado on Toast with Smoked Salmon', 'Creamy avocado on sourdough with smoked salmon, cucumber, watercress, and dill dressing.', 420, 16, 44, 20, '/uploads/recipes/avocado-toast-smoked-salmon.png', '{"1 avocado, peeled and stoned","2 tbsp low fat natural yoghurt","1 lemon, juiced","2 tbsp red wine vinegar","2 tbsp chopped dill","1 tsp Dijon mustard","1 tsp honey","75g smoked salmon","2 slices sourdough bread, toasted","1/2 cucumber, thinly sliced","1 handful watercress","1 radish, thinly sliced","1 tbsp olive oil","Pinch of salt and black pepper"}', '{"Begin by making the dressing by whisking together the yoghurt, lemon juice, red wine vinegar, dill, mustard and honey. Season to taste.","In a separate bowl, mix together the avocado, cucumber, watercress and radish. Drizzle over the dressing and gently toss to combine.","Toast the bread and top with the dressed salad and smoked salmon."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 2, NULL, '{high-protein}', '{Fish}', 15);
INSERT INTO public.recipes VALUES (131, 'Spicy Pork Salad', 'Spiced pork mince over fresh salad with cucumber, tomatoes and mint.', 750, 60, 36, 42, '/uploads/recipes/spicy-pork-salad.jpg', '{"1 tbsp peanut oil","1/2 brown onion, diced","1 clove garlic, minced","1 tsp fresh ginger, minced","250g pork mince","1 tsp paprika","1/2 tsp ground turmeric","Salt & cracked pepper","2 tbsp soy sauce","2 large tomatoes, chopped","1 large cucumber, chopped","300g lettuce leaves","1/2 bunch fresh mint, leaves picked"}', '{"Heat the peanut oil in a large frying pan. Add the onion and cook for 5 minutes or until translucent.","Add the garlic and ginger and cook for another 1-2 minutes.","Next, add the pork, paprika, turmeric, salt & cracked pepper.","Add the soy sauce and cook for about 7 minutes or until fully cooked. Remove from the heat and set aside.","Toss together the tomato, cucumber, lettuce and mint leaves.","Top with pork mince and chopped peanuts."}', '{Low-carb,"High protein"}', 'main', '2026-01-27 08:28:01.749239', NULL, 2, NULL, '{high-protein}', '{Pork}', 30);
INSERT INTO public.recipes VALUES (137, 'Salmon Nicoise', 'Classic French salad with pan-fried salmon, potatoes, green beans and olives.', 2224, 112, 140, 136, '/uploads/recipes/salmon-nicoise.jpg', '{"4 eggs, boiled and quartered","600g baby potatoes","300g green beans","300g tomatoes, chopped","165g kalamata olives, halved","1 tbsp capers","400g Atlantic salmon","1 tsp olive oil","olive oil","lemon juice","Dijon mustard",salt,pepper,"fresh dill"}', '{"Boil potatoes until tender and steam green beans.","Pan fry salmon in olive oil until cooked.","Mix dressing ingredients in a bowl.","Assemble all ingredients on plates and drizzle with dressing."}', '{"High protein"}', 'main', '2026-01-27 08:28:47.662929', NULL, 4, NULL, '{high-protein,gluten-free}', '{Fish}', 45);
INSERT INTO public.recipes VALUES (104, 'Stuffed Tofu', 'Crispy tofu squares stuffed with mushrooms and leek in a spiced tomato sauce.', 1900, 155, 95, 100, '/uploads/recipes/stuffed-tofu.jpg', '{"500 grams fried tofu, cut into 5 large squares","10 mushrooms, finely chopped","50 grams leek, chopped","5 grams garlic chives, grated","Salt and cracked pepper","1 tablespoon olive oil","70 millilitres passata","2 teaspoons oregano","2 teaspoons chilli flakes","2 tablespoons spring onions, diced"}', '{"Carve out the centre of each tofu square using a sharp knife.","Mix the carved tofu with mushrooms, leek, garlic chives, salt and pepper.","Stuff the mixture back into the tofu squares.","Heat olive oil in a frying pan and cook tofu squares for around 5 minutes each side until crispy. Remove and set aside.","In the same pan add passata, oregano and chilli flakes. Heat gently for 5 minutes.","Return tofu to the pan and cook for another 5 minutes, turning to coat in sauce.","Transfer to a serving bowl, top with spring onions and serve immediately."}', '{Vegan,"High protein"}', 'main', '2026-01-27 07:11:53.393263', NULL, 5, NULL, '{vegan,dairy-free,gluten-free}', '{Tofu}', 35);
INSERT INTO public.recipes VALUES (65, 'Bacon and Scrambled Cheesy Eggs', 'Crispy bacon paired with creamy scrambled eggs loaded with cheddar cheese and fresh chives.', 444, 31, 1, 35, '/uploads/recipes/bacon-scrambled-cheesy-eggs.png', '{"8 rashers bacon","8 eggs","2 tbsp milk","2 tbsp butter","120g cheddar cheese, grated","2 tbsp chives"}', '{"Preheat oven to 200°C/180°C fan. Line a baking tray with baking paper and lightly grease.","Place bacon on tray and cook for 5 to 7 minutes or until crispy.","Whisk together eggs, milk and cheese.","Melt butter in frying pan. Add egg mixture and gently fold while cooking.","Remove eggs when slightly underdone.","Divide eggs and bacon between plates and sprinkle with chives."}', NULL, 'breakfast', '2026-01-26 14:22:53.535748', NULL, 4, NULL, '{high-protein}', '{Pork,Eggs}', 25);
INSERT INTO public.recipes VALUES (89, 'Spicy Moroccan Eggs', 'North African-inspired eggs poached in a spiced tomato and chickpea sauce with fresh coriander.', 242, 16, 22, 10, '/uploads/recipes/spicy-moroccan-eggs.png', '{"2 tsp olive oil","2 garlic cloves, minced","1 small onion, finely diced","1 tsp ground cumin","1 tsp ground coriander","400g tin chickpeas, drained","400g tin chopped tomatoes","2 tbsp tomato puree","1 red chilli, sliced","1 tsp paprika","1 tsp ground cinnamon","2 eggs","A handful coriander, chopped"}', '{"Heat the olive oil in a frying pan and add the garlic and onion. Cook gently until softened.","Add the spices and cook for a further minute to release the flavours.","Stir in the chickpeas, chopped tomatoes, tomato puree and chilli. Simmer for 10 minutes.","Create small wells in the mixture and crack the eggs into them. Cover the pan and cook until the egg whites are set.","Garnish with fresh coriander and serve immediately."}', NULL, 'breakfast', '2026-01-26 14:33:26.839869', NULL, 4, NULL, '{vegetarian,high-protein}', '{Eggs}', 20);
INSERT INTO public.recipes VALUES (55, 'Smoked Salmon and Eggs', 'Elegant baked eggs with smoked salmon, capers, and cheddar cheese served with toasted sourdough.', 454, 27, 28, 26, '/uploads/recipes/smoked-salmon-and-eggs.png', '{"1/8 cup (1oz) butter, melted","8 eggs","2.5 oz double cream","1 tablespoon capers, drained and rinsed","4.8 oz smoked salmon, flaked","1/2 cup (30g) Cheddar cheese, grated","6 slices sourdough bread"}', '{"Preheat the oven to 200°C.","Brush the insides of six ramekins or one 25x30cm ceramic dish with the melted butter. Crack one egg into each ramekin (or all into the dish), top with cream and season with salt and pepper.","Scatter over the capers, salmon and cheese then bake for 10 minutes until the eggs are just cooked but the yolks runny.","Meanwhile, toast or grill the sourdough before removing the eggs from the oven and serving with the sourdough."}', NULL, 'breakfast', '2026-01-26 13:48:02.391477', NULL, 4, NULL, '{high-protein}', '{Fish,Eggs}', 15);
